/**
 * buildMinimalCognitiveFallback ã Render cognitivo baseado em intenûÏûÈo.
 *
 * Hierarquia:
 * 1. PRIMûRIO: usa mechanical_prompt_source (rawArr) como fonte de intenûÏûÈo ã
 *    transforma em fala cognitiva via _renderCognitiveFromIntent.
 *    Preserva conteû¤do tûˋcnico, muda apenas o tom. Validado por guardrail.
 * 2. FALLBACK: se nûÈo hûÀ fonte mecûÂnica ou guardrail falha ã
 *    _MINIMAL_FALLBACK_SPEECH_MAP por stage (fala cognitiva de seguranûÏa).
 * 3. GENûRICO: stage desconhecido ã "Pode continuar Þ" (nunca mecûÂnico).
 *
 * CONTRATO: rawArr como string literal NUNCA chega ao cliente.
 * O que chega ûˋ a INTENûûO do rawArr renderizada cognitivamente.
 *
 * Overlap: se mû¤ltiplas intenûÏûçes + off-trail ã prefix de reconhecimento antes da fala.
 *
 * Synchronous. Sem chamadas a LLM. Sem persistûˆncia. Sem mudanûÏa de gates.
 */
function buildMinimalCognitiveFallback(stage, rawArr, roundIntent) {
  // ãã PRIMûRIO: transformar frase mecûÂnica em fala cognitiva ãã
  const mechanicalSource = roundIntent?.mechanical_prompt_source || "";
  const cognitiveFromIntent = _renderCognitiveFromIntent(mechanicalSource, stage);

  // Se a transformaûÏûÈo passou no guardrail, usa como fala final
  let finalSpeech;
  if (cognitiveFromIntent) {
    finalSpeech = cognitiveFromIntent;
  } else {
    // ãã FALLBACK: mapa de seguranûÏa por stage ãã
    finalSpeech = _MINIMAL_FALLBACK_SPEECH_MAP.get(stage) || "Pode continuar Þ";
  }

  // Overlap: se mû¤ltiplas intenûÏûçes detectadas, reconhecer antes de continuar
  if (roundIntent?.pode_ter_multiplas_intencoes && roundIntent?.eh_off_trail) {
    return ["Anotei tudo aqui Þ Deixa eu continuar a anûÀlise do seu perfil.", finalSpeech];
  }
  return [finalSpeech];
}

/**
 * renderCognitiveSpeech ã ûrbitro soberano û¤nico da superfûÙcie visûÙvel.
 * TODA fala visûÙvel ao cliente deve sair desta funûÏûÈo.
 * O mecûÂnico permanece soberano em stage/gate/nextStage/persistûˆncia.
 *
 * HIERARQUIA SOBERANA (PR #550 ã BLOCO 1+2):
 *   1. LLM real (__speech_arbiter_source === "llm_real") ã ûNICO soberano.
 *      Quando disponûÙvel e vûÀlido, a fala do LLM ûˋ a fala final. Ponto.
 *   2. Fallback extremo mûÙnimo ã SOMENTE quando LLM nûÈo estiver disponûÙvel.
 *      Fonte: _MINIMAL_FALLBACK_SPEECH_MAP (mapa estûÀtico por stage) ou
 *      _renderCognitiveFromIntent (transformaûÏûÈo de tom sem LLM).
 *      HeurûÙstica, resolver e topo NûO produzem fala final pronta.
 *
 * REMOVIDO (BLOCO 2): Caminho "prefix > 20 chars" ã eliminado.
 *   Tamanho de string nûÈo pode ser critûˋrio de soberania da superfûÙcie.
 *
 * REMOVIDO (BLOCO 1): explicit_fallback com prefix arbitrûÀrio ã eliminado.
 *   HeurûÙstica/resolver NûO podem mais produzir fala final pronta.
 *   Se nûÈo veio de LLM, cai direto no fallback extremo mûÙnimo (mapa por stage).
 *
 * CONTRATO: rawArr como texto cru NUNCA chega ao cliente. Sem exceûÏûçes.
 */
function renderCognitiveSpeech(st, stage, rawArr) {
  const cognitivePrefix = String(st?.__cognitive_reply_prefix || "").trim();
  const v2TakesFinal = st?.__cognitive_v2_takes_final === true;
  const arbiterSource = st?.__speech_arbiter_source || null;
  const roundIntent = st?.__round_intent || null;

  // ãã PASSO 2: renderCognitiveSpeech como pass-through honesto ãã
  // Caminho cognitivo canûÇnico ûˋ o PRINCIPAL. renderCognitiveSpeech repassa a fala
  // aprovada pelo cognitivo sem decisûÈo conversacional paralela.
  // Apenas classifica a rota para telemetria.

  // Caminho ûNICO soberano: LLM real (caminho cognitivo canûÇnico principal)
  // Somente quando o LLM real produziu a fala e marcou como "llm_real".
  if (v2TakesFinal && cognitivePrefix && arbiterSource === "llm_real") {
    // ãã PASSO 2 TELEMETRIA: prova que cognitive path ûˋ principal ãã
    st.__render_path_used = "cognitive_canonical";
    return [cognitivePrefix];
  }

  // ãã TOP_SEALED_MODE: no topo selado, fallback extremo usa resposta estûÀtica do bucket ãã
  // NUNCA usa fala mecûÂnica (_MINIMAL_FALLBACK_SPEECH_MAP ou _renderCognitiveFromIntent)
  // no topo selado. Usa a resposta cognitiva estûÀtica do bucket classificado.
  if (TOP_SEALED_MODE && TOP_SEALED_STAGES.has(stage)) {
    const _bucket = st?.__topo_bucket || _classifyTopoIntentBucket(st?.last_user_text || "");
    const _staticReply = _TOPO_BUCKET_STATIC_REPLIES[_bucket] || _TOPO_BUCKET_STATIC_REPLIES.unknown_topo;
    st.__speech_arbiter_source = "topo_sealed_bucket_static";
    st.__topo_mechanical_surface_blocked = true;
    st.__render_path_used = "topo_sealed_bucket_static";
    return [_staticReply];
  }

  // Tudo que nûÈo ûˋ LLM real ã fallback extremo mûÙnimo (mapa por stage).
  // HeurûÙstica, resolver, topo, prefix local ã NADA disso ûˋ soberano.
  // O prefix (se existir) ûˋ DESCARTADO ã foi suporte interno, nûÈo fala final.
  st.__speech_arbiter_source = "extreme_fallback";
  st.__render_path_used = "extreme_fallback";
  return buildMinimalCognitiveFallback(stage, rawArr, roundIntent);
}

/**
 * classifyRenderPath ã Classifica a origem da fala renderizada.
 *
 * Retorna uma das classificaûÏûçes canûÇnicas do ûÀrbitro soberano:
 *   "llm_real"          ã LLM real assumiu a fala. ûnico soberano.
 *   "extreme_fallback"  ã Fallback extremo mûÙnimo: _MINIMAL_FALLBACK_SPEECH_MAP
 *                          ou _renderCognitiveFromIntent. Usado somente quando LLM
 *                          nûÈo disponûÙvel ou falhou. HeurûÙstica/resolver/topo/prefix
 *                          local NûO sûÈo soberanos ã tudo que nûÈo ûˋ LLM cai aqui.
 *
 * REMOVIDO: "explicit_fallback" (era largo demais ã permitia heurûÙstica disfarûÏada).
 * REMOVIDO: "cognitive_heuristic" (heurûÙstica ûˋ suporte interno, nûÈo classificaûÏûÈo).
 * Usado para telemetria e testes comportamentais. NûÈo altera a fala.
 */
function classifyRenderPath(st) {
  const arbiterSource = st?.__speech_arbiter_source || null;
  if (arbiterSource === "llm_real") return "llm_real";
  return "extreme_fallback";
}

// =============================================================
// ÞÏ  COGNITIVE V2 ã Adapter + Runner
// Converte output do motor isolado (runReadOnlyCognitiveEngine)
// para o formato compatûÙvel com o worker (mesmo contrato de cognitiveAssistV1)
// =============================================================

function adaptCognitiveV2Output(stage, v2Result) {
  const fallback = buildCognitiveFallback(stage);
  if (!v2Result || typeof v2Result !== "object" || !v2Result.ok) return fallback;

  const resp = v2Result.response;
  if (!resp || typeof resp !== "object") return fallback;

  const slotsDetected = resp.slots_detected && typeof resp.slots_detected === "object"
    ? resp.slots_detected : {};
  const slotKeys = Object.keys(slotsDetected);

  // Converter slots_detected ã entities flat (formato legado)
  const entities = {};
  for (const key of slotKeys) {
    const slot = slotsDetected[key];
    if (slot && slot.value != null) {
      entities[key] = slot.value;
      // Alias: V1 usa composicao_tipo, V2 usa composicao ã manter ambos para compatibilidade
      if (key === "composicao") entities.composicao_tipo = slot.value;
    }
  }

  // Converter slots_detected ã stage_signals flat (formato legado)
  const stageSignals = {};
  for (const key of slotKeys) {
    const slot = slotsDetected[key];
    if (slot && slot.value != null) stageSignals[key] = slot.value;
  }

  // Construir safe_stage_signal compatûÙvel com isStageSignalCompatible()
  let safeStageSignal = null;
  if (stage === "estado_civil" && entities.estado_civil) {
    safeStageSignal = "estado_civil:" + String(entities.estado_civil);
  } else if ((stage === "quem_pode_somar" || stage === "interpretar_composicao" ||
              stage === "somar_renda_solteiro" || stage === "somar_renda_familiar") && entities.composicao) {
    safeStageSignal = "composicao:" + String(entities.composicao);
  } else if (stage === "renda" && entities.renda != null) {
    safeStageSignal = "renda:" + String(entities.renda);
  } else if (stage === "ir_declarado" && entities.ir_declarado) {
    safeStageSignal = "ir:" + String(entities.ir_declarado);
  } else if (stage === "regime_trabalho" && entities.regime_trabalho) {
    safeStageSignal = "regime:" + String(entities.regime_trabalho);
  } else if (stage === "autonomo_ir_pergunta" && entities.ir_declarado) {
    safeStageSignal = "ir:" + String(entities.ir_declarado);
  }

  const hasSlots = slotKeys.length > 0;
  const confidence = Number.isFinite(resp.confidence) ? Math.max(0, Math.min(1, resp.confidence)) : 0;
  const hasPendingSlots = Array.isArray(resp.pending_slots) && resp.pending_slots.length > 0;

  const engineUsedLlm = v2Result.engine && v2Result.engine.llm_used === true;
  const speechOrigin = (v2Result.engine && v2Result.engine.speech_origin) || (engineUsedLlm ? "llm_real" : "heuristic_guidance");

  // ãã BLOCO 4 (PR #550): Post-LLM blindage ãã
  // Se o engine reporta heuristic_guidance ou fallback_mechanical, o reply_text
  // NûO pode ser usado como fala final pronta. Marcamos speech_origin honestamente
  // para que o caller (runFunnel) saiba que NûO deve promover para takes_final.
  // Somente speech_origin === "llm_real" ûˋ elegûÙvel para soberania da superfûÙcie.

  const intent = hasSlots
    ? "cognitive_v2_slot_detected"
    : (resp.conflicts && resp.conflicts.length > 0)
      ? "offtrack_contextual"
      : "fallback_contextual";

  const replyText = typeof resp.reply_text === "string" && resp.reply_text.trim()
    ? resp.reply_text.trim()
    : fallback.reply_text;

  return {
    reply_text: replyText,
    speech_origin: speechOrigin,
    intent,
    entities,
    stage_signals: stageSignals,
    still_needs_original_answer: hasPendingSlots && confidence < 0.8,
    answered_customer_question: replyText.length > 20 && resp.should_request_confirmation !== true,
    safe_stage_signal: safeStageSignal,
    suggested_stage: stage,
    confidence,
    reason: engineUsedLlm ? "cognitive_v2" : "cognitive_v2_heuristic"
  };
}

async function runCognitiveV2WithAdapter(env, stage, userText, st) {
  const fallback = buildCognitiveFallback(stage);
  try {
    const knownSlots = {};
    if (st.estado_civil) knownSlots.estado_civil = { value: st.estado_civil };
    // st.somar_renda mapeia para slot "composicao" (nome diferente no state vs. slot canûÇnico)
    if (st.somar_renda != null) knownSlots.composicao = { value: st.somar_renda };
    if (st.renda) knownSlots.renda = { value: st.renda };
    // st.regime mapeia para slot "regime_trabalho" (nome diferente no state vs. slot canûÇnico)
    if (st.regime) knownSlots.regime_trabalho = { value: st.regime };
    // BLOCO 11: processo_enviado_correspondente para prontidûÈo do pacote
    if (st.processo_enviado_correspondente != null) knownSlots.processo_enviado_correspondente = { value: st.processo_enviado_correspondente };

    // ãã PASSO 2: Caminho cognitivo canûÇnico formalizado ãã
    // Usa buildCognitiveInput para garantir shape canûÇnico estûÀvel.
    // Worker monta contexto do stage ã cognitivo recebe contrato formal.
    const rawInput = buildCognitiveInput({
      current_stage: stage,
      message_text: String(userText || ""),
      known_slots: knownSlots,
      goal_of_current_stage: getStageGoal(stage),
      forbidden_topics_for_stage: [],
      allowed_signals_for_stage: getAllowedSignalsForStage(stage),
      normative_context: [],
      recent_messages: []
    });

    const { apiKey } = getOpenAIConfig(env);
    const options = {
      openaiApiKey: apiKey || null,
      model: String(env.COGNITIVE_AI_MODEL || "gpt-4.1-mini"),
      fetchImpl:
        typeof env.__COGNITIVE_OPENAI_FETCH === "function"
          ? env.__COGNITIVE_OPENAI_FETCH
          : typeof fetch === "function"
            ? fetch.bind(globalThis)
            : null
    };

    const v2Result = await runReadOnlyCognitiveEngine(rawInput, options);
    return adaptCognitiveV2Output(stage, v2Result);
  } catch (e) {
    console.error("COGNITIVE_V2_ADAPTER_ERROR:", e);
    return fallback;
  }
}

async function cognitiveAssistV1(env, { stage, text, stateSnapshot }) {
  const base = buildCognitiveFallback(stage);

  const system = [
    "Vocûˆ ûˋ a camada cognitiva v1 da ENOVA e deve responder APENAS JSON vûÀlido.",
    "Objetivo: acolher, orientar sem prometer, e trazer o cliente de volta ao stage atual.",
    "NUNCA decidir funil sozinho; suggested_stage e stage_signals sûÈo apenas sugestûÈo.",
    "Use linguagem natural em pt-BR, tom acolhedor + firme + consultivo.",
    "Regras duras: sem promessa de aprovaûÏûÈo; sem antecipar valor/parcela/entrada/resultado; falar imû°vel; aprovaûÏûÈo depende de anûÀlise de perfil + avaliaûÏûÈo bancûÀria; escolha/simulaûÏûÈo de imû°vel apenas apû°s aprovaûÏûÈo no plantûÈo.",
    "Se responder dû¤vida mas faltar resposta objetiva do stage, marque still_needs_original_answer=true.",
    "Contrato de saûÙda obrigatû°rio: reply_text, intent, entities, stage_signals, still_needs_original_answer, answered_customer_question, safe_stage_signal, suggested_stage, confidence, reason."
  ].join(" ");

  const user = JSON.stringify({
    stage,
    customer_text: String(text || ""),
    playbook_v1: COGNITIVE_PLAYBOOK_V1,
    known_state: {
      estado_civil: stateSnapshot?.estado_civil || null,
      somar_renda: stateSnapshot?.somar_renda ?? null,
      renda: stateSnapshot?.renda || null,
      renda_parceiro: stateSnapshot?.renda_parceiro || null,
      regime: stateSnapshot?.regime || null
    }
  });

  const parsed = await callOpenAIJson(env, { system, user, temperature: 0.2 });
  if (!parsed || typeof parsed !== "object") return base;

  const confidence = Number(parsed.confidence ?? 0);
  const output = {
    reply_text: sanitizeCognitiveReply(parsed.reply_text),
    intent: String(parsed.intent || "fallback_contextual"),
    entities: parsed.entities && typeof parsed.entities === "object" ? parsed.entities : {},
    stage_signals: parsed.stage_signals && typeof parsed.stage_signals === "object" ? parsed.stage_signals : {},
    still_needs_original_answer: Boolean(parsed.still_needs_original_answer),
    answered_customer_question: Boolean(parsed.answered_customer_question),
    safe_stage_signal: parsed.safe_stage_signal ? String(parsed.safe_stage_signal) : null,
    suggested_stage: parsed.suggested_stage ? String(parsed.suggested_stage) : stage,
    confidence: Number.isFinite(confidence) ? Math.max(0, Math.min(1, confidence)) : 0,
    reason: String(parsed.reason || "cognitive_v1")
  };

  if (!output.reply_text) output.reply_text = base.reply_text;
  return output;
}

// =============================================================
// ÞÏ  OFFTRACK GUARD ã IA simples (classifica pergunta fora do trilho)
//  - Sû° decide: OFFTRACK ou ONTRACK
//  - Se OFFTRACK, dûÀ um label (FGTS, PRECO, REGIAO, COMPOR_RENDA, CASA, OUTRO)
//  - NûO muda fase. Sû° orienta responder padrûÈo.
// =============================================================
function shouldConsiderOfftrack(text) {
  const nt = normalizeText(text || "");
  if (!nt) return false;

  // HeurûÙstica barata: sû° chama IA quando parece pergunta/assunto paralelo
  if (nt.includes("?")) return true;

  return (
    /\b(fgts|valor|preco|parcela|entrada|onde|bairro|regiao|cidade|casa|namorad|espos|marid|restric|spc|serasa|negativ|sem registro|sem clt|nao tenho registro)\b/.test(nt)
  );
}

async function offtrackGuard(env, { wa_id, stage, text }) {
  // DesligûÀvel por env (seguranûÏa)
  const enabled = String(env.OFFTRACK_AI_ENABLED || "true").toLowerCase() !== "false";
  if (!enabled) return { offtrack: false };

  if (!shouldConsiderOfftrack(text)) return { offtrack: false };

  // Se nûÈo tiver key, nûÈo faz nada (nûÈo quebra atendimento)
  // Se nûÈo tiver key, nûÈo faz nada (nûÈo quebra atendimento)
const { apiKey } = getOpenAIConfig(env);

if (!apiKey) return { offtrack: false };
  const labels = ["ONTRACK", "FGTS", "PRECO", "REGIAO", "COMPOR_RENDA", "CASA", "RESTRICAO", "OUTRO"];

  const system =
    "Vocûˆ ûˋ um roteador. Sua û¤nica tarefa ûˋ dizer se a mensagem do cliente ûˋ uma PERGUNTA FORA DO TRILHO (OFFTRACK) " +
    "ou uma RESPOSTA DIRETA û  pergunta atual (ONTRACK). " +
    "Vocûˆ NûO pode inventar etapas, NûO pode orientar financiamento, NûO pode responder conteû¤do. " +
    "Responda APENAS JSON vûÀlido.";

  const user =
    JSON.stringify({
      stage_atual: stage,
      texto_cliente: String(text || ""),
      labels_validos: labels
    });

  const parsed = await callOpenAIJson(env, { system, user, temperature: 0 });
  if (!parsed) return { offtrack: false };

  const labelRaw = String(parsed?.label || parsed?.result || "").toUpperCase().trim();
  const confidence = Number(parsed?.confidence ?? 0);

  const label = labels.includes(labelRaw) ? labelRaw : "OUTRO";
  const offtrack = label !== "ONTRACK";

  return { offtrack, label, confidence: Number.isFinite(confidence) ? confidence : null };
}

function getP3TipoLabel(tipo) {
  const t = normalizeText(tipo || "");
  if (t === "pai") return "seu pai";
  if (t === "mae") return "sua mûÈe";
  if (t === "irmao") return "seu irmûÈo/sua irmûÈ";
  if (t === "namorada") return "sua namorada";
  if (t === "namorado") return "seu namorado";
  if (t === "sogra") return "sua sogra";
  if (t === "sogro") return "seu sogro";
  return "esse familiar";
}

function isModoFamiliar(st) {
  return st?.composicao_pessoa === "familiar" || st?.familiar_tipo != null;
}

function appendOwned(list, payload, owner) {
  const base = Array.isArray(list) ? list : [];
  return [...base, { owner, ...payload }];
}

function buildSimulationFlags(st, userText) {
  const normalized = normalizeText(userText || "");
  return {
    mei_detected: /\bmei\b/.test(normalized),
    aposentado_detected: /aposentad/.test(normalized),
    composicao_detected: Boolean(parseComposicaoRenda(userText || "")),
    renda_value: parseMoneyBR(userText || ""),
    estado_civil: st?.estado_civil || null,
    regime_trabalho: st?.regime_trabalho || null,
    somar_renda: st?.somar_renda ?? null,
    financiamento_conjunto: st?.financiamento_conjunto ?? null,
    renda: st?.renda ?? null,
    renda_parceiro: st?.renda_parceiro ?? null,
    ctps_36: st?.ctps_36 ?? null,
    restricao: st?.restricao ?? null,
    dependente: st?.dependente ?? null
  };
}

// =============================================================
// ÞÏÝ A3 ã TELEMETRIA ENOVA (MODO SAFE COM DETALHES)
//  - NûÈo escreve no Supabase
//  - Loga detalhes resumidos no console para debug
// =============================================================
async function telemetry(env, payload) {
  try {
    const level = (env.TELEMETRIA_LEVEL || "basic").toLowerCase();

    if (level === "off") return;

    const severity = payload.severity || "info";
    const event = payload.event || "unknown";

    const isInfo = severity === "info";
    const force = payload.force === true;
    if (level === "basic" && isInfo && !force) {
      return;
    }

    // Monta um preview seguro dos detalhes (erro do runFunnel etc.)
    let detailsPreview = null;
    if (payload.details) {
      try {
        detailsPreview = JSON.stringify(payload.details);
        if (detailsPreview.length > 800) {
          detailsPreview =
            detailsPreview.slice(0, 800) + "...(details truncado)";
        }
      } catch {
        detailsPreview = "[details nûÈo serializûÀveis]";
      }
    }

    const safePayload = {
      wa_id: payload.wa_id || null,
      event,
      stage: payload.stage || null,
      next_stage: payload.next_stage || null,
      severity,
      message: payload.message || null,
      details: detailsPreview
    };

    console.log("TELEMETRIA-SAFE:", JSON.stringify(safePayload));
    // Þ Nada de sbFetch aqui ã telemetria 100% sem Supabase.
  } catch (e) {
    console.error("Erro telemetria-safe:", e);
  }
}

// =============================================================
// ÞÏÝ A3.F ã FUNNEL TELEMETRY (atalho para o funil)
// =============================================================
async function funnelTelemetry(env, payload) {
  // Garante campos mûÙnimos
  const base = {
    event: payload.event || "funnel_event",
    stage: payload.stage || null,
    funil_status: payload.funil_status || null,
    severity: payload.severity || "info"
  };

  // Usa a mesma infra de telemetria principal
  return telemetry(env, { ...payload, ...base });
}

// =============================================================
// ÞÏÝ A8 ã VALIDATION ENGINE (variûÀveis de ambiente Cloudflare)
// =============================================================
const REQUIRED_ENV_VARS = [
  "VERCEL_PROXY_URL",
  "SUPABASE_SERVICE_ROLE",
  "META_API_VERSION",
  "PHONE_NUMBER_ID",
  "WHATS_TOKEN",
  "META_VERIFY_TOKEN"
  // ENOVA_DELAY_MS ûˋ nice-to-have, nûÈo crûÙtica
];

function checkEnvMissing(env) {
  const missing = [];

  for (const key of REQUIRED_ENV_VARS) {
    if (!env[key] || String(env[key]).trim() === "") {
      missing.push(key);
    }
  }

  return missing;
}

/**
 * validateEnv(env)
 *  - NûÈo quebra o Worker
 *  - Registra em telemetria se tiver qualquer variûÀvel faltando
 */
async function validateEnv(env) {
  const missing = checkEnvMissing(env);

  if (missing.length === 0) {
    return { ok: true, missing: [] };
  }

  // Telemetria crûÙtica: variûÀveis de ambiente faltando
  try {
    await telemetry(env, {
      wa_id: null,
      event: "env_missing",
      stage: "bootstrap",
      severity: "critical",
      message: "VariûÀveis de ambiente ausentes ou vazias",
      details: {
        missing_vars: missing
      }
    });
  } catch (e) {
    console.error("Erro telemetria env_missing:", e);
  }

  // NûO lanûÏamos erro aqui ã apenas avisamos.
  // A decisûÈo de abortar ou nûÈo a requisiûÏûÈo serûÀ feita no router.
  return { ok: false, missing };
}

// =============================================================
// Þ Mû°dulo interno ã Supabase via Proxy Vercel
// =============================================================
// Usa: env.VERCEL_PROXY_URL + /api/supabase-proxy/...
// NûO expûçe SERVICE_ROLE no Worker, tudo passa pelo Vercel.

async function supabaseProxyFetch(env, {
  path,       // exemplo: "/rest/v1/enova_state"
  method = "GET",
  query = null,   // objeto { select: "*", wa_id: "554..." }
  body = null,
  headers = {},
  signal
}) {
  if (!env.VERCEL_PROXY_URL) {
    throw new Error("VERCEL_PROXY_URL nûÈo configurada no Worker");
  }

  // Base do proxy (sem barra no final)
  let base = env.VERCEL_PROXY_URL;
  base = base.replace(/\/+$/, ""); // remove barras extras

  // Garante que o path comeûÏa com "/"
  if (!path.startsWith("/")) {
    path = "/" + path;
  }

  // NOVO FORMATO ã obrigatû°rio para o Proxy V2
// Agora usamos sempre query ?path=/rest/v1/tabela&select=*...
let url = base + "/api/supabase-proxy";

// query ûˋ obrigatû°rio, entûÈo garantimos que existe
const usp = new URLSearchParams();

// path obrigatû°rio ã agora ENCODED para impedir truncamento no Vercel
usp.append("path", path);

// acrescenta demais parûÂmetros (select, filtrosãÎ)
if (query && typeof query === "object") {
  for (const [key, value] of Object.entries(query)) {
    if (value === undefined || value === null) continue;
    usp.append(key, String(value));
  }
}

// URL final, sempre assim:
// https://proxy.../api/supabase-proxy?path=/rest/v1/enova_state&select=*&wa_id=eq.xxx
url += "?" + usp.toString();


  const finalHeaders = { ...headers };
  let finalBody = body;

  // Se body for objeto, envia como JSON
  if (
    body &&
    typeof body === "object" &&
    !(body instanceof ArrayBuffer) &&
    !(body instanceof Uint8Array)
  ) {
    if (!finalHeaders["Content-Type"]) {
      finalHeaders["Content-Type"] = "application/json";
    }
    finalBody = JSON.stringify(body);
  }

  // GET/HEAD nûÈo mandam body
  const sendBody =
    method === "GET" || method === "HEAD" ? undefined : finalBody;

      // ========== DEBUG (CONTROLADO) ã SUPABASE PROXY ==========
  // ã Ative apenas no TEST (env var SB_PROXY_DEBUG="true")
  const SB_DEBUG_ON = String(env.SB_PROXY_DEBUG || "").toLowerCase() === "true";

  if (SB_DEBUG_ON) {
    try {
      // Redact de secrets
      const safeHeaders = { ...finalHeaders };
      if (safeHeaders.Authorization) safeHeaders.Authorization = "REDACTED";
      if (safeHeaders.apikey) safeHeaders.apikey = "REDACTED";
      if (safeHeaders["x-enova-admin-key"]) safeHeaders["x-enova-admin-key"] = "REDACTED";

      console.log("DEBUG-SBREQUEST:", JSON.stringify({
        url,
        method,
        headers: safeHeaders,
        bodyPreview: typeof finalBody === "string"
          ? finalBody.slice(0, 200)
          : (finalBody ? "[non-string-body]" : null),
      }));
    } catch (err) {
      console.log("DEBUG-SBREQUEST-ERROR:", String(err));
    }

    // ã ÿ¡ Proxy-echo ûˋ caro (fetch extra). Deixe OFF por padrûÈo.
    const SB_ECHO_ON = String(env.SB_PROXY_ECHO || "").toLowerCase() === "true";
    if (SB_ECHO_ON) {
      try {
        const safeHeaders = { ...finalHeaders };
        if (safeHeaders.Authorization) safeHeaders.Authorization = "REDACTED";
        if (safeHeaders.apikey) safeHeaders.apikey = "REDACTED";

        const echo = await fetch(base + "/api/supabase-proxy-debug", {
          method,
          headers: safeHeaders
        });

        const echoJson = await echo.json();

        console.log("DEBUG-PROXY-ECHO:", JSON.stringify({
          sentHeaders: safeHeaders,
          proxyReceivedHeaders: echoJson?.received_headers || null
        }));
      } catch (err) {
        console.log("DEBUG-PROXY-ECHO-ERROR:", String(err));
      }
    }
  }
  // ========== FIM DEBUG ==========
// ========== FIM DO DEBUG TEMPORûRIO ==========

  let res;
  try {
    res = await fetch(url, {
      method,
      headers: finalHeaders,
      body: sendBody,
      signal
    });
  } catch (err) {
    console.error("supabaseProxyFetch: erro de rede/fetch", err);
    throw err;
  }

  const text = await res.text();
  let data = null;

  // Tenta parsear JSON; se nûÈo der, devolve texto cru
  try {
    data = text ? JSON.parse(text) : null;
  } catch {
    data = text;
  }

  if (!res.ok) {
    console.error("supabaseProxyFetch: erro HTTP", res.status, data);
    const error = new Error("Supabase proxy HTTP error");
    error.status = res.status;
    error.data = data;
    throw error;
  }

  return data;
}

// -------------------------------------------------------------
// Helpers de alto nûÙvel
// -------------------------------------------------------------
// SELECT
async function supabaseSelect(env, table, {
  columns = "*",
  filter = {},   // ex: { wa_id: "554..." }
  single = false
} = {}) {
  const query = { select: columns, ...filter };
  if (single) {
    query.limit = 1;
  }
  return supabaseProxyFetch(env, {
    path: `/rest/v1/${table}`,
    method: "GET",
    query
  });
}

// UPSERT (merge-duplicates)
async function supabaseUpsert(env, table, rows) {
  const payload = Array.isArray(rows) ? rows : [rows];

  // ÞÏ Para enova_state usamos a UNIQUE "enova_state_wa_id_key"
  //    -> on_conflict=wa_id (mesmo nome da coluna na tabela)
  const query = {};
  if (table === "enova_state") {
    query.on_conflict = "wa_id";
  }

  return supabaseProxyFetch(env, {
    path: `/rest/v1/${table}`,
    method: "POST",
    headers: {
      Prefer: "resolution=merge-duplicates",
      Accept: "application/json"
    },
    query,
    body: payload
  });
}

// INSERT simples
async function supabaseInsert(env, table, rows) {
  const payload = Array.isArray(rows) ? rows : [rows];

  return supabaseProxyFetch(env, {
    path: `/rest/v1/${table}`,
    method: "POST",
    headers: {
      Accept: "application/json"
    },
    body: payload
  });
}

// UPDATE com filtro na query (cuidado com where!)
async function supabaseUpdate(env, table, filter, patch) {
  const query = {};
  for (const [key, value] of Object.entries(filter || {})) {
    if (value === undefined || value === null) continue;
    // Supabase usa sintaxe col=eq.valor
    query[`${key}`] = `eq.${value}`;
  }

  return supabaseProxyFetch(env, {
    path: `/rest/v1/${table}`,
    method: "PATCH",
    headers: {
      Accept: "application/json"
    },
    query,
    body: patch
  });
}

