function hasComposicaoConfirmadaP2(st) {
  return resolveDossierCanonicalParticipantsFromState(st).some((p) => p.id === "p2");
}

function hasComposicaoConfirmadaP3(st) {
  return resolveDossierCanonicalParticipantsFromState(st).some((p) => p.id === "p3");
}

function resolveDossierCanonicalParticipantsFromState(st = {}) {
  const participantes = [{ id: "p1", tipo: "titular" }];
  const p2Tipo = String(st.p2_tipo || "").trim().toLowerCase();
  if (p2Tipo === "parceiro" || p2Tipo === "familiar") {
    participantes.push({ id: "p2", tipo: p2Tipo });
  }
  const p3Tipo = String(st.p3_tipo || "").trim().toLowerCase();
  if (st.p3_required === true || Boolean(p3Tipo)) {
    participantes.push({ id: "p3", tipo: p3Tipo || "familiar_p3" });
  }
  return participantes;
}

function describeEnvioDocsRendaByChecklist(itensParticipante = []) {
  const tipos = new Set(
    (Array.isArray(itensParticipante) ? itensParticipante : [])
      .map((item) => String(item?.tipo || "").trim().toLowerCase())
      .filter(Boolean)
  );

  if (tipos.has("comprovante_aposentadoria") || tipos.has("comprovante_pensao")) {
    return "extrato do benefûÙcio";
  }

  const hasDeclaracaoIr = tipos.has("declaracao_ir");
  const hasReciboIr = tipos.has("recibo_ir");
  const hasExtratos =
    tipos.has("extratos_bancarios") ||
    tipos.has("extrato_bancario") ||
    tipos.has("extratos_bancarios_3_meses");

  if (hasDeclaracaoIr && hasReciboIr && hasExtratos) return "declaraûÏûÈo de IR com recibo e extratos de movimentaûÏûÈo";
  if (hasDeclaracaoIr && hasReciboIr) return "declaraûÏûÈo de IR com recibo";
  if (hasDeclaracaoIr) return "declaraûÏûÈo do IR";
  if (hasReciboIr) return "recibo do IR";

  if (hasExtratos) return "extratos de movimentaûÏûÈo bancûÀria";

  if (tipos.has("holerites") || tipos.has("holerite") || tipos.has("holerite_ultimo") || tipos.has("holerites_ultimos_3")) {
    return "holerite";
  }

  if (tipos.has("comprovante_renda")) return "comprovante de renda";

  return null;
}

function buildEnvioDocsCallToAction(participanteAtual) {
  if (participanteAtual === "p2") {
    return "Agora vamos para os documentos da pessoa que vai entrar com vocûˆ no processo.\nMe envie primeiro o documento de identificaûÏûÈo dela. Assim que eu confirmar, jûÀ peûÏo o prû°ximo.";
  }
  if (participanteAtual === "p3") {
    return "Agora vamos para os documentos da prû°xima pessoa que tambûˋm vai entrar no processo.\nMe envie primeiro o documento de identificaûÏûÈo dela. Assim que eu confirmar, jûÀ peûÏo o prû°ximo.";
  }
  return "Vamos comeûÏar pelos seus documentos para nûÈo misturar com os da outra pessoa e evitar erro na anûÀlise.\nMe envie primeiro seu documento de identificaûÏûÈo. Assim que eu confirmar, jûÀ peûÏo o prû°ximo.";
}

const ENVIO_DOCS_ORDEM_PARTICIPANTES = Object.freeze(["p1", "p2", "p3"]);

function isEnvioDocsConversationalItem(item) {
  return String(item?.bucket || "").trim().toLowerCase() !== "recomendado";
}

function isEnvioDocsConversationalPendingItem(item) {
  if (!isEnvioDocsConversationalItem(item)) return false;
  return !isEnvioDocsItemReceived(item);
}

function resolveEnvioDocsCurrentParticipant(itensEnvioDocs = []) {
  const itens = Array.isArray(itensEnvioDocs) ? itensEnvioDocs : [];
  const participantesComItens = ENVIO_DOCS_ORDEM_PARTICIPANTES.filter((participante) =>
    itens.some((item) => String(item?.participante || "").trim().toLowerCase() === participante)
  );
  const participantes = participantesComItens.length ? participantesComItens : ["p1"];
  const participantesPendentes = new Set(
    itens
      .filter((item) => {
        const participante = String(item?.participante || "").trim().toLowerCase();
        return (
          ENVIO_DOCS_ORDEM_PARTICIPANTES.includes(participante) &&
          isEnvioDocsConversationalPendingItem(item)
        );
      })
      .map((item) => String(item?.participante || "").trim().toLowerCase())
  );
  return (
    participantes.find((participante) => participantesPendentes.has(participante)) ||
    participantes[0] ||
    "p1"
  );
}

function buildEnvioDocsListaMensagens(itensEnvioDocs = []) {
  const itens = Array.isArray(itensEnvioDocs) ? itensEnvioDocs : [];
  const participanteAtual = resolveEnvioDocsCurrentParticipant(itens);
  const itensParticipanteAtual = itens.filter(
    (item) => String(item?.participante || "").trim().toLowerCase() === participanteAtual
  );
  const tiposParticipanteAtual = new Set(
    itensParticipanteAtual.map((item) => String(item?.tipo || "").trim().toLowerCase()).filter(Boolean)
  );
  const listaCondensada = [];
  const incluirIdentidade =
    tiposParticipanteAtual.has("identidade_cpf") ||
    tiposParticipanteAtual.has("rg") ||
    tiposParticipanteAtual.has("rg_com_cpf") ||
    tiposParticipanteAtual.has("cnh");
  if (incluirIdentidade) listaCondensada.push("RG ou CNH");

  const incluirCpf =
    tiposParticipanteAtual.has("identidade_cpf") ||
    tiposParticipanteAtual.has("cpf") ||
    tiposParticipanteAtual.has("rg");
  if (incluirCpf) listaCondensada.push("CPF (se nûÈo constar no documento)");

  if (tiposParticipanteAtual.has("comprovante_residencia")) listaCondensada.push("comprovante de residûˆncia atual");

  const rendaLabel = describeEnvioDocsRendaByChecklist(itensParticipanteAtual);
  if (rendaLabel) listaCondensada.push(rendaLabel);

  if (tiposParticipanteAtual.has("ctps_completa") || tiposParticipanteAtual.has("ctps")) {
    listaCondensada.push("CTPS completa");
  }
  if (tiposParticipanteAtual.has("certidao_casamento")) {
    listaCondensada.push("certidûÈo de casamento");
  }
  if (tiposParticipanteAtual.has("certidao_nascimento_dependente")) {
    listaCondensada.push("certidûÈo de nascimento do dependente");
  }

  const listaTexto = listaCondensada.length
    ? listaCondensada.join(", ")
    : "documento de identificaûÏûÈo e comprovantes do seu processo";
  const mensagemPrincipal = `Fechamos por envio online aqui no WhatsApp.\nA lista ûˋ simples: ${listaTexto}. Pode ser foto, imagem ou PDF.`;

  return [mensagemPrincipal, "Þ Envie os documentos *um por vez* para que eu registre cada um corretamente no sistema.", buildEnvioDocsCallToAction(participanteAtual)];
}

function appendChecklistByRegime(checklist, participante, regime, irDeclarado) {
  if (regime === "clt" || regime === "servidor") {
    checklist.push({ tipo: "holerites", participante });
    return;
  }

  if (regime === "autonomo") {
    if (irDeclarado) {
      checklist.push(
        { tipo: "declaracao_ir", participante },
        { tipo: "recibo_ir", participante }
      );
    } else {
      checklist.push({ tipo: "extratos_bancarios", participante });
    }
    return;
  }

  if (regime === "aposentado" || regime === "beneficio") {
    checklist.push({ tipo: "comprovante_aposentadoria", participante });
    return;
  }

  if (regime === "pensionista") {
    checklist.push({ tipo: "comprovante_pensao", participante });
  }
}

function resolveAutonomoIrDeclarado(st, participante) {
  const readBool = (value) => {
    if (value === true) return true;
    if (value === false || value == null) return false;
    const txt = String(value).trim().toLowerCase();
    if (["true", "1", "sim", "yes"].includes(txt)) return true;
    if (["false", "0", "nao", "nûÈo", "no"].includes(txt)) return false;
    return false;
  };

  if (participante === "p1") {
    if (st.autonomo_ir === true || st.autonomo_ir === false) return st.autonomo_ir;
    return readBool(st.ir_declarado);
  }

  if (participante === "p2") {
    if (st.ir_declarado_parceiro === true || st.ir_declarado_parceiro === false) return st.ir_declarado_parceiro;
    return readBool(st.ir_declarado_p2);
  }

  return false;
}

// 17.2 ã Gera checklist dinûÂmico p/ P1 e P2
function generateChecklistForDocs(st) {
  const checklist = [];
  const hasP2Confirmado = hasComposicaoConfirmadaP2(st);
  const hasP3Confirmado = hasComposicaoConfirmadaP3(st);

  const addChecklistBase = (participante) => {
    checklist.push(
      { tipo: "identidade_cpf", participante },
      { tipo: "comprovante_residencia", participante },
      { tipo: "ctps_completa", participante }
    );
  };

  addChecklistBase("p1");
  appendChecklistByRegime(
    checklist,
    "p1",
    String(st.regime_trabalho || "").trim().toLowerCase(),
    resolveAutonomoIrDeclarado(st, "p1")
  );

  // Casamento civil ã certidûÈo
  if (st.casamento_formal === "civil_papel" || st.estado_civil === "casado") {
    checklist.push({ tipo: "certidao_casamento", participante: "p1" });
  }

  // Dependente
  if (st.dependente === true) {
    checklist.push({
      tipo: "certidao_nascimento_dependente",
      participante: "p1"
    });
  }

  // Documentos P2 caso somar renda
  if (hasP2Confirmado) {
    addChecklistBase("p2");
    appendChecklistByRegime(
      checklist,
      "p2",
      String(st.regime_trabalho_parceiro || st.regime_trabalho_parceiro_familiar || "").trim().toLowerCase(),
      resolveAutonomoIrDeclarado(st, "p2")
    );
  }

  if (hasP3Confirmado) {
    addChecklistBase("p3");
    appendChecklistByRegime(
      checklist,
      "p3",
      String(st.regime_trabalho_parceiro_familiar_p3 || "").trim().toLowerCase(),
      resolveAutonomoIrDeclarado(st, "p3")
    );
  }

  return dedupeChecklist(checklist);
}

function normalizeEnvioDocsParticipantId(value) {
  const participante = String(value || "").trim().toLowerCase();
  return ENVIO_DOCS_ORDEM_PARTICIPANTES.includes(participante) ? participante : null;
}

function resolveEnvioDocsCanonicalParticipantsFromState(st = {}) {
  const fromDossie = Array.isArray(st?.dossie_participantes_json) ? st.dossie_participantes_json : [];
  const fromPacote = Array.isArray(st?.pacote_participantes_json) ? st.pacote_participantes_json : [];
  const participantes = [...fromDossie, ...fromPacote]
    .map((item) => normalizeEnvioDocsParticipantId(item?.id || item?.participante))
    .filter(Boolean);
  return ENVIO_DOCS_ORDEM_PARTICIPANTES.filter((participante) => participantes.includes(participante));
}

function resolveEnvioDocsCanonicalChecklistFromDossier(st = {}, participantesCanonicos = []) {
  const pendenciasDossie = Array.isArray(st?.dossie_pendencias_json) ? st.dossie_pendencias_json : [];
  const docsObrigatorios = Array.isArray(st?.dossie_docs_obrigatorios_json) ? st.dossie_docs_obrigatorios_json : [];
  const docsCondicionais = Array.isArray(st?.dossie_docs_condicionais_json) ? st.dossie_docs_condicionais_json : [];
  const base = pendenciasDossie.length ? pendenciasDossie : [...docsObrigatorios, ...docsCondicionais];
  const participantesSet = new Set(Array.isArray(participantesCanonicos) ? participantesCanonicos : []);
  const checklist = dedupeChecklist(
    base
      .map((item) => {
        const participante = normalizeEnvioDocsParticipantId(item?.participante);
        const tipo = String(item?.tipo || "").trim().toLowerCase();
        if (!participante || !tipo) return null;
        if (participantesSet.size && !participantesSet.has(participante)) return null;
        const bucket =
          String(item?.bucket || "").trim().toLowerCase() ||
          (item?.obrigatorio === true ? "obrigatorio" : item?.regra ? "condicional" : "obrigatorio");
        return {
          tipo,
          participante,
          bucket,
          status: "pendente"
        };
      })
      .filter(Boolean)
  );
  return checklist;
}

function reconcileEnvioDocsItensWithSavedDossier(st = {}, itensEnvioDocs = []) {
  const itensAtuais = Array.isArray(itensEnvioDocs) ? itensEnvioDocs : [];
  const participantesCanonicos = resolveEnvioDocsCanonicalParticipantsFromState(st);
  if (!participantesCanonicos.length) return itensAtuais;

  const participantesSet = new Set(participantesCanonicos);
  const itensFiltrados = itensAtuais.filter((item) => participantesSet.has(normalizeEnvioDocsParticipantId(item?.participante)));
  const checklistCanonico = resolveEnvioDocsCanonicalChecklistFromDossier(st, participantesCanonicos);
  if (!checklistCanonico.length) return itensFiltrados;

  const itensAtuaisMap = new Map(
    itensFiltrados.map((item) => [getEnvioDocsChecklistItemKey(item), item])
  );
  return checklistCanonico.map((item) => {
    const key = getEnvioDocsChecklistItemKey(item);
    const atual = itensAtuaisMap.get(key);
    if (!atual) return item;
    return {
      ...item,
      ...atual,
      tipo: item.tipo,
      participante: item.participante,
      bucket: item.bucket || atual.bucket
    };
  });
}

// 17.3 ã Salva o status no Supabase
async function saveDocumentStatus(env, st, status) {
  await sbFetch(env, "/rest/v1/enova_docs_status", {
    method: "POST",
    body: JSON.stringify({
      wa_id: st.wa_id,
      status_json: status,
      updated_at: new Date().toISOString()
    })
  });
}

// ======================================================================
// ÞÏÝ BLOCO 18 ã ORQUESTRADOR DE DOCUMENTOS (PENDûNCIAS + AVANûO)
// ======================================================================

/**
 * updateDocsStatusV2(env, st)
 *
 * NOVA VERSûO ã segura e sem conflitos
 *
 * O que faz:
 *  - consulta todos os docs enviados no Supabase (enova_docs)
 *  - gera checklist atualizado (Bloco 16)
 *  - compara docs recebidos vs docs necessûÀrios (P1 e P2)
 *  - cria lista de pendûˆncias
 *  - se tudo entregue ã retorna { completo: true }
 *    se faltar ã retorna { completo: false, pendentes: [...] }
 */
async function updateDocsStatusV2(env, st) {

  // ================================
  // 1 ã BUSCA DOCUMENTOS RECEBIDOS
  // ================================
  const { data: docsRecebidos } = await sbFetch(env, "/rest/v1/enova_docs", {
    method: "GET",
    query: {
      wa_id: `eq.${st.wa_id}`,
      select: "*"
    }
  });

  const recebidos = docsRecebidos || [];

  // ================================
  // 2 ã CHECKLIST (docs necessûÀrios)
  // ================================
  const checklist = await gerarChecklistDocumentos(st);

    // ================================
  // 3 ã COMPARAR (pendûˆncias)
  // ================================
  const pendencias = [];

    for (const item of checklist) {
    const participanteChecklist = String(item?.participante || "").trim().toLowerCase();
    const tipoChecklist = String(item?.tipo || "").trim().toLowerCase();

    const docsDoParticipante = recebidos.filter((d) => {
      const participanteDoc = String(d?.participante || d?.participant || "").trim().toLowerCase();
      return participanteDoc === participanteChecklist;
    });

    const tiposRecebidos = new Set(
      docsDoParticipante
        .map((d) => String(d?.tipo || "").trim().toLowerCase())
        .filter(Boolean)
    );

    const achou = (() => {
      if (tiposRecebidos.has(tipoChecklist)) return true;

      if (tipoChecklist === "identidade_cpf") {
  if (tiposRecebidos.has("cnh")) return true;
  if (tiposRecebidos.has("rg_com_cpf")) return true;
  if (tiposRecebidos.has("rg") && tiposRecebidos.has("cpf")) return true;
}

      if (tipoChecklist === "ctps_completa" && tiposRecebidos.has("ctps")) return true;
      if (tipoChecklist === "holerites" && tiposRecebidos.has("holerite")) return true;
      if (tipoChecklist === "extratos_bancarios" && tiposRecebidos.has("extrato_bancario")) return true;

      return false;
    })();

    if (!achou) pendencias.push(item);
  }

  // ================================
  // 4 ã ATUALIZA STATUS NO SUPABASE
  // ================================
  await upsertState(env, st.wa_id, {
    docs_pendentes: pendencias.length,
    docs_completos: pendencias.length === 0
  });

  // ================================
  // 5 ã RETORNO FINAL
  // ================================
  return {
    completo: pendencias.length === 0,
    pendentes: pendencias
  };
}


// ====== FUNûûO: MENSAGEM BONITA DAS PENDûNCIAS ======
function mensagemPendenciasHumanizada(list) {
  if (!list || list.length === 0)
    return ["Tudo certo! Nenhuma pendûˆncia Þ"];

  const linhas = ["Ainda preciso destes docs pra finalizar Þ"];

  for (const item of list) {
    const tipo = labelTipoDocumento(item.tipo);
    const dono = item.participante === "p1" ? "seu" : "do parceiro(a)";
    linhas.push(`ãÂ ${tipo} (${dono})`);
  }

  return linhas;
}

function envioDocsResumoPendencias(itens = [], options = {}) {
  const includeNonBlocking = options?.includeNonBlocking === true;
  const requestedLimit = Number(options?.limit);
  const limit = Number.isFinite(requestedLimit) && requestedLimit >= 0 ? Math.floor(requestedLimit) : 4;
  const pendentes = (Array.isArray(itens) ? itens : [])
    .filter((item) => !isEnvioDocsItemReceived(item))
    .filter((item) => includeNonBlocking || isEnvioDocsBlockingItem(item));
  const resumo = limit === 0 ? pendentes : pendentes.slice(0, limit);
  return resumo.map((item) => `ãÂ ${prettyDocLabel(item.tipo)} (${item.participante === "p1" ? "titular" : "composiûÏûÈo"})`);
}

function resolveEnvioDocsNextPendingItemForClient(itens = []) {
  const itensBase = Array.isArray(itens) ? itens : [];
  const pendentes = itensBase.filter((item) => isEnvioDocsConversationalPendingItem(item));
  if (!pendentes.length) return null;
  const participanteAtual = resolveEnvioDocsCurrentParticipant(itensBase);
  const pendentesParticipanteAtual = pendentes.filter(
    (item) => String(item?.participante || "").trim().toLowerCase() === participanteAtual
  );
  const universoBusca = pendentesParticipanteAtual.length ? pendentesParticipanteAtual : pendentes;
  const pendenteBloqueante = universoBusca.find((item) => isEnvioDocsBlockingItem(item));
  if (pendenteBloqueante) return pendenteBloqueante;
  const pendenteCtps = universoBusca.find((item) => {
    const tipo = String(item?.tipo || "").trim().toLowerCase();
    return CTPS_NON_BLOCKING_DOC_TYPES.has(tipo);
  });
  return pendenteCtps || universoBusca[0];
}

function isEnvioDocsConversationalFlowComplete(itens = []) {
  const pendentesConversacionais = (Array.isArray(itens) ? itens : []).filter((item) =>
    isEnvioDocsConversationalPendingItem(item)
  );
  return pendentesConversacionais.length === 0;
}

function buildEnvioDocsNextPendingPrompt(item) {
  if (!item) return null;
  const tipo = String(item?.tipo || "").trim().toLowerCase();
  const participante = String(item?.participante || "").trim().toLowerCase();
  const docMap = {
    identidade_cpf: "o documento de identificaûÏûÈo",
    comprovante_residencia: "o comprovante de residûˆncia",
    holerites: "o holerite",
    holerite: "o holerite",
    comprovante_renda: "o comprovante de renda",
    declaracao_ir: "a declaraûÏûÈo de IR",
    recibo_ir: "o recibo de IR",
    extratos_bancarios: "os extratos bancûÀrios",
    extrato_bancario: "o extrato bancûÀrio",
    ctps_completa: "a CTPS completa",
    ctps: "a CTPS completa",
    certidao_casamento: "a certidûÈo de casamento",
    certidao_nascimento_dependente: "a certidûÈo de nascimento do dependente"
  };
  const documento = docMap[tipo] || `o documento ${prettyDocLabel(tipo).toLowerCase()}`;
  const alvo =
    participante === "p1"
      ? "do titular"
      : participante === "p2"
        ? "da composiûÏûÈo (parceiro(a))"
        : participante === "p3"
          ? "da composiûÏûÈo (familiar)"
          : "da composiûÏûÈo";
  return `Agora me envie ${documento} ${alvo}.`;
}

function buildEnvioDocsUploadGuidanceLines(itens = [], progress = {}) {
  if (isEnvioDocsConversationalFlowComplete(itens)) {
    return ["Recebemos sua pasta. Agora ela estûÀ em anûÀlise documental."];
  }
  const proximoItem = resolveEnvioDocsNextPendingItemForClient(itens);
  const proximoPedido = buildEnvioDocsNextPendingPrompt(proximoItem);
  if (proximoPedido) return [proximoPedido];
  return ["Pode me enviar o prû°ximo documento para concluir sua pasta."];
}

function isEnvioDocsBlockingItem(item) {
  if (!item || typeof item !== "object") return false;
  const tipo = String(item?.tipo || "").trim().toLowerCase();
  // Regra canûÇnica: CTPS continua na checklist/processo, mas nûÈo entra no gate bloqueante de envio ao correspondente.
  if (CTPS_NON_BLOCKING_DOC_TYPES.has(tipo)) return false;
  if (item.bucket === "obrigatorio") return true;
  if (item.bucket === "condicional") return false;
  if (item.bucket === "recomendado") return false;
  if (item.obrigatorio === true) return true;
  if (item.recomendacao) return false;
  if (item.regra) return true;
  // Fallback seguro: item sem metadado explûÙcito entra como bloqueante para nûÈo liberar "completo" por engano.
  return true;
}

function isEnvioDocsItemReceived(item) {
  const rawStatus = (item?.status || "").trim().toLowerCase();
  return (
    rawStatus === "recebido_pendente_validacao" ||
    rawStatus === "recebido pendente validacao" ||
    rawStatus === "validado_basico" ||
    rawStatus === "validado basico" ||
    rawStatus === "recebido" ||
    rawStatus === "validado"
  );
}

function isEnvioDocsItemUploadAttempted(item) {
  const rawStatus = (item?.status || "").trim().toLowerCase();
  if (isEnvioDocsItemReceived(item)) return true;
  return (
    rawStatus === "ilegivel" ||
    rawStatus === "ilegûÙvel" ||
    rawStatus === "invûÀlido" ||
    rawStatus === "invalido" ||
    rawStatus === "reenvio_solicitado" ||
    rawStatus === "reenvio solicitado"
  );
}

function recomputeEnvioDocsProgress(itens = []) {
  const itensBloqueantes = itens.filter((item) => isEnvioDocsBlockingItem(item));
  const totalRecebidos = itensBloqueantes.filter((item) => isEnvioDocsItemUploadAttempted(item)).length;
  const totalPendentes = itensBloqueantes.filter((item) => !isEnvioDocsItemReceived(item)).length;
  const status =
    totalRecebidos === 0
      ? "aguardando_envio"
      : totalPendentes === 0
        ? "completo"
        : "parcial";

  return {
    envio_docs_total_recebidos: totalRecebidos,
    envio_docs_total_pendentes: totalPendentes,
    envio_docs_status: status
  };
}

const ENVIO_DOCS_LEGACY_PENDING_CONFIRMATION_PREFIX = "pendente_confirmacao_tipo_doc::";

function encodeEnvioDocsLegacyPendingConfirmation(record = null) {
  if (!record || typeof record !== "object") return null;
  const compact = {
    upload_id: record?.upload_id || null,
    upload_message_id: record?.upload_message_id || null,
    detected_doc_type: record?.detected_doc_type || null,
    detected_doc_category: record?.detected_doc_category || null,
    detected_participant: record?.detected_participant || null,
    candidate_items: Array.isArray(record?.candidate_items)
      ? record.candidate_items.map((item) => ({
          tipo: item?.tipo || null,
          participante: item?.participante || null
        }))
      : [],
    pergunta_confirmacao: record?.pergunta_confirmacao || null,
    recebido_em: record?.recebido_em || record?.at || null
  };
  try {
    return `${ENVIO_DOCS_LEGACY_PENDING_CONFIRMATION_PREFIX}${JSON.stringify(compact)}`;
  } catch {
    return null;
  }
}

function decodeEnvioDocsLegacyPendingConfirmation(st = {}) {
  const raw = String(st?.docs_status_texto || "").trim();
  if (!raw.startsWith(ENVIO_DOCS_LEGACY_PENDING_CONFIRMATION_PREFIX)) return null;
  const payloadRaw = raw.slice(ENVIO_DOCS_LEGACY_PENDING_CONFIRMATION_PREFIX.length);
  if (!payloadRaw) return null;
  try {
    const parsed = JSON.parse(payloadRaw);
    if (!parsed || typeof parsed !== "object") return null;
    return parsed;
  } catch {
    return null;
  }
}

function normalizeEnvioDocsLegacyStatus(progressStatus) {
  const raw = String(progressStatus || "").trim().toLowerCase();
  if (raw === "completo") return "completo";
  if (raw === "parcial") return "parcial";
  return "pendente";
}

function buildEnvioDocsLegacySummaryPatch(itens = [], progress = {}, options = {}) {
  const nowIso = new Date().toISOString();
  const recebidos = itens
    .filter((item) => isEnvioDocsItemReceived(item))
    .map((item) => ({ tipo: item?.tipo || null, participante: item?.participante || null }));
  const faltantes = itens
    .filter((item) => isEnvioDocsBlockingItem(item) && !isEnvioDocsItemReceived(item))
    .map((item) => ({ tipo: item?.tipo || null, participante: item?.participante || null }));
  const legacyStatus = normalizeEnvioDocsLegacyStatus(progress?.envio_docs_status);
  const isPendingConfirmation = options?.isPendingConfirmation === true;
  const pendingSummaryText = isPendingConfirmation
    ? encodeEnvioDocsLegacyPendingConfirmation(options?.pendingConfirmationRecord || null)
    : null;
  const resumoPendencias = envioDocsResumoPendencias(itens, { includeNonBlocking: true, limit: 0 });
  const summaryText = pendingSummaryText || (
    legacyStatus === "completo"
      ? "Pasta documental completa e pronta para anûÀlise."
      : resumoPendencias.length
        ? `Pendûˆncias atuais: ${resumoPendencias.join(" | ")}`
        : "Pasta em atualizaûÏûÈo documental."
  );
  return {
    docs_status: legacyStatus,
    docs_status_geral: legacyStatus,
    docs_status_completo: legacyStatus === "completo",
    docs_status_parcial: legacyStatus === "parcial",
    docs_completos: legacyStatus === "completo",
    docs_faltantes: faltantes,
    docs_itens_pendentes: faltantes,
    docs_itens_recebidos: recebidos,
    docs_pendentes: Number(progress?.envio_docs_total_pendentes || faltantes.length) || 0,
    fase_docs: isPendingConfirmation ? "aguardando_confirmacao_tipo_doc" : "envio_documentos",
    docs_status_texto: summaryText,
    docs_validacao_atualizada: nowIso,
    ultima_interacao_docs: nowIso
  };
}

function mapAnaliseDocsStatusToLegacyStatus(analiseStatus) {
  const raw = String(analiseStatus || "").trim().toLowerCase();
  if (!raw) return null;
  if (raw === "validada") return "completo";
  if (raw === "em_analise") return "parcial";
  if (raw === "pendente_ajuste") return "pendente";
  return raw;
}

function pickEnvioDocsPersistedPacotePatch(pacotePayload = {}) {
  const base = pacotePayload && typeof pacotePayload === "object" ? pacotePayload : {};
  return {
    pacote_status: base?.pacote_status || null,
    pacote_destino: base?.pacote_destino || null,
    pacote_resumo_caso: base?.pacote_resumo_caso || null,
    pacote_enviado_em: base?.pacote_enviado_em || null,
    pacote_participantes_json: Array.isArray(base?.pacote_participantes_json) ? base.pacote_participantes_json : null,
    pacote_renda_resumo_json: base?.pacote_renda_resumo_json && typeof base.pacote_renda_resumo_json === "object" ? base.pacote_renda_resumo_json : null,
    pacote_restricoes_json: base?.pacote_restricoes_json && typeof base.pacote_restricoes_json === "object" ? base.pacote_restricoes_json : null,
    pacote_pendencias_json: Array.isArray(base?.pacote_pendencias_json) ? base.pacote_pendencias_json : null,
    pacote_documentos_anexados_json: Array.isArray(base?.pacote_documentos_anexados_json) ? base.pacote_documentos_anexados_json : null,
    pacote_observacoes_json: Array.isArray(base?.pacote_observacoes_json) ? base.pacote_observacoes_json : null
  };
}

function buildEnvioDocsPlausiveisPendentesConferenciaFromState(st = {}) {
  const pendingStatusRaw = String(
    st?.envio_docs_confirmacao_tipo_doc_status ||
    st?.fase_docs ||
    ""
  ).trim().toLowerCase();
  const pendingStatus = pendingStatusRaw === "aguardando_confirmacao_tipo_doc"
    ? "aguardando_confirmacao_tipo_doc"
    : "";
  const pendingUpload = (
    st?.envio_docs_ultimo_upload_pendente_confirmacao_json &&
    typeof st.envio_docs_ultimo_upload_pendente_confirmacao_json === "object"
  )
    ? st.envio_docs_ultimo_upload_pendente_confirmacao_json
    : decodeEnvioDocsLegacyPendingConfirmation(st);
  if (pendingStatus !== "aguardando_confirmacao_tipo_doc" || !pendingUpload || typeof pendingUpload !== "object") {
    return [];
  }
  const candidateItems = Array.isArray(pendingUpload?.candidate_items) ? pendingUpload.candidate_items : [];
  const mediaRef = pendingUpload?.media_ref && typeof pendingUpload.media_ref === "object" ? pendingUpload.media_ref : {};
  return [{
    upload_id: pendingUpload?.upload_id || null,
    status: "plausivel_incerto",
    detected_doc_type: pendingUpload?.detected_doc_type || null,
    detected_doc_category: pendingUpload?.detected_doc_category || null,
    detected_participant: pendingUpload?.detected_participant || null,
    candidate_items: candidateItems.map((item) => ({
      tipo: item?.tipo || null,
      participante: item?.participante || null
    })),
    file_name: mediaRef?.file_name || pendingUpload?.file_name || null,
    mime_type: mediaRef?.mime_type || null,
    media_id: mediaRef?.media_id || null,
    url: String(
      mediaRef?.url ||
      mediaRef?.link ||
      mediaRef?.document_url ||
      mediaRef?.download_url ||
      mediaRef?.media_url ||
      ""
    ).trim() || null,
    recebido_em: pendingUpload?.recebido_em || pendingUpload?.at || null
  }];
}

function buildAnaliseDocsPayloadFromEnvio(itens = [], options = {}) {
  const itensBloqueantes = itens.filter((item) => isEnvioDocsBlockingItem(item));
  const normalizeStatus = (item) => String(item?.status || "").trim().toLowerCase();
  const plausiveisPendentes = Array.isArray(options?.plausiveisPendentes) ? options.plausiveisPendentes : [];
  const plausiveisCandidateKeys = new Set(
    plausiveisPendentes.flatMap((item) =>
      Array.isArray(item?.candidate_items)
        ? item.candidate_items.map((candidate) => `${candidate?.tipo || ""}:${candidate?.participante || ""}`)
        : []
    )
  );

  const docsValidos = itensBloqueantes.filter((item) => isEnvioDocsItemReceived(item));
  const docsInvalidos = itensBloqueantes.filter((item) => {
    const status = normalizeStatus(item);
    return status === "invalido" || status === "invûÀlido" || status === "reenvio_solicitado" || status === "reenvio solicitado";
  });
  const docsIlegiveis = itensBloqueantes.filter((item) => {
    const status = normalizeStatus(item);
    return status === "ilegivel" || status === "ilegûÙvel";
  });
  const docsFaltantes = itensBloqueantes.filter((item) => {
  if (isEnvioDocsItemReceived(item)) return false;
  const status = normalizeStatus(item);
  const itemKey = `${item?.tipo || ""}:${item?.participante || ""}`;
  if (plausiveisCandidateKeys.has(itemKey)) return false;
  return !(
    status === "invalido" ||
    status === "invûÀlido" ||
    status === "reenvio_solicitado" ||
    status === "reenvio solicitado" ||
    status === "ilegivel" ||
    status === "ilegûÙvel"
  );
});

  const toDocItem = (item) => ({
    tipo: item?.tipo || null,
    participante: item?.participante || null,
    status: item?.status || null
  });

  const pendencias = [
    ...docsInvalidos.map((item) => ({ ...toDocItem(item), pendencia: "invalido" })),
    ...docsIlegiveis.map((item) => ({ ...toDocItem(item), pendencia: "ilegivel" })),
    ...plausiveisPendentes.map((item) => ({
      upload_id: item?.upload_id || null,
      tipo: item?.detected_doc_type || null,
      participante: item?.detected_participant || null,
      status: item?.status || "plausivel_incerto",
      pendencia: "plausivel_pendente_conferencia",
      candidate_items: Array.isArray(item?.candidate_items) ? item.candidate_items : []
    })),
    ...docsFaltantes.map((item) => ({ ...toDocItem(item), pendencia: "faltante" }))
  ];

  const analiseStatus =
  docsInvalidos.length > 0 || docsIlegiveis.length > 0
    ? "pendente_ajuste"
    : docsFaltantes.length > 0 || plausiveisPendentes.length > 0
      ? "em_analise"
      : "validada";

  const resumo = {
    status: analiseStatus,
    total_validos: docsValidos.length,
    total_plausiveis_pendentes_conferencia: plausiveisPendentes.length,
    total_invalidos: docsInvalidos.length,
    total_ilegiveis: docsIlegiveis.length,
    total_faltantes: docsFaltantes.length
  };

  return {
    analise_docs_status: analiseStatus,
    analise_docs_docs_confirmados_json: docsValidos.map(toDocItem),
    analise_docs_docs_plausiveis_pendentes_conferencia_json: plausiveisPendentes,
    analise_docs_total_validos: docsValidos.length,
    analise_docs_total_plausiveis_pendentes_conferencia: plausiveisPendentes.length,
    analise_docs_total_invalidos: docsInvalidos.length,
    analise_docs_total_ilegiveis: docsIlegiveis.length,
    analise_docs_total_faltantes: docsFaltantes.length,
    analise_docs_resumo_json: resumo,
    analise_docs_docs_invalidos_json: docsInvalidos.map(toDocItem),
    analise_docs_docs_ilegiveis_json: docsIlegiveis.map(toDocItem),
    analise_docs_docs_faltantes_json: docsFaltantes.map(toDocItem),
    analise_docs_pendencias_json: pendencias
  };
}

function buildPacoteRendaResumoPorParticipante(participantes = []) {
  return participantes.map((p) => {
    const rendaFormal = dossieToMoney(p?.renda_formal);
    const rendaInformal = dossieToMoney(p?.renda_informal);
    const rendaTotal = rendaFormal + rendaInformal;
    const natureza =
      rendaFormal > 0 && rendaInformal > 0
        ? "mista_ou_indefinida"
        : rendaFormal > 0
          ? "formal"
          : rendaInformal > 0
            ? "informal"
            : "mista_ou_indefinida";
    return {
      participante: p?.participante || p?.id || null,
      papel: p?.papel || p?.role || null,
      regime_trabalho: p?.regime_trabalho || null,
      renda_formal: rendaFormal,
      renda_informal: rendaInformal,
      renda_total: rendaTotal,
      natureza_renda: natureza
    };
  });
}

function buildPacoteDocumentosAnexadosResumo(itens = [], analiseBase = {}, historico = []) {
  const invalidos = Array.isArray(analiseBase?.analise_docs_docs_invalidos_json) ? analiseBase.analise_docs_docs_invalidos_json : [];
  const ilegiveis = Array.isArray(analiseBase?.analise_docs_docs_ilegiveis_json) ? analiseBase.analise_docs_docs_ilegiveis_json : [];
  const faltantes = Array.isArray(analiseBase?.analise_docs_docs_faltantes_json) ? analiseBase.analise_docs_docs_faltantes_json : [];
  const plausiveis = Array.isArray(analiseBase?.analise_docs_docs_plausiveis_pendentes_conferencia_json)
    ? analiseBase.analise_docs_docs_plausiveis_pendentes_conferencia_json
    : [];
  const historicoLista = Array.isArray(historico) ? historico : [];

  const invalidosSet = new Set(invalidos.map((i) => `${i?.tipo || ""}:${i?.participante || ""}`));
  const ilegiveisSet = new Set(ilegiveis.map((i) => `${i?.tipo || ""}:${i?.participante || ""}`));
  const faltantesSet = new Set(faltantes.map((i) => `${i?.tipo || ""}:${i?.participante || ""}`));
  const plausiveisSet = new Set(
    plausiveis.flatMap((i) =>
      Array.isArray(i?.candidate_items)
        ? i.candidate_items.map((candidate) => `${candidate?.tipo || ""}:${candidate?.participante || ""}`)
        : []
    )
  );
  const latestUploadByKey = new Map();
  for (let idx = historicoLista.length - 1; idx >= 0; idx -= 1) {
    const row = historicoLista[idx];
    if (!["upload", "confirmacao_textual"].includes(String(row?.origem || "").toLowerCase())) continue;
    const tipo = String(row?.associado?.tipo || row?.matched_checklist_item?.tipo || "").trim().toLowerCase();
    const participante = String(row?.associado?.participante || row?.matched_checklist_item?.participante || "").trim().toLowerCase();
    if (!tipo || !participante) continue;
    const key = `${tipo}:${participante}`;
    if (!latestUploadByKey.has(key)) latestUploadByKey.set(key, row);
  }

  return (Array.isArray(itens) ? itens : []).map((item) => {
    const key = `${item?.tipo || ""}:${item?.participante || ""}`;
    const uploadRef = latestUploadByKey.get(key);
    const mediaRef = uploadRef?.media_ref && typeof uploadRef.media_ref === "object" ? uploadRef.media_ref : {};
    const resolvedUrl = String(
      mediaRef?.url ||
      mediaRef?.link ||
      mediaRef?.document_url ||
      mediaRef?.download_url ||
      mediaRef?.media_url ||
      ""
    ).trim();
    return {
      tipo: item?.tipo || null,
      participante: item?.participante || null,
      bucket: item?.bucket || null,
      status: item?.status || null,
      recebido_em: item?.recebido_em || null,
      media_id: mediaRef?.media_id || null,
      mime_type: mediaRef?.mime_type || null,
      file_name: mediaRef?.file_name || null,
      ...(resolvedUrl ? { url: resolvedUrl } : {}),
      validacao_basica_motivo: item?.validacao_basica_motivo || null,
      observacao_analise: invalidosSet.has(key)
        ? "invalido"
        : ilegiveisSet.has(key)
          ? "ilegivel"
          : plausiveisSet.has(key)
            ? "plausivel_pendente_conferencia"
          : faltantesSet.has(key)
            ? "faltante"
            : "sem_pendencia_analise"
    };
  });
}

function buildPacoteCorrespondentePayloadFromState(st, itens = [], analisePayload = null) {
  const sinaisPersistidos = getCorrespondenteDossierPredocsSignals(st);
  const participantes = Array.isArray(st?.dossie_participantes_json) ? st.dossie_participantes_json : [];
  const baseMinimaCoerente = participantes.length > 0;
  const envioCompleto = String(st?.envio_docs_status || "").toLowerCase() === "completo";

  const analiseBase = analisePayload && typeof analisePayload === "object"
    ? analisePayload
    : {
      analise_docs_docs_confirmados_json: st?.analise_docs_docs_confirmados_json,
      analise_docs_docs_plausiveis_pendentes_conferencia_json: st?.analise_docs_docs_plausiveis_pendentes_conferencia_json,
      analise_docs_pendencias_json: st?.analise_docs_pendencias_json,
      analise_docs_docs_invalidos_json: st?.analise_docs_docs_invalidos_json,
      analise_docs_docs_ilegiveis_json: st?.analise_docs_docs_ilegiveis_json,
      analise_docs_docs_faltantes_json: st?.analise_docs_docs_faltantes_json
    };
  const docsConfirmados = Array.isArray(analiseBase?.analise_docs_docs_confirmados_json)
    ? analiseBase.analise_docs_docs_confirmados_json
    : [];
  const docsPlausiveisPendentes = Array.isArray(analiseBase?.analise_docs_docs_plausiveis_pendentes_conferencia_json)
    ? analiseBase.analise_docs_docs_plausiveis_pendentes_conferencia_json
    : [];
  const docsFaltantes = Array.isArray(analiseBase?.analise_docs_docs_faltantes_json)
    ? analiseBase.analise_docs_docs_faltantes_json
    : [];

  if (!baseMinimaCoerente || !envioCompleto || docsPlausiveisPendentes.length > 0) {
    return {
      pacote_status: "nao_montado",
      pacote_destino: "correspondente",
      pacote_enviado_em: null,
      pacote_docs_confirmados_json: docsConfirmados,
      pacote_docs_plausiveis_pendentes_conferencia_json: docsPlausiveisPendentes,
      pacote_docs_faltantes_json: docsFaltantes
    };
  }

  const pendencias = Array.isArray(analiseBase?.analise_docs_pendencias_json)
    ? analiseBase.analise_docs_pendencias_json
    : Array.isArray(st?.dossie_pendencias_json)
      ? st.dossie_pendencias_json
      : [];

  const observacoesCorrespondente = Array.isArray(st?.dossie_observacoes_correspondente_json) ? st.dossie_observacoes_correspondente_json : [];
  const observacoesCliente = Array.isArray(st?.dossie_observacoes_cliente_json) ? st.dossie_observacoes_cliente_json : [];
  const observacoes = [...new Set([...observacoesCorrespondente, ...observacoesCliente])];
  const historicoUploads = Array.isArray(st?.envio_docs_historico_json) ? st.envio_docs_historico_json : [];

  const rendaResumoPorParticipante = buildPacoteRendaResumoPorParticipante(participantes);
  const rendaTotalFormal = Number(st?.dossie_renda_total_formal ?? 0) || 0;
  const rendaTotalInformal = Number(st?.dossie_renda_total_informal ?? 0) || 0;

  return {
    pacote_status: "pronto",
    pacote_destino: "correspondente",
    pacote_resumo_caso: st?.dossie_resumo_humano || `Pacote com ${participantes.length} participante(s) pronto para correspondente.`,
    pacote_enviado_em: null,
    pacote_participantes_json: participantes,
    pacote_renda_resumo_json: {
      total_formal: rendaTotalFormal,
      total_informal: rendaTotalInformal,
      total_geral: rendaTotalFormal + rendaTotalInformal,
      por_participante: rendaResumoPorParticipante
    },
    pacote_restricoes_json: {
      resumo: st?.dossie_restricao_resumo || null,
      participantes: participantes.map((p) => ({
        participante: p?.participante || p?.id || null,
        tem_restricao: dossieIsYes(p?.tem_restricao ?? p?.restricao),
        restricao_regularizada: dossieIsYes(p?.restricao_regularizada ?? p?.regularizacao_restricao)
      }))
    },
    pacote_docs_confirmados_json: docsConfirmados,
    pacote_docs_plausiveis_pendentes_conferencia_json: docsPlausiveisPendentes,
    pacote_docs_faltantes_json: docsFaltantes,
    pacote_pendencias_json: pendencias,
    pacote_documentos_anexados_json: buildPacoteDocumentosAnexadosResumo(itens, analiseBase, historicoUploads),
    pacote_observacoes_json: observacoes,
    pacote_sinais_persistidos_json: sinaisPersistidos
  };
}

function guessEnvioDocsTipoFromText(texto) {
  const t = normalizeText(texto || "");
  if (!t) return null;

  if (/\b(cnh|carteira nacional de habilitacao|habilitacao|carteira de motorista)\b/.test(t)) return "cnh";
  if (/\b(ctps|carteira de trabalho)\b/.test(t)) return "ctps";
  if (/\b(rg|registro geral|identidade)\b/.test(t)) return "rg";
  if (/\bcpf\b/.test(t)) return "cpf";

  if (/\b(comprovante.*resid\w*|residenc\w*|conta de (luz|agua|ûÀgua|internet)|iptu)\b/.test(t)) {
    return "comprovante_residencia";
  }
  if (/\b(comprovante.*rend\w*|rend\w*.*comprovante)\b/.test(t)) return "comprovante_renda";

  if (/\b(holerite|contracheque)\b/.test(t)) return "holerite";
  if (/\bextrat/.test(t)) return "extrato_bancario";

  if ((/\b(recibo|darf)\b/.test(t)) && (/\bir\b/.test(t) || /\bimposto de renda\b/.test(t))) {
    return "recibo_ir";
  }

  if ((/\b(declaracao|declaraûÏûÈo)\b/.test(t)) && (/\bir\b/.test(t) || /\bimposto de renda\b/.test(t))) {
    return "declaracao_ir";
  }

  if (/\b(certidao|certidûÈo)\b/.test(t) && /\bnasc/.test(t)) return "certidao_nascimento_dependente";
  if (/\b(certidao|certidûÈo)\b/.test(t) && /\bcasament/.test(t)) return "certidao_casamento";

  if (/\bir\b/.test(t)) return "declaracao_ir";

  return null;
}

function inferEnvioDocsParticipanteFromText(texto) {
  const t = normalizeText(texto || "");
  if (!t) return null;

  if (/\b(p1|titular|principal|cliente)\b/.test(t)) return "p1";
  if (/\b(p2|parceir[oa]?|espos[ao]|conjuge|c[oûÇ]njuge)\b/.test(t)) return "p2";
  if (/\b(p3|familiar|dependente|filh[oa]|pai|mae|mûÈe|irma[oa]|avo|av[oû°]|sogr[oa])\b/.test(t)) return "p3";
  return null;
}

function envioDocsParticipanteLabel(participante) {
  if (participante === "p1") return "titular";
  if (participante === "p2") return "parceiro(a)";
  if (participante === "p3") return "familiar";
  return "composiûÏûÈo";
}

function envioDocsCategoriaFromTipo(tipo) {
  const t = String(tipo || "").trim().toLowerCase();
  if (["identidade_cpf", "rg", "cnh", "cpf"].includes(t)) return "identidade";
  if (t === "comprovante_residencia") return "comprovante_residencia";
  if (["holerite", "holerites", "holerite_ultimo", "holerites_ultimos_3", "declaracao_ir", "recibo_ir", "extrato_bancario", "extratos_bancarios", "extratos_bancarios_3_meses", "ctps", "ctps_completa", "comprovante_renda", "comprovante_pensao", "comprovante_aposentadoria"].includes(t)) return "comprovante_renda";
  if (["certidao_casamento", "certidao_nascimento_dependente"].includes(t)) return "documento_civil";
  return null;
}

function normalizeEnvioDocsTipoForChecklist(tipo) {
  const t = String(tipo || "").trim().toLowerCase();
  if (!t) return null;
  if (t === "cnh") return "rg";
  if (t === "rg_com_cpf") return "rg";
  if (t === "holerite") return "holerite_ultimo";
  if (t === "extrato_bancario") return "extratos_bancarios_3_meses";
  if (t === "ctps") return "ctps_completa";
  return t;
}

const ENVIO_DOCS_COVERAGE_MAP = Object.freeze({
  cnh: ["rg", "cpf"],
  rg: ["rg"],
  rg_com_cpf: ["rg", "cpf"],
  cpf: ["cpf"],
  comprovante_residencia: ["comprovante_residencia"],
  holerite: ["comprovante_renda"],
  ctps: ["ctps_completa"],
  extrato_bancario: ["comprovante_renda"],
  declaracao_ir: ["comprovante_renda"],
  recibo_ir: ["comprovante_renda"]
});
const ENVIO_DOCS_TIPOS_ALVO_RENDA_RESIDENCIA = Object.freeze([
  "comprovante_residencia",
  "holerite",
  "extrato_bancario",
  "declaracao_ir",
  "recibo_ir"
]);

function getEnvioDocsCoveredChecklistTypes(detectedDocType) {
  const t = String(detectedDocType || "").trim().toLowerCase();
  if (!t) return [];
  return Array.isArray(ENVIO_DOCS_COVERAGE_MAP[t]) ? ENVIO_DOCS_COVERAGE_MAP[t] : [];
}

function envioDocsCoveredTypeMatchesItemType(coveredType, itemTipo) {
  const covered = String(coveredType || "").trim().toLowerCase();
  const item = String(itemTipo || "").trim().toLowerCase();
  if (!covered || !item) return false;
  if (covered === item) return true;
  if ((covered === "rg" || covered === "cpf") && item === "identidade_cpf") return true;
  return false;
}

function envioDocsHintTipoMatchesItemTipo(hintedTipoRaw, itemTipo) {
  const hinted = String(hintedTipoRaw || "").trim().toLowerCase();
  const item = String(itemTipo || "").trim().toLowerCase();
  if (!hinted || !item) return false;
  if (hinted === item) return true;
  const coveredTypes = getEnvioDocsCoveredChecklistTypes(hinted);
  if (coveredTypes.length && coveredTypes.some((coveredType) => envioDocsCoveredTypeMatchesItemType(coveredType, item))) return true;
  if (normalizeEnvioDocsTipoForChecklist(hinted) === item) return true;
  if (hinted === "holerite" && ["holerites", "holerites_ultimos_3", "holerite_ultimo"].includes(item)) return true;
  if (hinted === "extrato_bancario" && ["extratos_bancarios", "extratos_bancarios_3_meses"].includes(item)) return true;
  if (hinted === "ctps" && item === "ctps_completa") return true;
  return false;
}

// Checks if two CANONICAL/checklist types can both be covered by the same raw upload type.
// Needed for dossier projection when docs are stored with matched checklist types.
function canSameUploadCoverBothChecklistTypes(tipoA, tipoB) {
  const a = String(tipoA || "").trim().toLowerCase();
  const b = String(tipoB || "").trim().toLowerCase();
  if (!a || !b || a === b) return false;
  for (const rawType of Object.keys(ENVIO_DOCS_COVERAGE_MAP)) {
    if (envioDocsHintTipoMatchesItemTipo(rawType, a) && envioDocsHintTipoMatchesItemTipo(rawType, b)) {
      return true;
    }
  }
  return false;
}

function inferEnvioDocsCategoriaBasica({ hintText = "", filename = "", mimeType = "" } = {}) {
  const tipoFromHint = guessEnvioDocsTipoFromText(`${hintText || ""} ${filename || ""}`);
  const categoriaFromTipo = envioDocsCategoriaFromTipo(tipoFromHint);
  if (categoriaFromTipo) return categoriaFromTipo;

  const t = normalizeText(`${hintText || ""} ${filename || ""}`);
  if (/\b(certid\w*|casament\w*|nasciment\w*)\b/.test(t)) return "documento_civil";
  if (/\b(residenc\w*|conta de luz|conta de agua|conta de ûÀgua|iptu)\b/.test(t)) return "comprovante_residencia";
  if (/\b(renda\w*|holerit\w*|contracheque\w*|ir\b|extrat\w*|ctps)\b/.test(t)) return "comprovante_renda";
  if (/\b(rg|cpf|cnh|identidade)\b/.test(t)) return "identidade";

  const mime = String(mimeType || "").toLowerCase();
  if (mime.startsWith("image/") || mime === "application/pdf") return null;
  return "nao_documento";
}

function getEnvioDocsDocumentAIConfig(env) {
  const envMode = String(env?.ENV_MODE || env?.ENOVA_ENV || "").toLowerCase();
  const isProd = envMode === "prod";
  const apiKey = isProd
    ? (env?.MISTRAL_API_KEY || "")
    : (env?.MISTRAL_API_KEY_TEST || env?.MISTRAL_API_KEY || "");
  const model = String(env?.MISTRAL_DOC_MODEL || "mistral-ocr-latest");
  const endpoint = String(env?.MISTRAL_OCR_ENDPOINT || "https://api.mistral.ai/v1/ocr");
  return {
    provider: "mistral",
    envMode: isProd ? "prod" : "test",
    apiKey,
    model,
    endpoint,
    enabled: Boolean(apiKey)
  };
}

function getEnvioDocsDocumentAIProvider(env) {
  const config = getEnvioDocsDocumentAIConfig(env);
  return {
    ...config,
    runOcr: (input, options = {}) => runMistralOCR(env, input, options)
  };
}

function bufferToBase64Safe(arrayBuffer) {
  if (!arrayBuffer) return "";
  if (typeof Buffer !== "undefined") {
    return Buffer.from(arrayBuffer).toString("base64");
  }
  const bytes = new Uint8Array(arrayBuffer);
  const chars = Array.from(bytes, (b) => String.fromCharCode(b));
  const binary = chars.join("");
  if (typeof btoa === "function") return btoa(binary);
  return "";
}

async function downloadEnvioDocsMediaAsBase64(env, mediaObject, options = {}) {
  const fetchImpl = options?.fetchImpl || fetch;
  const mimeType = String(mediaObject?.mime_type || mediaObject?.mimetype || "").toLowerCase();
  const fileName = String(mediaObject?.filename || mediaObject?.file_name || "").trim() || null;
  const sourceUrl = String(
    mediaObject?.url ||
    mediaObject?.link ||
    mediaObject?.download_url ||
    mediaObject?.media_url ||
    ""
  ).trim();

  const inlineBase64 = String(
    mediaObject?.base64 ||
    mediaObject?.file_base64 ||
    mediaObject?.data_base64 ||
    ""
  ).trim();

  if (inlineBase64) {
    return {
      ok: true,
      base64: inlineBase64,
      source: "inline_base64",
      mime_type: mimeType || null,
      file_name: fileName
    };
  }

  const dataUrl = String(mediaObject?.data_url || "").trim();
  const dataUrlMatch = /^data:([^;]+);base64,(.+)$/i.exec(dataUrl);
  if (dataUrlMatch) {
    return {
      ok: true,
      base64: dataUrlMatch[2],
      source: "data_url",
      mime_type: mimeType || dataUrlMatch[1].toLowerCase(),
      file_name: fileName
    };
  }

  let resolvedUrl = sourceUrl;
  if (!resolvedUrl && mediaObject?.id && env?.WHATS_TOKEN) {
    try {
      const metaApiVersion = String(env?.META_API_VERSION || "v20.0");
      const metaResp = await fetchImpl(`https://graph.facebook.com/${metaApiVersion}/${mediaObject.id}`, {
        headers: { Authorization: `Bearer ${env.WHATS_TOKEN}` }
      });
      if (metaResp.ok) {
        const metaJson = await metaResp.json();
        resolvedUrl = String(metaJson?.url || "").trim();
      }
    } catch {}
  }

  if (!resolvedUrl) {
    return {
      ok: false,
      error_code: "missing_media_source",
      error_message: "Sem URL/base64 para extraûÏûÈo documental."
    };
  }

  try {
    const headers = {};
    if (env?.WHATS_TOKEN) headers.Authorization = `Bearer ${env.WHATS_TOKEN}`;
    const mediaResp = await fetchImpl(resolvedUrl, { headers });
    if (!mediaResp?.ok) {
      return {
        ok: false,
        error_code: `media_download_http_${mediaResp?.status || "unknown"}`,
        error_message: "Falha ao baixar mûÙdia para extraûÏûÈo documental."
      };
    }
    const arr = await mediaResp.arrayBuffer();
    return {
      ok: true,
      base64: bufferToBase64Safe(arr),
      source: "download_url",
      mime_type: mimeType || String(mediaResp.headers.get("content-type") || "").toLowerCase() || null,
      file_name: fileName
    };
  } catch (err) {
    return {
      ok: false,
      error_code: "media_download_exception",
      error_message: err?.message || "Erro ao baixar mûÙdia para extraûÏûÈo documental."
    };
  }
}

function extractMistralTextAndMetadata(payload) {
  const pages = Array.isArray(payload?.pages) ? payload.pages : [];
  const pieces = [];

  const rootText = [
    payload?.text,
    payload?.output_text,
    payload?.content,
    payload?.document?.text
  ].filter((v) => typeof v === "string" && v.trim().length > 0);
  pieces.push(...rootText);

  for (const p of pages) {
    if (typeof p?.markdown === "string" && p.markdown.trim()) pieces.push(p.markdown);
    else if (typeof p?.text === "string" && p.text.trim()) pieces.push(p.text);
    else if (typeof p?.content === "string" && p.content.trim()) pieces.push(p.content);
  }

  const resultNodes = Array.isArray(payload?.results) ? payload.results : [];
  for (const r of resultNodes) {
    if (typeof r?.text === "string" && r.text.trim()) pieces.push(r.text);
    else if (typeof r?.content === "string" && r.content.trim()) pieces.push(r.content);
  }

  const text = [...new Set(pieces.map((v) => String(v || "").trim()).filter(Boolean))].join("\n\n").trim();

  const pageCount =
    Number(payload?.page_count) ||
    Number(payload?.pages_count) ||
    (pages.length > 0 ? pages.length : null);

  const confidenceCandidates = [
    Number(payload?.confidence),
    ...pages.map((p) => Number(p?.confidence)).filter((v) => Number.isFinite(v))
  ].filter((v) => Number.isFinite(v) && v >= 0);
  const confidenceBase = confidenceCandidates.length
    ? confidenceCandidates.reduce((acc, n) => acc + n, 0) / confidenceCandidates.length
    : null;

  return { text, pageCount, confidenceBase };
}

const ENVIO_DOCS_MASKED_PREVIEW_MIN_LEN = 300;
const ENVIO_DOCS_MASKED_PREVIEW_MAX_LEN = 500;
const ENVIO_DOCS_MASKED_PREVIEW_SOURCE_SLICE_LEN = 900;

function maskEnvioDocsExtractPreview(text, maxLen = 400) {
  const limit = Math.max(
    ENVIO_DOCS_MASKED_PREVIEW_MIN_LEN,
    Math.min(ENVIO_DOCS_MASKED_PREVIEW_MAX_LEN, Number(maxLen) || 400)
  );
  const raw = String(text || "");
  if (!raw) return "";
  const source = raw.slice(0, Math.max(limit * 2, ENVIO_DOCS_MASKED_PREVIEW_SOURCE_SLICE_LEN));
  const masked = source
    .replace(/\b[A-Z0-9._%+-]+@[A-Z0-9.-]+\.[A-Z]{2,}\b/gi, "[email]")
    .replace(/\b(?:\d{3}\.?\d{3}\.?\d{3}-?\d{2}|\d{11})\b/g, "[cpf]")
    .replace(/\b(rg|rnm)\s*[:\-]?\s*[a-z0-9.\-\/]{5,24}\b/gi, (_, prefix) => `${String(prefix || "id").toLowerCase()}:[id]`)
    .replace(/\b(?:\d[\s.\-]?){8,}\d\b/g, "[num]")
    .replace(/\s+/g, " ")
    .trim();
  return masked.slice(0, limit);
}

function logEnvioDocsDocAiDebug(payload = {}) {
  try {
    console.log("ENVIO_DOCS_DOC_AI_DEBUG:", JSON.stringify(payload));
  } catch {}
}

function buildSafeMistralDebugPreview(input, maxLen = 400) {
  const limit = Math.max(300, Math.min(500, Number(maxLen) || 400));
  let raw = "";
  if (typeof input === "string") raw = input;
  else {
    try {
      raw = JSON.stringify(input || {});
    } catch {
      raw = String(input || "");
    }
  }
  const source = String(raw || "").slice(0, 2400);
  if (!source) return "";
  return source
    .replace(/\bBearer\s+[A-Za-z0-9._\-]+\b/gi, "Bearer [redacted]")
    .replace(/("?(?:authorization|api[_-]?key|token|secret|password)"?\s*:\s*)"[^"]+"/gi, "$1\"[redacted]\"")
    .replace(/\b[A-Za-z0-9+\/]{80,}={0,2}\b/g, "[blob]")
    .replace(/\b[A-Z0-9._%+-]+@[A-Z0-9.-]+\.[A-Z]{2,}\b/gi, "[email]")
    .replace(/\b(?:\d{3}\.?\d{3}\.?\d{3}-?\d{2}|\d{11})\b/g, "[cpf]")
    .replace(/\b(?:\d[\s.\-]?){8,}\d\b/g, "[num]")
    .replace(/\s+/g, " ")
    .trim()
    .slice(0, limit);
}

async function runMistralOCR(env, input = {}, options = {}) {
  const provider = getEnvioDocsDocumentAIProvider(env);
  const fetchImpl = options?.fetchImpl || fetch;
  if (!provider.enabled) {
    return {
      ok: false,
      provider: provider.provider,
      error_code: "missing_api_key",
      error_message: "Mistral API key ausente para extraûÏûÈo documental."
    };
  }

  const sourceType = String(input?.sourceType || "").toLowerCase();
  const isPdf = sourceType === "pdf";
  const sourceUrl = String(input?.sourceUrl || "").trim();
  const base64 = String(input?.base64 || "").trim();
  const waId = String(options?.wa_id || options?.waId || input?.wa_id || input?.waId || "").trim() || null;
  const mimeTypeRaw = String(
    input?.mime_type ||
    input?.mimeType ||
    options?.mime_type ||
    options?.mimeType ||
    ""
  ).toLowerCase().trim();
  const mimeType = mimeTypeRaw || null;
  const fileName = String(
    input?.file_name ||
    input?.fileName ||
    options?.file_name ||
    options?.fileName ||
    ""
  ).trim() || null;
  const base64Length = base64 ? base64.length : 0;
  const binarySizeFromInput = Number(
    input?.binary_size_bytes ??
    input?.binarySizeBytes ??
    options?.binary_size_bytes ??
    options?.binarySizeBytes
  );
  const binarySizeBytes = Number.isFinite(binarySizeFromInput)
    ? Math.max(0, Math.trunc(binarySizeFromInput))
    : (
      base64Length > 0
        ? Math.max(0, Math.floor((base64Length * 3) / 4) - (base64.endsWith("==") ? 2 : (base64.endsWith("=") ? 1 : 0)))
        : null
    );

  if (!sourceUrl && !base64) {
    return {
      ok: false,
      provider: provider.provider,
      error_code: "missing_input",
      error_message: "Entrada sem URL/base64 para OCR."
    };
  }

  const pdfDocumentUrl = !sourceUrl && isPdf && base64
    ? `data:${mimeType || "application/pdf"};base64,${base64}`
    : null;
  const imageDocumentUrl = !sourceUrl && !isPdf && base64
    ? `data:${mimeType && mimeType.startsWith("image/") ? mimeType : "image/jpeg"};base64,${base64}`
    : null;
  const document = sourceUrl
    ? { type: "document_url", document_url: sourceUrl }
    : isPdf
      ? { type: "document_url", document_url: pdfDocumentUrl }
      : { type: "document_url", document_url: imageDocumentUrl };
  const requestPayload = {
    model: provider.model,
    document
  };
  const payloadTopLevelKeys = Object.keys(requestPayload);
  const documentObjectKeys = document && typeof document === "object" ? Object.keys(document) : [];
  const runtimeGuardVersion = "mistral-runtime-guard-v1";
  const buildStamp = String(typeof ENOVA_BUILD === "string" ? ENOVA_BUILD : "").trim() || null;
  const gitCommitHint = getRuntimeGitCommitHint(env);
  const workerName = String(
    env?.WORKER_NAME ||
    env?.CF_WORKER_NAME ||
    env?.CLOUDFLARE_WORKER_NAME ||
    env?.ENOVA_WORKER_NAME ||
    "nv-enova"
  ).trim() || null;
  const deploymentHint = String(
    env?.ENOVA_DEPLOYMENT_HINT ||
    env?.CF_PAGES_URL ||
    env?.VERCEL_URL ||
    env?.WORKER_ENV ||
    ""
  ).trim() || null;
  const payloadShapeGuard = isPdf ? "pdf=document_url" : "non_pdf=document_url";
  const requestPathGuard = "runMistralOCR-active";
  const documentTypeFinal = document?.type || null;
  const documentUrlValue = documentTypeFinal === "document_url" ? String(document?.document_url || "").trim() : null;
  const documentUrlKind = documentTypeFinal === "document_url"
    ? (String(documentUrlValue || "").startsWith("data:") ? "data_url" : "remote_url")
    : null;
  const testKeyRaw = String(env?.MISTRAL_API_KEY_TEST || "");
  const prodKeyRaw = String(env?.MISTRAL_API_KEY || "");
  let usingTestKey = false;
  let usingProdKey = false;
  if (provider.envMode === "prod") {
    usingProdKey = Boolean(prodKeyRaw) && provider.apiKey === prodKeyRaw;
  } else if (Boolean(testKeyRaw) && provider.apiKey === testKeyRaw) {
    usingTestKey = true;
  } else {
    usingProdKey = Boolean(prodKeyRaw) && provider.apiKey === prodKeyRaw;
  }

  try {
    await telemetry(env, {
      wa_id: waId,
      event: "envio_docs_mistral_request_debug",
      stage: "envio_docs",
      severity: "info",
      force: true,
      message: "DEBUG request OCR Mistral",
      details: {
        wa_id: waId,
        mistral_endpoint: provider.endpoint || null,
        mistral_model: provider.model || null,
        build_stamp: buildStamp,
        git_commit_hint: gitCommitHint,
        runtime_guard_version: runtimeGuardVersion,
        worker_name: workerName,
        env_mode: provider.envMode || null,
        deployment_hint: deploymentHint,
        payload_shape_guard: payloadShapeGuard,
        request_path_guard: requestPathGuard,
        document_type: document?.type || null,
        document_type_final: documentTypeFinal,
        mime_type: mimeType,
        file_name: fileName,
        binary_size_bytes: binarySizeBytes,
        base64_length: base64Length,
        payload_has_document: Boolean(requestPayload?.document),
        payload_has_model: Boolean(requestPayload?.model),
        payload_top_level_keys: payloadTopLevelKeys,
        document_object_keys: documentObjectKeys,
        document_url_kind: documentUrlKind,
        using_test_key: usingTestKey === true,
        using_prod_key: usingProdKey === true
      }
    });
  } catch {}

  if (isPdf && documentTypeFinal !== "document_url") {
    const payloadShapeGuardExpected = "pdf=document_url";
    const payloadShapeGuardReceived = `pdf=${documentTypeFinal || "unknown"}`;
    try {
      await telemetry(env, {
        wa_id: waId,
        event: "envio_docs_mistral_pdf_shape_guard_violation",
        stage: "envio_docs",
        severity: "error",
        force: true,
        message: "Guard rail: PDF com shape invûÀlido antes do fetch OCR Mistral",
        details: {
          wa_id: waId,
          build_stamp: buildStamp,
          runtime_guard_version: runtimeGuardVersion,
          file_name: fileName,
          mime_type: mimeType,
          document_type_final: documentTypeFinal,
          document_object_keys: documentObjectKeys,
          payload_shape_guard_expected: payloadShapeGuardExpected,
          payload_shape_guard_received: payloadShapeGuardReceived,
          request_path_guard: requestPathGuard
        }
      });
    } catch {}
    return {
      ok: false,
      provider: provider.provider,
      error_code: "pdf_shape_guard_violation",
      error_message: "Guard rail bloqueou OCR: PDF precisa ser enviado como document_url."
    };
  }

  let resp;
  try {
    resp = await fetchImpl(provider.endpoint, {
      method: "POST",
      headers: {
        Authorization: `Bearer ${provider.apiKey}`,
        "Content-Type": "application/json"
      },
      body: JSON.stringify(requestPayload)
    });
  } catch (err) {
    return {
      ok: false,
      provider: provider.provider,
      error_code: "network_error",
      error_message: err?.message || "Erro de rede na chamada Mistral OCR."
    };
  }

  let payload = null;
  let responseText = "";
  let responseReadError = null;
  const responseContentType = String(resp?.headers?.get?.("content-type") || "").toLowerCase() || null;
  try {
    responseText = await resp.text();
  } catch (err) {
    responseText = "";
    responseReadError = err?.message || "response_read_error";
  }
  if (responseText) {
    try {
      payload = JSON.parse(responseText);
    } catch {
      payload = null;
    }
  } else {
    payload = null;
  }

  if (!resp?.ok) {
    const normalizedErrorCodeCandidate = `remote_http_${resp?.status || "unknown"}`;
    const remoteErrorJsonKeys =
      payload && typeof payload === "object"
        ? Object.keys(payload).slice(0, 30)
        : [];
    const remoteErrorPreview = buildSafeMistralDebugPreview(
      payload && typeof payload === "object" ? payload : responseText,
      400
    );
    const normalizedErrorMessage =
      payload?.error?.message ||
      payload?.message ||
      remoteErrorPreview ||
      "Falha remota na extraûÏûÈo documental.";
    try {
      await telemetry(env, {
        wa_id: waId,
        event: "envio_docs_mistral_response_debug",
        stage: "envio_docs",
        severity: "info",
        force: true,
        message: "DEBUG resposta OCR Mistral",
        details: {
          wa_id: waId,
          mistral_endpoint: provider.endpoint || null,
          mistral_model: provider.model || null,
          http_status: resp?.status || null,
          http_ok: resp?.ok === true,
          mime_type: mimeType,
          file_name: fileName,
          remote_error_preview: remoteErrorPreview || null,
          remote_error_json_keys: remoteErrorJsonKeys,
          response_content_type: responseContentType,
          response_read_error: responseReadError,
          normalized_error_code_candidate: normalizedErrorCodeCandidate
        }
      });
    } catch {}
    try {
      await telemetry(env, {
        wa_id: waId,
        event: "envio_docs_mistral_failure_normalized",
        stage: "envio_docs",
        severity: "info",
        force: true,
        message: "DEBUG falha OCR Mistral normalizada",
        details: {
          wa_id: waId,
          file_name: fileName,
          mime_type: mimeType,
          build_stamp: buildStamp,
          runtime_guard_version: runtimeGuardVersion,
          payload_shape_guard: payloadShapeGuard,
          document_type_final: documentTypeFinal,
          document_object_keys: documentObjectKeys,
          http_status: resp?.status || null,
          normalized_error_code: normalizedErrorCodeCandidate,
          normalized_error_message: normalizedErrorMessage,
          extraction_ok: false,
          extraction_source: "mistral",
          remote_error_preview: remoteErrorPreview || null,
          mistral_endpoint: provider.endpoint || null,
          mistral_model: provider.model || null
        }
      });
    } catch {}
    return {
      ok: false,
      provider: provider.provider,
      status: resp?.status || null,
      error_code: normalizedErrorCodeCandidate,
      error_message: normalizedErrorMessage
    };
  }

  const parsed = extractMistralTextAndMetadata(payload || {});
  return {
    ok: true,
    provider: provider.provider,
    model: provider.model,
    text: parsed.text,
    page_count: parsed.pageCount,
    confidence_base: parsed.confidenceBase,
    raw: payload
  };
}

function inferEnvioDocsSignalsFromExtractedText(text, context = {}) {
  const normalized = normalizeText(text || "");
  if (!normalized) {
    return {
      doc_type_hints: [],
      participant_hints: [],
      has_cpf_pattern: false,
      has_rnm_pattern: false,
      keyword_density: 0,
      context: {
        file_name: context?.fileName || null,
        mime_type: context?.mimeType || null
      }
    };
  }

  const fileNameNormalized = normalizeText(context?.fileName || "");
  const combined = `${normalized} ${fileNameNormalized}`.trim();

  const docTypeHints = [];
  const addHint = (cond, hint) => {
    if (cond && !docTypeHints.includes(hint)) docTypeHints.push(hint);
  };

  const participantHints = [];
  const addParticipantHint = (cond, hint) => {
    if (cond && !participantHints.includes(hint)) participantHints.push(hint);
  };

  const hasCpfPattern = /\b\d{3}\.?\d{3}\.?\d{3}-?\d{2}\b/.test(combined);
  const hasRnmPattern = /\b(rnm|registro nacional migratorio)\b/.test(combined);

  const hasCpfStrongContext =
    /\b(cadastro de pessoa fisica|cadastro pessoa fisica|comprovante de inscricao no cpf|comprovante de situacao cadastral|receita federal)\b/.test(combined);

  const hasRgStrongContext =
    /\b(rg|registro geral|carteira de identidade|documento de identidade|identidade civil|instituto de identificacao|secretaria de seguranca)\b/.test(combined);

  const hasCnhStrongContext =
    /\b(cnh|cnh digital|cnh-e|carteira nacional de habilitacao|carteira nacional de habilitaûÏûÈo|carteira digital de transito|carteira digital de trûÂnsito|renach)\b/.test(combined);

  const hasCtpsStrongContext =
    /\b(ctps|ctpsdigital|ctps digital|carteira de trabalho digital|carteira de trabalho e previdencia social|carteira de trabalho e previdûˆncia social)\b/.test(combined);

  const hasCtpsSupportiveContext =
    /\b(pis\/pasep|pis pasep|pis|pasep|data de admissao|data de admissûÈo|admissao|admissûÈo|contrato de trabalho|vinculo empregaticio|vûÙnculo empregatûÙcio)\b/.test(combined);

  const hasHoleriteContext =
    /\b(holerite|contracheque|demonstrativo de pagamento|demonstrativo de salario|demonstrativo de salûÀrio|folha de pagamento|salario liquido|salûÀrio lûÙquido|salario base|salûÀrio base|valor liquido|valor lûÙquido)\b/.test(combined);

  const hasBankStatementContext =
    /\b(extrato bancario|extrato bancûÀrio|movimentacao bancaria|movimentaûÏûÈo bancûÀria|saldo anterior|saldo atual|lancamentos|lanûÏamentos|debito|dûˋbito|credito|crûˋdito)\b/.test(combined);

  const hasRetirementStatementContext =
    /\b(extrato de aposentadoria|beneficio do inss|benefûÙcio do inss|meu inss|historico de credito|histû°rico de crûˋdito|competencia|competûˆncia)\b/.test(combined);

  const hasIrDeclarationContext =
    /\b(declaracao de imposto de renda|declaraûÏûÈo de imposto de renda|imposto de renda pessoa fisica|imposto de renda pessoa fûÙsica|dirpf|bens e direitos|rendimentos tributaveis|rendimentos tributûÀveis)\b/.test(combined);

  const hasIrReceiptContext =
    /\b(recibo de entrega|numero do recibo|nû¤mero do recibo|recibo irpf|recibo dirpf)\b/.test(combined);

  const hasResidenceUtilityContext =
    /\b(conta de luz|energia eletrica|energia elûˋtrica|equatorial|copel|cemig|enel|neoenergia|cpfl|light|edp|conta de agua|conta de ûÀgua|sanepar|sabesp|iguûÀ|igua|conta de gas|conta de gûÀs|naturgy|oi|vivo|tim|claro|conta de telefone|conta de celular|comprovante de residencia|comprovante de residûˆncia|fatura|boleto|cep|logradouro|endereco|endereûÏo|bairro|cidade|numero da instalacao|nû¤mero da instalaûÏûÈo|unidade consumidora)\b/.test(combined);

  const hasBoletoResidenceContext =
    /\b(vencimento|codigo de barras|cû°digo de barras|pagavel preferencialmente|pagûÀvel preferencialmente)\b/.test(combined) &&
    /\b(cep|logradouro|endereco|endereûÏo|bairro|cidade)\b/.test(combined);

  const keywordDensity =
    [
      hasCpfStrongContext,
      hasRgStrongContext,
      hasCnhStrongContext,
      hasCtpsStrongContext || hasCtpsSupportiveContext,
      hasHoleriteContext,
      hasBankStatementContext,
      hasRetirementStatementContext,
      hasIrDeclarationContext,
      hasIrReceiptContext,
      hasResidenceUtilityContext || hasBoletoResidenceContext,
      hasCpfPattern,
      hasRnmPattern
    ].filter(Boolean).length;

  addHint(hasCpfStrongContext, "cpf");
  addHint(hasRgStrongContext, "rg");
  addHint(hasCnhStrongContext, "cnh");

  // CNH pode continuar carregando sinais de RG e CPF sem perder o tipo principal CNH
  if (hasCnhStrongContext) {
    addHint(true, "rg");
    if (hasCpfPattern) addHint(true, "cpf");
  }

  addHint(hasCtpsStrongContext || (hasCtpsSupportiveContext && /\b(trabalho|emprego|empregaticio|empregatûÙcio|admissao|admissûÈo)\b/.test(combined)), "ctps_completa");
  addHint(hasHoleriteContext, "holerite");
  addHint(hasBankStatementContext, "extrato_bancario");
  addHint(hasRetirementStatementContext, "extrato_aposentadoria");
  addHint(hasIrDeclarationContext, "declaracao_ir");
  addHint(hasIrReceiptContext, "recibo_ir");
  addHint(hasResidenceUtilityContext || hasBoletoResidenceContext, "comprovante_residencia");

  if (!hasCpfStrongContext && hasCpfPattern && !hasResidenceUtilityContext && !hasCnhStrongContext && !hasCtpsStrongContext) {
    addHint(true, "cpf");
  }

  // NûÈo gerar P3 por filiaûÏûÈo solta em documento
  // P3 sû° deve nascer no fluxo do processo, nunca por "pai", "mûÈe" ou "filiaûÏûÈo" lidos no OCR
  addParticipantHint(/\b(titular)\b/.test(combined), "titular");
  addParticipantHint(/\b(conjuge|cûÇnjuge|esposo|esposa|marido|mulher)\b/.test(combined), "parceiro");

  return {
    doc_type_hints: docTypeHints,
    participant_hints: participantHints,
    has_cpf_pattern: hasCpfPattern,
    has_rnm_pattern: hasRnmPattern,
    keyword_density: keywordDensity,
    context: {
      file_name: context?.fileName || null,
      mime_type: context?.mimeType || null
    }
  };
}

function normalizeEnvioDocsDetectedDocType(tipo) {
  const t = String(tipo || "").trim().toLowerCase();
  if (!t) return "nao_identificado";
  if (t === "ctps") return "ctps_completa";
  if (["rg", "rg_com_cpf", "cpf", "cnh", "ctps_completa", "comprovante_residencia", "holerite", "extrato_bancario", "declaracao_ir", "recibo_ir"].includes(t)) {
    return t;
  }
  return "nao_identificado";
}

function scoreEnvioDocsDocumentClassification({ textScores = {}, signalScores = {}, supportScores = {} } = {}) {
  const candidates = ["rg", "rg_com_cpf", "cpf", "cnh", "ctps_completa", "comprovante_residencia", "holerite", "extrato_bancario", "declaracao_ir", "recibo_ir"];
  const totals = {};
  for (const tipo of candidates) {
    const textWeight = 0.65;
    const signalWeight = 0.25;
    const supportWeight = 0.10;
    const textScore = Number(textScores?.[tipo] || 0);
    const signalScore = Number(signalScores?.[tipo] || 0);
    const supportScore = Number(supportScores?.[tipo] || 0);
    totals[tipo] = (textScore * textWeight) + (signalScore * signalWeight) + (supportScore * supportWeight);
  }
  const ordered = Object.entries(totals).sort((a, b) => b[1] - a[1]);
  const best = ordered[0] || ["nao_identificado", 0];
  const second = ordered[1] || ["nao_identificado", 0];
  const topType = normalizeEnvioDocsDetectedDocType(best[0]);
  const topScore = Number(best[1] || 0);
  const secondType = normalizeEnvioDocsDetectedDocType(second[0]);
  const secondScore = Number(second[1] || 0);
  const hasRelevantConflictBase =
    topType !== "nao_identificado" &&
    secondType !== "nao_identificado" &&
    secondScore >= 0.40 &&
    Math.abs(topScore - secondScore) <= 0.12;
  const conflictOnlyWithinRendaResidencia =
    ENVIO_DOCS_TIPOS_ALVO_RENDA_RESIDENCIA.includes(topType) &&
    ENVIO_DOCS_TIPOS_ALVO_RENDA_RESIDENCIA.includes(secondType);
  // Em renda/residûˆncia, tratamos conflito como "forte" apenas quando o segundo candidato
  // permanece muito alto (>= 0.55), para evitar desbloqueio indevido em ambiguidade real.
  const STRONG_TARGET_CONFLICT_MIN_SECOND_SCORE = 0.55;
  const hasStrongTargetConflict =
    conflictOnlyWithinRendaResidencia &&
    secondScore >= STRONG_TARGET_CONFLICT_MIN_SECOND_SCORE;
  const hasRelevantConflict =
    hasRelevantConflictBase &&
    (!conflictOnlyWithinRendaResidencia || hasStrongTargetConflict);
  return {
    topType,
    topScore,
    secondType,
    secondScore,
    hasRelevantConflict,
    hasRelevantConflictBase,
    conflictOnlyWithinRendaResidencia,
    hasStrongTargetConflict,
    totals
  };
}

function buildEnvioDocsDocumentClassificationResult(input = {}) {
  const detectedDocType = normalizeEnvioDocsDetectedDocType(input.detected_doc_type);
  const category = detectedDocType === "nao_identificado" ? null : (envioDocsCategoriaFromTipo(detectedDocType) || null);
  const confidence = Number(input.classification_confidence || 0);
  return {
    detected_doc_type: detectedDocType,
    detected_doc_category: category,
    classification_confidence: Number.isFinite(confidence) ? Math.max(0, Math.min(1, confidence)) : 0,
    classification_reason: String(input.classification_reason || "Documento sem sinais suficientes para classificaûÏûÈo segura."),
    detected_signals_json: input.detected_signals_json && typeof input.detected_signals_json === "object" ? input.detected_signals_json : {},
    classifier_version: "envio_docs_classifier_v1",
    classification_ok: input.classification_ok === true,
    classification_error_code: input.classification_error_code || null,
    classification_error_message: input.classification_error_message || null
  };
}

function normalizeEnvioDocsDetectedParticipant(participante) {
  const p = String(participante || "").trim().toLowerCase();
  if (p === "p1" || p === "p2" || p === "p3") return p;
  return "desconhecido";
}

function scoreEnvioDocsParticipantInference({ documentClassification, documentAiSignals, st = {}, opts = {} } = {}) {
  const MIN_CONFLICT_SCORE_THRESHOLD = 0.45;
  const MAX_SCORE_DIFFERENCE_FOR_CONFLICT = 0.15;
  const MIN_CONFIDENCE_THRESHOLD = 0.6;
  const MAX_CONFIDENCE_FOR_UNKNOWN = 0.5;
  const participants = ["p1", "p2", "p3"];
  const score = { p1: 0, p2: 0, p3: 0 };
  const reasons = { p1: [], p2: [], p3: [] };
  const basis = { p1: [], p2: [], p3: [] };

  const addEvidence = (participant, value, reason, basisCode) => {
    const p = normalizeEnvioDocsDetectedParticipant(participant);
    if (p === "desconhecido") return;
    score[p] += Number(value) || 0;
    if (reason) reasons[p].push(reason);
    if (basisCode) basis[p].push(basisCode);
  };

  const text = normalizeText(
    documentAiSignals?.extracted_text_full ||
    documentAiSignals?.extracted_text_preview ||
    ""
  );
  const signalsJson = documentAiSignals?.signals_json && typeof documentAiSignals.signals_json === "object"
    ? documentAiSignals.signals_json
    : {};
  const supportText = normalizeText(`${opts?.hintText || ""} ${opts?.caption || ""} ${opts?.fileName || ""}`);
  const inferredFromSupport = inferEnvioDocsParticipanteFromText(supportText);
  if (inferredFromSupport) {
    addEvidence(inferredFromSupport, 0.55, "Pista explûÙcita de participante no contexto do envio.", "context_participant_hint");
  }

  const signalParticipantHints = Array.isArray(signalsJson?.participant_hints)
    ? signalsJson.participant_hints
    : [];
  for (const hint of signalParticipantHints) {
    addEvidence(hint, 0.45, "Sinal estruturado de participante detectado no documento.", "ocr_participant_hint");
  }

  const normalizePersonName = (raw) => normalizeText(raw || "").replace(/[^a-z0-9\s]/g, " ").replace(/\s+/g, " ").trim();
  const toTokenSet = (raw) => new Set(normalizePersonName(raw).split(" ").filter((t) => t.length >= 3));
  const hasStrongNameMatch = (docName, candidateName) => {
    const docTokens = toTokenSet(docName);
    const candidateTokens = toTokenSet(candidateName);
    if (!docTokens.size || !candidateTokens.size) return false;
    let overlap = 0;
    for (const token of docTokens) {
      if (candidateTokens.has(token)) overlap += 1;
    }
    return overlap >= 2 || (docTokens.size === 1 && overlap === 1);
  };

  const stateParticipantNames = {
    p1: [st?.nome, st?.nome_normalizado],
    p2: [st?.nome_parceiro, st?.nome_parceiro_normalizado, st?.nome_parceiro_familiar],
    p3: [st?.nome_familiar, st?.nome_p3, st?.nome_parceiro_familiar_p3]
  };
  const signalNames = []
    .concat(Array.isArray(signalsJson?.names) ? signalsJson.names : [])
    .concat(Array.isArray(signalsJson?.extracted_names) ? signalsJson.extracted_names : []);

  const namesFromText = [];
  const nomeCampoRegex = /\b(nome|titular|cliente|beneficiario)\s*[:\-]\s*([a-zû -û¢][a-zû -û¢\s]{4,80})/gi;
  let nomeMatch;
  while ((nomeMatch = nomeCampoRegex.exec(text)) !== null) {
    namesFromText.push(nomeMatch[2]);
  }
  const candidateNames = [...new Set([...signalNames, ...namesFromText].map((n) => String(n || "").trim()).filter(Boolean))];

  for (const candidateName of candidateNames) {
    for (const participant of participants) {
      const names = stateParticipantNames[participant].filter(Boolean);
      if (!names.length) continue;
      if (names.some((stateName) => hasStrongNameMatch(candidateName, stateName))) {
        addEvidence(participant, 0.9, `Nome documental compatûÙvel com ${participant}.`, "name_match_strong");
      }
    }
  }

  const normalizeDigits = (v) => String(v || "").replace(/\D+/g, "");
  const cpfRegex = /\b\d{3}\.?\d{3}\.?\d{3}-?\d{2}\b/g;
  const extractedCpfs = new Set();
  let cpfMatch;
  while ((cpfMatch = cpfRegex.exec(text)) !== null) {
    const digits = normalizeDigits(cpfMatch[0]);
    if (digits.length === 11) extractedCpfs.add(digits);
  }
  const signalCpfs = Array.isArray(signalsJson?.cpfs) ? signalsJson.cpfs : [];
  for (const cpf of signalCpfs) {
    const digits = normalizeDigits(cpf);
    if (digits.length === 11) extractedCpfs.add(digits);
  }

  const stateIds = {
    p1: [st?.cpf, st?.cpf_titular, st?.cpf_p1, st?.documento_cpf_p1],
    p2: [st?.cpf_parceiro, st?.cpf_p2, st?.documento_cpf_p2],
    p3: [st?.cpf_p3, st?.cpf_familiar, st?.documento_cpf_p3]
  };
  for (const participant of participants) {
    const cpfs = new Set(stateIds[participant].map(normalizeDigits).filter((v) => v.length === 11));
    for (const cpf of extractedCpfs) {
      if (cpfs.has(cpf)) {
        addEvidence(participant, 1.0, `CPF documental compatûÙvel com ${participant}.`, "cpf_match_strong");
      }
    }
  }

  const detectedDocType = normalizeEnvioDocsDetectedDocType(documentClassification?.detected_doc_type);
  const coveredTypes = getEnvioDocsCoveredChecklistTypes(detectedDocType);
  const pendingItems = Array.isArray(st?.envio_docs_itens_json)
    ? st.envio_docs_itens_json.filter((item) => isEnvioDocsBlockingItem(item) && !isEnvioDocsItemReceived(item))
    : [];
  if (coveredTypes.length && pendingItems.length) {
    const compatibleByParticipant = {
      p1: 0,
      p2: 0,
      p3: 0
    };
    for (const item of pendingItems) {
      if (!participants.includes(item?.participante)) continue;
      if (coveredTypes.some((tipo) => envioDocsHintTipoMatchesItemTipo(tipo, item?.tipo))) {
        compatibleByParticipant[item.participante] += 1;
      }
    }
    for (const participant of participants) {
      if (compatibleByParticipant[participant] > 0) {
        addEvidence(participant, 0.25, "Checklist pendente compatûÙvel com o tipo documental detectado.", "checklist_support");
      }
    }
  }

  const top = participants
    .map((participant) => ({
      participant,
      score: Math.max(0, Math.min(1, Number(score[participant] || 0))),
      reasons: reasons[participant],
      basis: [...new Set(basis[participant])]
    }))
    .sort((a, b) => b.score - a.score);

  const best = top[0];
  const second = top[1];
  const hasConflict =
    best &&
    second &&
    best.score >= MIN_CONFLICT_SCORE_THRESHOLD &&
    second.score >= MIN_CONFLICT_SCORE_THRESHOLD &&
    Math.abs(best.score - second.score) <= MAX_SCORE_DIFFERENCE_FOR_CONFLICT;
  const hasConfidence = best && best.score >= MIN_CONFIDENCE_THRESHOLD;
  const detectedParticipant = hasConflict || !hasConfidence
    ? "desconhecido"
    : normalizeEnvioDocsDetectedParticipant(best.participant);

  return {
    detectedParticipant,
    confidence: detectedParticipant === "desconhecido" ? Math.min(best?.score || 0, MAX_CONFIDENCE_FOR_UNKNOWN) : (best?.score || 0),
    matchBasis: detectedParticipant === "desconhecido"
      ? hasConflict
        ? "ambiguous_conflict"
        : "insufficient_evidence"
      : (best?.basis?.[0] || "heuristic_combined"),
    reason: detectedParticipant === "desconhecido"
      ? hasConflict
        ? "Conflito relevante de evidûˆncias entre participantes; inferûˆncia conservadora aplicada."
        : "Sinais insuficientes para inferûˆncia segura de participante."
      : (best?.reasons?.[0] || "Inferûˆncia por combinaûÏûÈo conservadora de sinais documentais."),
    signalsJson: {
      scoring: top.map((item) => ({
        participante: item.participant,
        score: item.score,
        basis: item.basis
      })),
      extracted_names: candidateNames,
      extracted_cpfs: [...extractedCpfs],
      covered_checklist_types: coveredTypes
    },
    ok: detectedParticipant !== "desconhecido",
    errorCode: detectedParticipant === "desconhecido"
      ? hasConflict
        ? "participant_ambiguous_conflict"
        : "participant_insufficient_evidence"
      : null,
    errorMessage: detectedParticipant === "desconhecido"
      ? hasConflict
        ? "HûÀ ambiguidade relevante entre participantes possûÙveis."
        : "Sem prova suficiente para inferir participante com seguranûÏa."
      : null
  };
}

function buildEnvioDocsParticipantInferenceResult(input = {}) {
  const confidence = Number(input.confidence || 0);
  return {
    detected_participant: normalizeEnvioDocsDetectedParticipant(input.detectedParticipant),
    participant_confidence: Number.isFinite(confidence) ? Math.max(0, Math.min(1, confidence)) : 0,
    participant_match_basis: String(input.matchBasis || "insufficient_evidence"),
    participant_reason: String(input.reason || "Sinais insuficientes para inferûˆncia segura de participante."),
    participant_signals_json: input.signalsJson && typeof input.signalsJson === "object" ? input.signalsJson : {},
    participant_inference_version: "envio_docs_participant_inference_v1",
    participant_inference_ok: input.ok === true,
    participant_inference_error_code: input.errorCode || null,
    participant_inference_error_message: input.errorMessage || null
  };
}

function inferEnvioDocsParticipantFromSignals(documentClassification, documentAiSignals, st = {}, opts = {}) {
  try {
    const scored = scoreEnvioDocsParticipantInference({
      documentClassification,
      documentAiSignals,
      st,
      opts
    });
    return buildEnvioDocsParticipantInferenceResult(scored);
  } catch (err) {
    return buildEnvioDocsParticipantInferenceResult({
      detectedParticipant: "desconhecido",
      confidence: 0,
      matchBasis: "inference_runtime_error",
      reason: "Falha interna ao inferir participante de documento.",
      signalsJson: {},
      ok: false,
      errorCode: "participant_inference_runtime_error",
      errorMessage: err?.message || "Erro interno na inferûˆncia de participante."
    });
  }
}

function scoreEnvioDocsChecklistMatch({ item, detectedDocType, detectedDocCategory, detectedParticipant, participantConfidence }) {
  const tipoItem = String(item?.tipo || "").trim().toLowerCase();
  const participanteItem = String(item?.participante || "").trim().toLowerCase();
  const docType = String(detectedDocType || "").trim().toLowerCase();
  const docCategory = String(detectedDocCategory || "").trim().toLowerCase();
  const participant = normalizeEnvioDocsDetectedParticipant(detectedParticipant);
  const participantConf = Number(participantConfidence || 0);

  const typeStrongMatch = envioDocsHintTipoMatchesItemTipo(docType, tipoItem);
  const categoryMatch = docCategory && envioDocsCategoriaFromTipo(tipoItem) === docCategory;
  const participantMatch = participant && participant !== "desconhecido"
    ? participanteItem === participant
    : null;
  const participantStrong = participantMatch !== null && participantConf >= 0.75;

  let score = 0;
  if (typeStrongMatch) score += 0.8;
  if (categoryMatch) score += 0.1;
  if (participantStrong && participantMatch) score += 0.1;
  if (participantStrong && !participantMatch) score -= 0.3;

  return {
    item,
    typeStrongMatch,
    categoryMatch,
    participantMatch,
    participantStrong,
    score: Math.max(0, Math.min(1, score))
  };
}

function normalizeEnvioDocsChecklistMatchResult(input = {}) {
  const status = ["matched_safe", "ambiguous", "no_match"].includes(input.match_status)
    ? input.match_status
    : "no_match";
  const confidence = Number(input.match_confidence || 0);
  const matchedItems = Array.isArray(input.matched_items) ? input.matched_items : [];
  return {
    matched_items: matchedItems,
    matched_item_ids: matchedItems.map((item) => `${item?.tipo || ""}:${item?.participante || ""}`),
    match_confidence: Number.isFinite(confidence) ? Math.max(0, Math.min(1, confidence)) : 0,
    match_status: status,
    match_reason: String(input.match_reason || ""),
    match_signals_json: input.match_signals_json && typeof input.match_signals_json === "object" ? input.match_signals_json : {},
    checklist_match_version: "envio_docs_checklist_match_v1",
    checklist_match_ok: input.checklist_match_ok === true,
    checklist_match_error_code: input.checklist_match_error_code || null,
    checklist_match_error_message: input.checklist_match_error_message || null
  };
}

function buildEnvioDocsChecklistMatchResult(input = {}) {
  return normalizeEnvioDocsChecklistMatchResult(input);
}

function matchEnvioDocsClassificationToChecklist(documentClassification, participantInference, st = {}, opts = {}) {
  try {
    const detectedDocType = String(documentClassification?.detected_doc_type || "").trim().toLowerCase();
    const detectedDocCategory = String(documentClassification?.detected_doc_category || "").trim().toLowerCase();
    const detectedParticipant = normalizeEnvioDocsDetectedParticipant(participantInference?.detected_participant);
    const participantConfidence = Number(participantInference?.participant_confidence || 0);
    const itens = Array.isArray(st?.envio_docs_itens_json) ? st.envio_docs_itens_json : [];
    const pendentes = itens.filter((item) => isEnvioDocsConversationalPendingItem(item));
    const coveredTypes = getEnvioDocsCoveredChecklistTypes(detectedDocType);
    const participantStrong = detectedParticipant && detectedParticipant !== "desconhecido" && participantConfidence >= 0.75;
    const participantSoft =
      detectedParticipant &&
      detectedParticipant !== "desconhecido" &&
      participantConfidence >= 0.6;
    const allowsSoftParticipantScope =
      ["comprovante_residencia", "holerite", "extrato_bancario", "declaracao_ir", "recibo_ir"].includes(detectedDocType);

    if (!detectedDocType || detectedDocType === "nao_identificado") {
      return buildEnvioDocsChecklistMatchResult({
        matched_items: [],
        match_confidence: 0,
        match_status: "no_match",
        match_reason: "document_type_not_identified",
        match_signals_json: {
          detected_doc_type: detectedDocType || null,
          detected_doc_category: detectedDocCategory || null,
          detected_participant: detectedParticipant || "desconhecido",
          participant_confidence: participantConfidence,
          covered_types: coveredTypes,
          pending_items: pendentes.map((item) => ({ tipo: item?.tipo || null, participante: item?.participante || null }))
        },
        checklist_match_ok: true
      });
    }

    const scored = pendentes.map((item) => scoreEnvioDocsChecklistMatch({
      item,
      detectedDocType,
      detectedDocCategory,
      detectedParticipant,
      participantConfidence
    }));

    const strongTypeCandidates = scored.filter((entry) => entry.typeStrongMatch);
    const participantScoped = participantStrong
      ? strongTypeCandidates.filter((entry) => entry.participantMatch === true)
      : (
          allowsSoftParticipantScope && participantSoft
            ? strongTypeCandidates.filter((entry) => entry.participantMatch === true)
            : strongTypeCandidates
        );
    const candidates = participantScoped.filter((entry) => entry.score >= 0.75);

    if (!candidates.length) {
      const canUseDossierSingleCoverageFallback =
        ENVIO_DOCS_TIPOS_ALVO_RENDA_RESIDENCIA.includes(detectedDocType) &&
        strongTypeCandidates.length === 1;
      if (canUseDossierSingleCoverageFallback) {
        const selected = strongTypeCandidates[0];
        const DOSSIER_SINGLE_COVERAGE_CONFIDENCE_CAP = 0.92;
        const DOSSIER_SINGLE_COVERAGE_CLASSIFICATION_FLOOR = 0.7;
        return buildEnvioDocsChecklistMatchResult({
          matched_items: [{ tipo: selected.item?.tipo || null, participante: selected.item?.participante || null }],
          match_confidence: Math.max(
            0.75,
            // Cap/floor conservadores para fallback por cobertura û¤nica do dossiûˆ:
            // mantûˋm confianûÏa alta o suficiente para vûÙnculo seguro, sem equiparar a um match textual pleno.
            Math.min(
              DOSSIER_SINGLE_COVERAGE_CONFIDENCE_CAP,
              Number(selected.score || 0) * Math.max(
                DOSSIER_SINGLE_COVERAGE_CLASSIFICATION_FLOOR,
                Number(documentClassification?.classification_confidence || 0)
              )
            )
          ),
          match_status: "matched_safe",
          match_reason: "single_pending_item_resolved_by_dossier_coverage",
          match_signals_json: {
            detected_doc_type: detectedDocType,
            detected_doc_category: detectedDocCategory || null,
            detected_participant: detectedParticipant || "desconhecido",
            participant_confidence: participantConfidence,
            participant_strong: participantStrong,
            covered_types: coveredTypes
          },
          checklist_match_ok: true
        });
      }
    }

    if (!candidates.length) {
      return buildEnvioDocsChecklistMatchResult({
        matched_items: [],
        match_confidence: 0,
        match_status: "no_match",
        match_reason: participantStrong
          ? "no_pending_item_for_doc_type_and_participant"
          : "no_pending_item_for_doc_type",
        match_signals_json: {
          detected_doc_type: detectedDocType,
          detected_doc_category: detectedDocCategory || null,
          detected_participant: detectedParticipant || "desconhecido",
          participant_confidence: participantConfidence,
          participant_strong: participantStrong,
          covered_types: coveredTypes,
          candidates_scored: scored.map((entry) => ({
            tipo: entry.item?.tipo || null,
            participante: entry.item?.participante || null,
            type_strong_match: entry.typeStrongMatch,
            category_match: entry.categoryMatch,
            participant_match: entry.participantMatch,
            score: entry.score
          }))
        },
        checklist_match_ok: true
      });
    }

    if (candidates.length > 1) {
      const candidatesParticipants = new Set(
        candidates.map((entry) => normalizeEnvioDocsDetectedParticipant(entry?.item?.participante))
      );
      const candidatesShareSingleKnownParticipant =
        candidatesParticipants.size === 1 && !candidatesParticipants.has("desconhecido");
      const normalizedCandidateTypes = new Set(
        candidates.map((entry) => normalizeEnvioDocsTipoForChecklist(entry?.item?.tipo))
      );
      const IDENTITY_CPF_PAIR_TYPES = ["rg", "cpf", "identidade_cpf"];
      const resolvesIdentityCpfPair =
        (detectedDocType === "rg_com_cpf" || detectedDocType === "cnh") &&
        coveredTypes.includes("rg") &&
        coveredTypes.includes("cpf") &&
        candidatesShareSingleKnownParticipant &&
        [...normalizedCandidateTypes].every((tipo) => IDENTITY_CPF_PAIR_TYPES.includes(tipo)) &&
        normalizedCandidateTypes.size <= 2;
      if (resolvesIdentityCpfPair) {
        const matchedItems = normalizeEnvioDocsMatchedItems(
          candidates.map((entry) => ({ tipo: entry.item?.tipo || null, participante: entry.item?.participante || null }))
        );
        const topScore = Math.max(...candidates.map((entry) => Number(entry.score || 0)));
        return buildEnvioDocsChecklistMatchResult({
          matched_items: matchedItems,
          match_confidence: Math.max(
            0.8,
            Math.min(
              0.95,
              topScore * Math.max(0.7, Number(documentClassification?.classification_confidence || 0))
            )
          ),
          match_status: "matched_safe",
          match_reason: "rg_com_cpf_resolves_identity_and_cpf_same_participant",
          match_signals_json: {
            detected_doc_type: detectedDocType,
            detected_doc_category: detectedDocCategory || null,
            detected_participant: detectedParticipant || "desconhecido",
            participant_confidence: participantConfidence,
            participant_strong: participantStrong,
            covered_types: coveredTypes,
            resolved_identity_cpf_pair: {
              participant: [...candidatesParticipants][0],
              candidate_types: [...normalizedCandidateTypes],
              candidate_count: candidates.length
            }
          },
          checklist_match_ok: true
        });
      }
      const canResolveIdentityByCurrentParticipantBlock =
        ["cnh", "rg", "cpf", "rg_com_cpf"].includes(detectedDocType) &&
        coveredTypes.some((tipo) => tipo === "rg" || tipo === "cpf") &&
        [...normalizedCandidateTypes].every((tipo) => IDENTITY_CPF_PAIR_TYPES.includes(tipo));
      if (canResolveIdentityByCurrentParticipantBlock) {
        const participanteAtualBloco = resolveEnvioDocsCurrentParticipant(itens);
        const hasSafeCurrentParticipantContext = ENVIO_DOCS_ORDEM_PARTICIPANTES.includes(participanteAtualBloco);
        if (hasSafeCurrentParticipantContext) {
          const scopedByCurrentParticipant = candidates.filter(
            (entry) => normalizeEnvioDocsDetectedParticipant(entry?.item?.participante) === participanteAtualBloco
          );
          if (scopedByCurrentParticipant.length >= 1) {
            const matchedItems = normalizeEnvioDocsMatchedItems(
              scopedByCurrentParticipant.map((entry) => ({
                tipo: entry.item?.tipo || null,
                participante: entry.item?.participante || null
              }))
            );
            const topScore = Math.max(...scopedByCurrentParticipant.map((entry) => Number(entry.score || 0)));
            return buildEnvioDocsChecklistMatchResult({
              matched_items: matchedItems,
              match_confidence: Math.max(
                0.8,
                Math.min(
                  0.95,
                  topScore * Math.max(0.7, Number(documentClassification?.classification_confidence || 0))
                )
              ),
              match_status: "matched_safe",
              match_reason: "identity_resolved_by_current_envio_docs_participant",
              match_signals_json: {
                detected_doc_type: detectedDocType,
                detected_doc_category: detectedDocCategory || null,
                detected_participant: detectedParticipant || "desconhecido",
                participant_confidence: participantConfidence,
                participant_strong: participantStrong,
                covered_types: coveredTypes,
                current_participant_tiebreak: {
                  participante_atual: participanteAtualBloco,
                  candidate_count: candidates.length,
                  selected_count: scopedByCurrentParticipant.length
                }
              },
              checklist_match_ok: true
            });
          }
        }
      }
      const participanteAtualBloco = resolveEnvioDocsCurrentParticipant(itens);
      const hasSafeCurrentParticipantContext = ENVIO_DOCS_ORDEM_PARTICIPANTES.includes(participanteAtualBloco);
      if (hasSafeCurrentParticipantContext) {
        const scopedByCurrentParticipant = candidates.filter(
          (entry) => normalizeEnvioDocsDetectedParticipant(entry?.item?.participante) === participanteAtualBloco
        );
        if (scopedByCurrentParticipant.length >= 1) {
          const matchedItems = normalizeEnvioDocsMatchedItems(
            scopedByCurrentParticipant.map((entry) => ({
              tipo: entry.item?.tipo || null,
              participante: entry.item?.participante || null
            }))
          );
          const topScore = Math.max(...scopedByCurrentParticipant.map((entry) => Number(entry.score || 0)));
          return buildEnvioDocsChecklistMatchResult({
            matched_items: matchedItems,
            match_confidence: Math.max(
              0.8,
              Math.min(
                0.95,
                topScore * Math.max(0.7, Number(documentClassification?.classification_confidence || 0))
              )
            ),
            match_status: "matched_safe",
            match_reason: "resolved_by_current_envio_docs_participant",
            match_signals_json: {
              detected_doc_type: detectedDocType,
              detected_doc_category: detectedDocCategory || null,
              detected_participant: detectedParticipant || "desconhecido",
              participant_confidence: participantConfidence,
              participant_strong: participantStrong,
              covered_types: coveredTypes,
              current_participant_tiebreak: {
                participante_atual: participanteAtualBloco,
                candidate_count: candidates.length,
                selected_count: scopedByCurrentParticipant.length
              }
            },
            checklist_match_ok: true
          });
        }
      }
      const allowsConservativeParticipantTieBreak =
        ["comprovante_residencia", "holerite", "extrato_bancario", "declaracao_ir", "recibo_ir"].includes(detectedDocType);
      if (allowsConservativeParticipantTieBreak) {
        const participantScoringRaw = Array.isArray(participantInference?.participant_signals_json?.scoring)
          ? participantInference.participant_signals_json.scoring
          : [];
        const participantScoring = participantScoringRaw
          .map((entry) => ({
            participante: normalizeEnvioDocsDetectedParticipant(entry?.participante),
            score: Number(entry?.score || 0)
          }))
          .filter((entry) => entry.participante !== "desconhecido" && Number.isFinite(entry.score))
          .sort((a, b) => b.score - a.score);
        const topParticipant = participantScoring[0] || null;
        const secondParticipantScore = Number(participantScoring[1]?.score || 0);
        const hasSafeParticipantTieBreakSignal =
          topParticipant &&
          topParticipant.score >= 0.6 &&
          (topParticipant.score - secondParticipantScore) >= 0.2;

        if (hasSafeParticipantTieBreakSignal) {
          const participantScopedCandidates = candidates.filter(
            (entry) => normalizeEnvioDocsDetectedParticipant(entry?.item?.participante) === topParticipant.participante
          );
          if (participantScopedCandidates.length === 1) {
            const selected = participantScopedCandidates[0];
            return buildEnvioDocsChecklistMatchResult({
              matched_items: [{ tipo: selected.item?.tipo || null, participante: selected.item?.participante || null }],
              match_confidence: Math.max(
                0.75,
                Math.min(
                  0.95,
                  Number(selected.score || 0) *
                    Math.max(0.6, Number(documentClassification?.classification_confidence || 0)) *
                    Math.max(0.75, topParticipant.score)
                )
              ),
              match_status: "matched_safe",
              match_reason: "single_pending_item_resolved_by_participant_signal",
              match_signals_json: {
                detected_doc_type: detectedDocType,
                detected_doc_category: detectedDocCategory || null,
                detected_participant: detectedParticipant || "desconhecido",
                participant_confidence: participantConfidence,
                participant_strong: participantStrong,
                covered_types: coveredTypes,
                participant_tiebreak: {
                  participante: topParticipant.participante,
                  score: topParticipant.score,
                  second_score: secondParticipantScore
                }
              },
              checklist_match_ok: true
            });
          }
        }
      }
      const topScore = Math.max(...candidates.map((entry) => Number(entry.score || 0)));
      const matchedItems = candidates
        .map((entry) => ({ tipo: entry.item?.tipo || null, participante: entry.item?.participante || null }));
      return buildEnvioDocsChecklistMatchResult({
        matched_items: matchedItems,
        match_confidence: Math.min(0.69, topScore),
        match_status: "ambiguous",
        match_reason: participantStrong
          ? "multiple_pending_items_for_doc_type_and_participant"
          : "multiple_pending_items_for_doc_type",
        match_signals_json: {
          detected_doc_type: detectedDocType,
          detected_doc_category: detectedDocCategory || null,
          detected_participant: detectedParticipant || "desconhecido",
          participant_confidence: participantConfidence,
          participant_strong: participantStrong,
          covered_types: coveredTypes
        },
        checklist_match_ok: true
      });
    }

    const selected = candidates[0];
    return buildEnvioDocsChecklistMatchResult({
      matched_items: [{ tipo: selected.item?.tipo || null, participante: selected.item?.participante || null }],
      match_confidence: Math.max(
        0.75,
        Math.min(
          0.98,
          Number(selected.score || 0) *
            Math.max(0.6, Number(documentClassification?.classification_confidence || 0)) *
            (participantStrong ? Math.max(0.75, participantConfidence) : 1)
        )
      ),
      match_status: "matched_safe",
      match_reason: participantStrong
        ? "single_pending_item_strong_type_and_participant_match"
        : "single_pending_item_strong_type_match",
      match_signals_json: {
        detected_doc_type: detectedDocType,
        detected_doc_category: detectedDocCategory || null,
        detected_participant: detectedParticipant || "desconhecido",
        participant_confidence: participantConfidence,
        participant_strong: participantStrong,
        covered_types: coveredTypes
      },
      checklist_match_ok: true
    });
  } catch (err) {
    return buildEnvioDocsChecklistMatchResult({
      matched_items: [],
      match_confidence: 0,
      match_status: "no_match",
      match_reason: "checklist_match_runtime_error",
      match_signals_json: {},
      checklist_match_ok: false,
      checklist_match_error_code: "checklist_match_runtime_error",
      checklist_match_error_message: err?.message || "Erro interno no match seguro de checklist."
    });
  }
}

function classifyEnvioDocsDocument(signals, st = {}, opts = {}) {
  const SCORE_MAX = 1;
  const SCORE_STRONG_HINT = 0.85;
  const SCORE_SUPPORTIVE = 0.8;
  const SCORE_CPF_GENERIC = 0.45;
  const SCORE_CPF_DAMPENED = 0.2;
  const SCORE_CTPS_HINT_TEXT = 0.9;
  const extractedTextRaw = String(
    signals?.extracted_text_full ||
    signals?.extracted_text_preview ||
    ""
  );
  const extractedText = normalizeText(extractedTextRaw);
  const textHasContent = extractedText.length >= 20;
  const signalsJson = signals?.signals_json && typeof signals.signals_json === "object" ? signals.signals_json : {};
  const hintSupportText = normalizeText(
    `${opts?.hintText || ""} ${opts?.fileName || signals?.file_name || ""} ${opts?.caption || ""}`
  );
  const debugFileName = String(opts?.fileName || signals?.file_name || "").trim() || null;
  const mimeType = String(opts?.mimeType || signals?.mime_type || "").toLowerCase();

  if (!signals?.extraction_ok && !textHasContent) {
    return buildEnvioDocsDocumentClassificationResult({
      detected_doc_type: "nao_identificado",
      classification_confidence: 0,
      classification_reason: "ExtraûÏûÈo OCR indisponûÙvel; sem texto suficiente para classificar com seguranûÏa.",
      detected_signals_json: signalsJson,
      classification_ok: false,
      classification_error_code: "extraction_not_available",
      classification_error_message: signals?.extraction_error_message || "ExtraûÏûÈo documental nûÈo disponûÙvel."
    });
  }

  const hasCtpsStrongContext = /\b(ctps digital|ctpsdigital|carteira de trabalho digital|carteira de trabalho e previdencia social|ctps)\b/.test(extractedText);
  const hasCtpsSupportiveContext = /\b(carteira de trabalho|pis\/pasep|pis pasep)\b/.test(extractedText);
  const hasCpfTokenOrPattern = /\bcpf\b/.test(extractedText) || /\b\d{3}\.?\d{3}\.?\d{3}-?\d{2}\b/.test(extractedText);
  const hasGenericIdentityToken = /\bidentidade\b/.test(extractedText);
  const hasRgSpecificContext = /\b(rg|registro geral|secretaria de seguranca|carteira de identidade|carteira de identidade nacional|documento nacional de identificacao|cin|instituto de identificacao)\b/.test(extractedText);
  const hasCnhStrongContext = /\b(cnh|carteira nacional de habilitacao|permissao para dirigir|categoria [abcde])\b/.test(extractedText);
  const hasCnhDigitalContext = /\b(cnh digital|carteira digital de transito|documento digital de habilitacao|registro nacional de condutores habilitados|renach)\b/.test(extractedText);
  const hasResidenciaUtilityProviderContext = /\b(copel|enel|cemig|light|cpfl|neoenergia|eletropaulo|equatorial|celesc|sanepar|sabesp|caesb|oi|vivo|tim|claro)\b/.test(extractedText);
  const hasResidenciaUtilityBillingContext = /\b(tarifa|consumo|kwh|leitura|unidade consumidora|vencimento|valor a pagar|fatura|cobranca|mensalidade|referencia|referûˆncia)\b/.test(extractedText);
  const hasResidenciaAddressContext = /\b(cep|logradouro|endereco|bairro|cidade|uf)\b/.test(extractedText);
  const hasResidenciaUtilityStrongContext =
    hasResidenciaUtilityProviderContext &&
    (hasResidenciaUtilityBillingContext || hasResidenciaAddressContext);
  const hasResidenciaStrongContext =
    hasResidenciaUtilityStrongContext ||
    (hasResidenciaUtilityBillingContext && hasResidenciaAddressContext);
  const hasExtratoBancarioStrongContext =
    /\b(extrato bancario|agencia|conta corrente|saldo anterior|saldo atual|lancamentos)\b/.test(extractedText);
  const hasExtratoBancarioGenericContext =
    /\b(movimentacao|debito|credito|historico|beneficio inss|aposentadoria|previdencia social)\b/.test(extractedText);
  const hasCnhStrongHint = /\b(cnh[-\s]?e|cnh digital|carteira nacional de habilitacao|renach|carteira digital de transito)\b/.test(hintSupportText);
  const hasCtpsStrongHint = /\b(ctpsdigital|ctps digital|ctps|carteira de trabalho digital|carteira de trabalho e previdencia social|carteira de trabalho)\b/.test(hintSupportText);
  const hasCpfStrongContext = /\b(cadastro de pessoas fisicas|comprovante de situacao cadastral no cpf)\b/.test(extractedText);
  const hasStrongNonCpfDocumentContext =
    hasCtpsStrongContext ||
    hasCnhStrongContext ||
    hasCnhDigitalContext ||
    hasCnhStrongHint ||
    hasResidenciaStrongContext;
  const cpfTextScore =
    hasCpfStrongContext
      ? SCORE_MAX
      : (
          hasCpfTokenOrPattern
            ? (hasStrongNonCpfDocumentContext ? SCORE_CPF_DAMPENED : SCORE_CPF_GENERIC)
            : 0
        );
  const hasGenericIdentityWithoutSpecificDocContext =
    hasGenericIdentityToken &&
    !hasCtpsStrongContext &&
    !hasCnhStrongContext &&
    !hasCnhDigitalContext &&
    !hasCnhStrongHint;
  const cnhTextScore = (hasCnhStrongContext || hasCnhDigitalContext) ? SCORE_MAX : (hasCnhStrongHint ? SCORE_STRONG_HINT : 0);
  const hasHoleritePayrollColumns =
    /\b(proventos|descontos|total liquido|total lûÙquido|valor liquido|valor lûÙquido|liquido a receber|lûÙquido a receber|liquido a pagar|lûÙquido a pagar)\b/.test(extractedText);
  const hasHoleriteReceiptContext = /\b(recibo de pagamento(?: de salario| de salûÀrio)?)\b/.test(extractedText);
  const holeriteTextScore =
    /\b(holerite|contracheque|demonstrativo de pagamento|demonstrativo de salario|demonstrativo de salûÀrio|folha de pagamento|vencimentos|salario base|salûÀrio base|valor liquido|valor lûÙquido)\b/.test(extractedText) ||
    hasHoleritePayrollColumns ||
    hasHoleriteReceiptContext
      ? 1
      : 0;
  const holeriteContextDominant =
    holeriteTextScore >= SCORE_MAX &&
    (hasHoleritePayrollColumns || hasHoleriteReceiptContext);
  const ctpsTextScore =
    hasCtpsStrongContext
      ? (holeriteContextDominant ? SCORE_SUPPORTIVE : SCORE_MAX)
      : (hasCtpsStrongHint ? SCORE_CTPS_HINT_TEXT : (hasCtpsSupportiveContext ? SCORE_SUPPORTIVE : 0));

  const hasBoletoWithAddressContext =
    /\bboleto\b/.test(extractedText) &&
    /\b(nome|pagador|sacado)\b/.test(extractedText) &&
    /\b(endereco|logradouro|cep)\b/.test(extractedText);
  const UTILITY_CONTEXT_GENERIC_HINT_DAMPENED_SCORE = 0.2;

  const textScores = {
  cnh: cnhTextScore,

  rg: (
    /\b(rg|registro geral|secretaria de seguranca|carteira de identidade|instituto de identificacao)\b/.test(extractedText) &&
    !hasCpfTokenOrPattern
  ) ? 1 : 0,

  rg_com_cpf: (
    (
      hasRgSpecificContext ||
      hasGenericIdentityWithoutSpecificDocContext
    ) &&
    hasCpfTokenOrPattern
  ) ? 1 : 0,

  cpf: cpfTextScore,
  ctps_completa: ctpsTextScore,
  comprovante_residencia: (
    /\b(comprovante de residencia|conta de luz|conta de agua|conta de internet|fatura de energia|iptu|logradouro|cep|endereco)\b/.test(extractedText) ||
    hasResidenciaStrongContext ||
    hasBoletoWithAddressContext
  ) ? 1 : 0,
  holerite: holeriteTextScore,
  extrato_bancario:
    hasExtratoBancarioStrongContext
      ? 1
      : ((/\bextrato\b/.test(extractedText) && hasExtratoBancarioGenericContext) ? 0.75 : 0),
  declaracao_ir: /\b(declaracao de ajuste anual|declaracao de imposto de renda|imposto de renda da pessoa fisica|dirpf)\b/.test(extractedText) ? 1 : 0,
  recibo_ir: /\b(recibo de entrega|numero do recibo|codigo de controle|darf|documento de arrecadacao de receitas federais)\b/.test(extractedText) ? 1 : 0
};

  const hintToCanonical = {
    rg: "rg",
    cpf: "cpf",
    cnh: "cnh",
    ctps: "ctps_completa",
    comprovante_residencia: "comprovante_residencia",
    holerite: "holerite",
    extrato_bancario: "extrato_bancario",
    declaracao_ir: "declaracao_ir",
    recibo_ir: "recibo_ir"
  };
  const signalScores = {};
  for (const tipo of Object.values(hintToCanonical)) signalScores[tipo] = 0;
  const docTypeHints = Array.isArray(signalsJson?.doc_type_hints) ? signalsJson.doc_type_hints : [];
  for (const hint of docTypeHints) {
    const canonical = hintToCanonical[String(hint || "").trim().toLowerCase()] || null;
    if (!canonical) continue;
    signalScores[canonical] = Math.max(signalScores[canonical] || 0, 0.8);
  }
  if (signalsJson?.has_cpf_pattern) signalScores.cpf = Math.max(signalScores.cpf || 0, 0.65);
  if (hasCnhStrongContext || hasCnhDigitalContext || hasCnhStrongHint) {
    signalScores.rg = Math.min(signalScores.rg || 0, UTILITY_CONTEXT_GENERIC_HINT_DAMPENED_SCORE);
    signalScores.cpf = Math.min(signalScores.cpf || 0, UTILITY_CONTEXT_GENERIC_HINT_DAMPENED_SCORE);
  }
  if (hasResidenciaStrongContext) {
    signalScores.rg = Math.min(signalScores.rg || 0, UTILITY_CONTEXT_GENERIC_HINT_DAMPENED_SCORE);
    signalScores.cpf = Math.min(signalScores.cpf || 0, UTILITY_CONTEXT_GENERIC_HINT_DAMPENED_SCORE);
    signalScores.cnh = Math.min(signalScores.cnh || 0, UTILITY_CONTEXT_GENERIC_HINT_DAMPENED_SCORE);
  }
  if (hasCnhStrongHint) signalScores.cnh = Math.max(signalScores.cnh || 0, SCORE_STRONG_HINT);
  if (hasCtpsStrongHint) signalScores.ctps_completa = Math.max(signalScores.ctps_completa || 0, SCORE_STRONG_HINT);

  const supportScores = {
    cnh: /\b(cnh[-\s]?e|cnh|cnh digital|habilitacao|carteira nacional de habilitacao|renach)\b/.test(hintSupportText) ? 0.8 : 0,
    rg: /\b(rg|identidade)\b/.test(hintSupportText) ? 0.8 : 0,
    cpf: /\b(cpf)\b/.test(hintSupportText) ? 0.8 : 0,
    ctps_completa: /\b(ctpsdigital|ctps digital|ctps|carteira de trabalho digital|carteira de trabalho)\b/.test(hintSupportText) ? 0.8 : 0,
    comprovante_residencia: /\b(comprovante|residenc|conta de luz|conta de agua|conta de internet|fatura de energia|boleto|iptu|logradouro|cep|endereco)\b/.test(hintSupportText) ? 0.8 : 0,
    holerite: /\b(holerite|contracheque|folha de pagamento|vencimentos)\b/.test(hintSupportText) ? 0.8 : 0,
    extrato_bancario: /\b(extrato|movimentacao|aposentadoria|inss|beneficio)\b/.test(hintSupportText) ? 0.8 : 0,
    declaracao_ir: /\b(declaracao.*ir|imposto de renda|dirpf)\b/.test(hintSupportText) ? 0.8 : 0,
    recibo_ir: /\b(recibo.*ir|numero do recibo|darf)\b/.test(hintSupportText) ? 0.8 : 0
  };

  if (mimeType.startsWith("image/") || mimeType === "application/pdf") {
    // apenas sinal fraco de apoio para documento visualmente vûÀlido
    for (const key of Object.keys(supportScores)) supportScores[key] = Math.max(0, supportScores[key]);
  }

  if (hasCtpsStrongContext || hasCtpsStrongHint) {
    textScores.comprovante_residencia = 0;
    signalScores.comprovante_residencia = 0;
    supportScores.comprovante_residencia = 0;
  }

  // Blindagem conservadora: quando houver contexto residencial forte e coerente
  // (ex.: concessionûÀria/telecom + cobranûÏa/endereûÏo), extrato nûÈo deve competir forte
  // apenas por tokens genûˋricos compartilhados.
  const shouldApplyResidenciaExtratoTiebreak =
    hasResidenciaStrongContext &&
    !hasExtratoBancarioStrongContext &&
    textScores.comprovante_residencia >= SCORE_MAX;
  const MAX_EXTRATO_SCORE_UNDER_RESIDENCIA_TIEBREAK = 0.2;
  if (shouldApplyResidenciaExtratoTiebreak) {
    textScores.extrato_bancario = Math.min(Number(textScores.extrato_bancario || 0), MAX_EXTRATO_SCORE_UNDER_RESIDENCIA_TIEBREAK);
    signalScores.extrato_bancario = Math.min(Number(signalScores.extrato_bancario || 0), MAX_EXTRATO_SCORE_UNDER_RESIDENCIA_TIEBREAK);
    supportScores.extrato_bancario = Math.min(Number(supportScores.extrato_bancario || 0), MAX_EXTRATO_SCORE_UNDER_RESIDENCIA_TIEBREAK);
  }

  const scoring = scoreEnvioDocsDocumentClassification({ textScores, signalScores, supportScores });
  const textStrongTypes = Object.entries(textScores).filter(([, score]) => Number(score) >= 0.95).map(([tipo]) => tipo);
  const hasTextConflict =
    textStrongTypes.length > 1 &&
    !textStrongTypes.every((tipo) => ENVIO_DOCS_TIPOS_ALVO_RENDA_RESIDENCIA.includes(String(tipo || "").trim().toLowerCase()));
  const blockedByThreshold = scoring.topScore < 0.45;
  const blockedByConflict = hasTextConflict || scoring.hasRelevantConflict;
  // Relaxamento estritamente controlado para renda/residûˆncia:
  // - exige pista forte estruturada/contextual (>= 0.8),
  // - baixa competiûÏûÈo do segundo candidato (< 0.2),
  // - e score mûÙnimo total (>= 0.28 = 0.25*0.8 + 0.10*0.8).
  const RELAXED_MIN_TOP_SCORE = 0.28;
  const RELAXED_MAX_SECOND_SCORE = 0.2;
  const RELAXED_MIN_SIGNAL_OR_SUPPORT = 0.8;
  const topIsRendaResidencia = ENVIO_DOCS_TIPOS_ALVO_RENDA_RESIDENCIA.includes(scoring.topType);
  const topSignalScore = Number(signalScores?.[scoring.topType] || 0);
  const topSupportScore = Number(supportScores?.[scoring.topType] || 0);
  const pendingItems = Array.isArray(st?.envio_docs_itens_json)
    ? st.envio_docs_itens_json.filter((item) => isEnvioDocsBlockingItem(item) && !isEnvioDocsItemReceived(item))
    : [];
  const topCoverageMatches = pendingItems.filter((item) => envioDocsHintTipoMatchesItemTipo(scoring.topType, item?.tipo));
  const secondCoverageMatches = pendingItems.filter((item) => envioDocsHintTipoMatchesItemTipo(scoring.secondType, item?.tipo));
  let resolvedTargetedConflictTypeFromDossier = null;
  if (scoring.conflictOnlyWithinRendaResidencia === true) {
    if (topCoverageMatches.length === 1 && secondCoverageMatches.length === 0) {
      resolvedTargetedConflictTypeFromDossier = scoring.topType;
    } else if (topCoverageMatches.length === 0 && secondCoverageMatches.length === 1) {
      resolvedTargetedConflictTypeFromDossier = scoring.secondType;
    }
  }
  const canRelaxTargetedConflictWithDossier =
    blockedByConflict &&
    !hasTextConflict &&
    !!resolvedTargetedConflictTypeFromDossier;
  const canRelaxTargetedLowEvidence =
    blockedByThreshold &&
    !blockedByConflict &&
    topIsRendaResidencia &&
    scoring.topScore >= RELAXED_MIN_TOP_SCORE &&
    scoring.secondScore < RELAXED_MAX_SECOND_SCORE &&
    (topSignalScore >= RELAXED_MIN_SIGNAL_OR_SUPPORT || topSupportScore >= RELAXED_MIN_SIGNAL_OR_SUPPORT);
  const shouldBlockClassification =
    (blockedByConflict && !canRelaxTargetedConflictWithDossier) ||
    (blockedByThreshold && !canRelaxTargetedLowEvidence);

  logEnvioDocsDocAiDebug({
    event: "envio_docs_doc_ai_scoring_debug",
    stage: "envio_docs",
    message: "DEBUG scoring classificaûÏûÈo documental",
    details: {
      file_name: debugFileName,
      mime_type: mimeType || null,
      text_has_content: textHasContent,
      text_scores: textScores,
      signal_scores: signalScores,
      support_scores: supportScores,
      top_candidate: scoring.topType,
      second_candidate: scoring.secondType,
      top_score: Number(scoring.topScore || 0),
      second_score: Number(scoring.secondScore || 0),
      has_text_conflict: hasTextConflict,
      has_relevant_conflict: scoring.hasRelevantConflict === true,
      has_relevant_conflict_base: scoring.hasRelevantConflictBase === true,
      conflict_only_within_renda_residencia: scoring.conflictOnlyWithinRendaResidencia === true,
      has_strong_target_conflict: scoring.hasStrongTargetConflict === true,
      threshold_min: 0.45,
      top_signal_score: topSignalScore,
      top_support_score: topSupportScore,
      residencia_vs_extrato_tiebreak_applied: shouldApplyResidenciaExtratoTiebreak,
      top_coverage_matches_pending: topCoverageMatches.map((item) => ({ tipo: item?.tipo || null, participante: item?.participante || null })),
      second_coverage_matches_pending: secondCoverageMatches.map((item) => ({ tipo: item?.tipo || null, participante: item?.participante || null })),
      resolved_targeted_conflict_type_from_dossier: resolvedTargetedConflictTypeFromDossier,
      can_relax_targeted_conflict_with_dossier: canRelaxTargetedConflictWithDossier,
      can_relax_targeted_low_evidence: canRelaxTargetedLowEvidence,
      would_return_nao_identificado: shouldBlockClassification
    }
  });

  if (shouldBlockClassification) {
    const classificationConfidence = Math.min(0.4, Math.max(0, scoring.topScore));
    const classificationReason = hasTextConflict
      ? "Conflito de evidûˆncia textual forte entre tipos documentais."
      : scoring.hasRelevantConflict
        ? "Ambiguidade relevante entre sinais textuais/estruturados."
        : "Sinais insuficientes para classificaûÏûÈo documental segura.";
    const classificationErrorCode = "ambiguous_or_low_confidence";
    const classificationErrorMessage = "ClassificaûÏûÈo conservadora: retorno como nao_identificado.";

    logEnvioDocsDocAiDebug({
      event: "envio_docs_doc_ai_block_reason",
      stage: "envio_docs",
      message: "DEBUG bloqueio conservador da classificaûÏûÈo documental",
      details: {
        file_name: debugFileName,
        detected_doc_type_final: "nao_identificado",
        classification_confidence: classificationConfidence,
        classification_reason: classificationReason,
        classification_error_code: classificationErrorCode,
        classification_error_message: classificationErrorMessage,
        top_candidate: scoring.topType,
        second_candidate: scoring.secondType,
        top_score: Number(scoring.topScore || 0),
        second_score: Number(scoring.secondScore || 0),
        has_text_conflict: hasTextConflict,
        has_relevant_conflict: scoring.hasRelevantConflict === true,
        blocked_by_threshold: blockedByThreshold,
        blocked_by_conflict: blockedByConflict,
        can_relax_targeted_conflict_with_dossier: canRelaxTargetedConflictWithDossier,
        resolved_targeted_conflict_type_from_dossier: resolvedTargetedConflictTypeFromDossier,
        can_relax_targeted_low_evidence: canRelaxTargetedLowEvidence,
        recognition_source_candidate: "document_engine"
      }
    });

    return buildEnvioDocsDocumentClassificationResult({
      detected_doc_type: "nao_identificado",
      classification_confidence: classificationConfidence,
      classification_reason: classificationReason,
      detected_signals_json: {
        ...signalsJson,
        text_scores: textScores,
        signal_scores: signalScores,
        support_scores: supportScores,
        top_candidate: scoring.topType,
        second_candidate: scoring.secondType
      },
      classification_ok: false,
      classification_error_code: classificationErrorCode,
      classification_error_message: classificationErrorMessage
    });
  }

  const resolvedDocType =
    canRelaxTargetedConflictWithDossier && resolvedTargetedConflictTypeFromDossier
      ? resolvedTargetedConflictTypeFromDossier
      : scoring.topType;
  const resolvedConfidence =
    resolvedDocType === scoring.secondType
      ? Number(scoring.secondScore || 0)
      : Number(scoring.topScore || 0);

  return buildEnvioDocsDocumentClassificationResult({
    detected_doc_type: resolvedDocType,
    classification_confidence: resolvedConfidence,
    classification_reason: textHasContent
      ? "ClassificaûÏûÈo priorizada por evidûˆncia textual extraûÙda, com sinais estruturados e apoio contextual."
      : "ClassificaûÏûÈo sem texto forte; baseada em sinais estruturados e apoio contextual.",
    detected_signals_json: {
      ...signalsJson,
      text_scores: textScores,
      signal_scores: signalScores,
      support_scores: supportScores,
      top_candidate: scoring.topType,
      second_candidate: scoring.secondType
    },
    classification_ok: true
  });
}

async function extractEnvioDocsSignals(env, mediaObject, opts = {}) {
  const MAX_TEXT_PREVIEW_LENGTH = 1200;
  const sourceTypeRaw = String(
    opts?.sourceType || mediaObject?.source_type || mediaObject?.type || ""
  ).toLowerCase();
  const mimeType = String(mediaObject?.mime_type || mediaObject?.mimetype || "").toLowerCase();
  const fileName = String(mediaObject?.filename || mediaObject?.file_name || "").trim() || null;
  const buildStamp = String(typeof ENOVA_BUILD === "string" ? ENOVA_BUILD : "").trim() || null;
  const runtimeGitCommit = getRuntimeGitCommitHint(env);

  const sourceType =
    sourceTypeRaw === "image"
      ? "image"
      : sourceTypeRaw === "document" ||
          mimeType === "application/pdf" ||
          /\.pdf$/i.test(fileName || "")
        ? "pdf"
        : sourceTypeRaw;

  const rawFileSize =
    mediaObject?.file_size ??
    mediaObject?.size ??
    mediaObject?.bytes ??
    mediaObject?.fileSize ??
    null;

  const binarySizeBytes = Number.isFinite(Number(rawFileSize))
    ? Number(rawFileSize)
    : null;

  const result = {
    source_type: sourceType || null,
    mime_type: mimeType || null,
    file_name: fileName,
    extraction_source: "mistral",
    extracted_text_preview: null,
    extracted_text_full: null,
    page_count: null,
    signals_json: {},
    confidence_base: null,
    extraction_ok: false,
    extraction_error_code: null,
    extraction_error_message: null
  };

  if (sourceType !== "pdf" && sourceType !== "image") {
    result.extraction_error_code = "unsupported_source_type";
    result.extraction_error_message = "ExtraûÏûÈo documental sû° suporta PDF/imagem nesta fase.";

    logEnvioDocsDocAiDebug({
      event: "envio_docs_doc_ai_extract_debug",
      stage: "envio_docs",
      message: "DEBUG extraûÏûÈo documental ã source_type nûÈo suportado",
      details: {
        source_type: result.source_type || null,
        source_type_raw: sourceTypeRaw || null,
        mime_type: result.mime_type || null,
        file_name: result.file_name || null,
        binary_size_bytes: binarySizeBytes,
        extraction_ok: false,
        extraction_error_code: result.extraction_error_code,
        extraction_error_message: result.extraction_error_message,
        build_stamp: buildStamp,
        runtime_git_commit: runtimeGitCommit
      }
    });

    return result;
  }

  const mediaPayload = await downloadEnvioDocsMediaAsBase64(env, mediaObject, opts);

  if (!mediaPayload?.ok) {
    result.extraction_error_code = mediaPayload?.error_code || "media_resolution_failed";
    result.extraction_error_message =
      mediaPayload?.error_message || "Falha ao resolver mûÙdia para extraûÏûÈo.";

    logEnvioDocsDocAiDebug({
      event: "envio_docs_doc_ai_extract_debug",
      stage: "envio_docs",
      message: "DEBUG extraûÏûÈo documental ã falha ao resolver mûÙdia",
      details: {
        source_type: result.source_type || null,
        source_type_raw: sourceTypeRaw || null,
        mime_type: result.mime_type || null,
        file_name: result.file_name || null,
        binary_size_bytes: binarySizeBytes,
        extraction_ok: false,
        extraction_error_code: result.extraction_error_code,
        extraction_error_message: result.extraction_error_message,
        media_payload_ok: false,
        build_stamp: buildStamp,
        runtime_git_commit: runtimeGitCommit
      }
    });

    return result;
  }

  const mediaPayloadBase64Length = String(mediaPayload?.base64 || "").length;

  const ocr = await runMistralOCR(
    env,
    {
      sourceType,
      base64: mediaPayload.base64,
      sourceUrl: null,
      mime_type: result.mime_type,
      file_name: result.file_name,
      binary_size_bytes: binarySizeBytes
    },
    opts
  );

  if (!ocr?.ok) {
    result.extraction_error_code = ocr?.error_code || "ocr_failed";
    result.extraction_error_message = ocr?.error_message || "Falha na extraûÏûÈo OCR.";

    logEnvioDocsDocAiDebug({
      event: "envio_docs_doc_ai_extract_debug",
      stage: "envio_docs",
      message: "DEBUG extraûÏûÈo documental ã OCR falhou",
      details: {
        source_type: result.source_type || null,
        source_type_raw: sourceTypeRaw || null,
        mime_type: result.mime_type || null,
        file_name: result.file_name || null,
        binary_size_bytes: binarySizeBytes,
        media_payload_ok: true,
        media_payload_base64_length: mediaPayloadBase64Length,
        extraction_ok: false,
        extraction_error_code: result.extraction_error_code,
        extraction_error_message: result.extraction_error_message,
        ocr_provider: ocr?.provider || result.extraction_source || null,
        build_stamp: buildStamp,
        runtime_git_commit: runtimeGitCommit
      }
    });

    return result;
  }

  const textFull = String(ocr?.text || "").trim();
  const normalizedText = normalizeText(textFull);

  result.extraction_ok = true;
  result.page_count = ocr?.page_count ?? null;
  result.confidence_base = ocr?.confidence_base ?? null;
  result.extracted_text_full = textFull || null;
  result.extracted_text_preview = textFull
    ? textFull.slice(0, MAX_TEXT_PREVIEW_LENGTH)
    : null;
  result.signals_json = inferEnvioDocsSignalsFromExtractedText(textFull, {
    fileName,
    mimeType: result.mime_type
  });

  const docTypeHints = Array.isArray(result?.signals_json?.doc_type_hints)
    ? result.signals_json.doc_type_hints
    : [];
  const participantHints = Array.isArray(result?.signals_json?.participant_hints)
    ? result.signals_json.participant_hints
    : [];
  const hasCpfPattern = result?.signals_json?.has_cpf_pattern === true;
  const keywordDensity = Number(result?.signals_json?.keyword_density || 0) || 0;

  logEnvioDocsDocAiDebug({
    event: "envio_docs_doc_ai_extract_debug",
    stage: "envio_docs",
    message: "DEBUG extraûÏûÈo documental",
    details: {
      source_type: result.source_type || null,
      source_type_raw: sourceTypeRaw || null,
      mime_type: result.mime_type || null,
      file_name: result.file_name || null,
      binary_size_bytes: binarySizeBytes,
      media_payload_ok: true,
      media_payload_base64_length: mediaPayloadBase64Length,
      extraction_ok: true,
      extraction_source: result.extraction_source || null,
      ocr_provider: ocr?.provider || result.extraction_source || null,
      ocr_error_code: result.extraction_error_code || null,
      ocr_error_message: result.extraction_error_message || null,
      page_count: result.page_count,
      confidence_base: result.confidence_base,
      extracted_text_length: textFull.length,
      extracted_text_preview_masked: maskEnvioDocsExtractPreview(textFull, 400),
      has_text_content: normalizedText.length >= 20,
      doc_type_hints: docTypeHints,
      participant_hints: participantHints,
      has_cpf_pattern: hasCpfPattern,
      keyword_density: keywordDensity,
      build_stamp: buildStamp,
      runtime_git_commit: runtimeGitCommit
    }
  });

  return result;
}

function classifyEnvioDocsBasicValidation({ mediaObject, normalizedMsg, target, hintText }) {
  const MIN_IMAGE_SIZE_BYTES = 15 * 1024;
  const MIN_IMAGE_DIMENSION = 320;
  const MIN_DOCUMENT_SIZE_BYTES = 20 * 1024;

  if (!mediaObject) {
    return {
      status: "recebido_pendente_validacao",
      reason: "sinal_textual_sem_arquivo",
      details: { sourceType: "text_signal", expectedCategory: envioDocsCategoriaFromTipo(target?.tipo || "") }
    };
  }

  const sourceType =
    normalizedMsg?.image ? "image" :
    normalizedMsg?.document ? "document" :
    normalizedMsg?.audio ? "audio" :
    normalizedMsg?.video ? "video" :
    null;
  const mimeType = String(mediaObject?.mime_type || "").toLowerCase();
  const fileName = String(mediaObject?.filename || mediaObject?.file_name || "").trim();
  const rawFileSize = mediaObject?.file_size ?? mediaObject?.size ?? mediaObject?.bytes ?? null;
  const hasKnownFileSize = rawFileSize !== null && rawFileSize !== undefined && rawFileSize !== "";
  const fileSize = hasKnownFileSize ? Number(rawFileSize) : null;
    
  console.log("DEBUG-ENVIO-DOCS-VALIDATION:", JSON.stringify({
    sourceType,
    mimeType,
    fileName,
    raw_file_size: mediaObject?.file_size ?? null,
    raw_size: mediaObject?.size ?? null,
    raw_bytes: mediaObject?.bytes ?? null,
    computed_fileSize: fileSize,
    width: mediaObject?.width ?? null,
    height: mediaObject?.height ?? null
  }));
  const width = Number(mediaObject?.width || 0);
  const height = Number(mediaObject?.height || 0);

  const allowed = sourceType === "image" || sourceType === "document";
  if (!allowed) {
    return { status: "invalido", reason: "tipo_midia_nao_documental", details: { sourceType, mimeType, fileSize, fileName } };
  }

  const inferredCategory = inferEnvioDocsCategoriaBasica({ hintText, filename: fileName, mimeType });
  if (inferredCategory === "nao_documento") {
    return { status: "invalido", reason: "mime_nao_documental", details: { sourceType, mimeType, fileSize, fileName } };
  }

  if (hasKnownFileSize && (!Number.isFinite(fileSize) || fileSize <= 0)) {
    return { status: "ilegivel", reason: "arquivo_vazio_ou_corrompido", details: { sourceType, mimeType, fileSize, fileName } };
  }

  if (sourceType === "image") {
  if (hasKnownFileSize && fileSize < MIN_IMAGE_SIZE_BYTES) {
    return { status: "ilegivel", reason: "imagem_muito_pequena", details: { sourceType, mimeType, fileSize, width, height, fileName } };
  }
  if ((width && width < MIN_IMAGE_DIMENSION) || (height && height < MIN_IMAGE_DIMENSION)) {
    return { status: "ilegivel", reason: "resolucao_baixa", details: { sourceType, mimeType, fileSize, width, height, fileName } };
  }
}

  if (sourceType === "document") {
    const isPdf = mimeType === "application/pdf" || /\.pdf$/i.test(fileName);
    if (!isPdf && mimeType && !mimeType.startsWith("image/")) {
      return { status: "invalido", reason: "documento_sem_formato_aceito", details: { sourceType, mimeType, fileSize, fileName } };
    }
    if (hasKnownFileSize && fileSize < MIN_DOCUMENT_SIZE_BYTES) {
      return { status: "ilegivel", reason: "arquivo_documento_muito_pequeno", details: { sourceType, mimeType, fileSize, fileName } };
    }
  }

  const expectedCategory = envioDocsCategoriaFromTipo(target?.tipo || "");
  if (expectedCategory && inferredCategory && inferredCategory !== expectedCategory) {
    return {
      status: "reenvio_solicitado",
      reason: "categoria_divergente",
      details: { sourceType, mimeType, fileSize, fileName, expectedCategory, inferredCategory }
    };
  }

  return {
    status: inferredCategory ? "validado_basico" : "recebido_pendente_validacao",
    reason: inferredCategory ? "validacao_basica_ok" : "categoria_nao_inferida",
    details: { sourceType, mimeType, fileSize, width, height, fileName, inferredCategory, expectedCategory }
  };
}

function selectEnvioDocsItemForUpload(st, selectionContext = {}) {
  const itens = Array.isArray(st.envio_docs_itens_json) ? st.envio_docs_itens_json : [];
  const pendentes = itens.filter((item) => isEnvioDocsConversationalPendingItem(item));
  if (!pendentes.length) {
    return {
      item: null,
      items: [],
      debug: {
        hinted_tipo_raw: null,
        hinted_tipo_normalized: null,
        detected_doc_type: null,
        covers_checklist_types: [],
        matched_item_tipo: null,
        matched_item_participante: null,
        matched_checklist_items: [],
        expected_pending_items_before: []
      }
    };
  }

  // Backward-compatible: aceita string legado (hintText) e objeto com contexto explûÙcito.
  const context = typeof selectionContext === "string"
    ? { hintText: selectionContext }
    : (selectionContext || {});

  const hintText = String(context.hintText || "");
  // Aceita fileName e filename para compatibilidade com payloads legados.
  const fileName = String(context.fileName || context.filename || "");
  const joinedHintText = `${hintText} ${fileName}`.trim();

  const normalizedJoinedHintText = normalizeText(joinedHintText);
  const hasHintUtil = /\b(rg|cpf|cnh|ctps|carteira|identidade|comprovante|residenc|renda|holerite|contracheque|extrat|recibo|darf|imposto de renda|ir)\b/.test(
    normalizedJoinedHintText
  );

  const hintedTipoRaw = guessEnvioDocsTipoFromText(joinedHintText);
  const hintedTipo = normalizeEnvioDocsTipoForChecklist(hintedTipoRaw);
  const detectedDocType = hintedTipoRaw || null;
  const coversChecklistTypes = getEnvioDocsCoveredChecklistTypes(detectedDocType);
  const hintedCategoria = envioDocsCategoriaFromTipo(hintedTipoRaw);
  const hintedParticipante = inferEnvioDocsParticipanteFromText(joinedHintText);

  const tipoMatches = hintedTipo
    ? pendentes.filter((item) => envioDocsHintTipoMatchesItemTipo(hintedTipoRaw, item.tipo))
    : [];

  const categoriaMatches = hintedCategoria
    ? pendentes.filter((item) => envioDocsCategoriaFromTipo(item.tipo) === hintedCategoria)
    : [];

  const extractUniqueParticipante = (matches) => {
    const participantes = [...new Set((matches || []).map((item) => item?.participante).filter(Boolean))];
    return participantes.length === 1 ? participantes[0] : null;
  };

  const detectedParticipant =
    hintedParticipante ||
    extractUniqueParticipante(tipoMatches) ||
    extractUniqueParticipante(categoriaMatches) ||
    null;

  const expectedPendingItemsBefore = pendentes.map((item) => `${item.tipo}:${item.participante}`);

  const toResult = (item, itemsMatched = [], extraDebug = {}) => ({
    item: item || null,
    items: Array.isArray(itemsMatched) ? itemsMatched : [],
    debug: {
      hinted_tipo_raw: hintedTipoRaw || null,
      hinted_tipo_normalized: hintedTipo || null,
      detected_doc_type: detectedDocType,
      covers_checklist_types: coversChecklistTypes,
      detected_participant: detectedParticipant,
      matched_item_tipo: item?.tipo || null,
      matched_item_participante: item?.participante || null,
      matched_checklist_item: item ? { tipo: item.tipo || null, participante: item.participante || null } : null,
      matched_checklist_items: (Array.isArray(itemsMatched) ? itemsMatched : [])
        .map((matched) => ({ tipo: matched?.tipo || null, participante: matched?.participante || null })),
      expected_pending_items_before: expectedPendingItemsBefore,
      ...extraDebug
    }
  });

  if (hintedTipo && hintedParticipante) {
    const matches = pendentes.filter(
      (item) =>
        envioDocsHintTipoMatchesItemTipo(hintedTipoRaw, item.tipo) &&
        item.participante === hintedParticipante
    );
    if (matches.length) return toResult(matches[0], matches);
  }

  if (coversChecklistTypes.length) {
    const coverageMatches = pendentes.filter((item) => envioDocsHintTipoMatchesItemTipo(hintedTipoRaw, item.tipo));
    const participantFromCoverage = extractUniqueParticipante(coverageMatches);
    const participantResolved = hintedParticipante || detectedParticipant || participantFromCoverage || null;

    if (participantResolved) {
      const scopedMatches = coverageMatches.filter((item) => item.participante === participantResolved);
      if (scopedMatches.length) return toResult(scopedMatches[0], scopedMatches);
    }

    // Modo conservador: sem participante resolvido, nûÈo cruza checklist de pessoas diferentes.
    if (coverageMatches.length > 1 && !participantResolved) {
      return toResult(null, [], {
        ambiguity_reason: "coverage_participant_ambiguous",
        ambiguity_candidates: coverageMatches.map((item) => `${item.tipo}:${item.participante}`)
      });
    }
  }

  if (hintedTipo) {
    if (tipoMatches.length === 1) return toResult(tipoMatches[0], tipoMatches);
    if (tipoMatches.length > 1) {
      return toResult(null, [], {
        ambiguity_reason: "tipo_matches_multiple",
        ambiguity_candidates: tipoMatches.map((item) => `${item.tipo}:${item.participante}`)
      });
    }
  }

  if (hintedCategoria && hintedParticipante) {
    const categoryParticipantMatches = categoriaMatches.filter((item) => item.participante === hintedParticipante);
    if (categoryParticipantMatches.length === 1) return toResult(categoryParticipantMatches[0], categoryParticipantMatches);
    if (categoryParticipantMatches.length > 1) {
      return toResult(null, [], {
        ambiguity_reason: "category_participant_matches_multiple",
        ambiguity_candidates: categoryParticipantMatches.map((item) => `${item.tipo}:${item.participante}`)
      });
    }
  }

  if (hintedCategoria) {
    if (categoriaMatches.length === 1) return toResult(categoriaMatches[0], categoriaMatches);
    if (categoriaMatches.length > 1) {
      return toResult(null, [], {
        ambiguity_reason: "category_matches_multiple",
        ambiguity_candidates: categoriaMatches.map((item) => `${item.tipo}:${item.participante}`)
      });
    }

    // Categoria detectada, mas sem pendente compatûÙvel: nûÈo vincula automaticamente.
    return toResult(null, [], {
      ambiguity_reason: "category_detected_without_pending_match"
    });
  }

  // Se existe qualquer pista û¤til no texto/nome do arquivo, mas nada casou com seguranûÏa,
  // nûÈo faz vûÙnculo cego.
  if (hasHintUtil || hintedTipoRaw || hintedParticipante) {
    return toResult(null, [], {
      ambiguity_reason: "hint_present_without_safe_match"
    });
  }

  // Sem pista textual e sem match seguro: tambûˋm nûÈo vincula automaticamente.
  return toResult(null, [], {
    ambiguity_reason: "no_safe_match"
  });
}

function resolveEnvioDocsTargetFromDocumentEngine(itens = [], checklistMatch = {}, documentClassification = {}) {
  const pendingItems = Array.isArray(itens)
    ? itens.filter((item) => isEnvioDocsConversationalPendingItem(item))
    : [];
  const matchStatus = String(checklistMatch?.match_status || "").trim().toLowerCase();
  const detectedDocType = String(documentClassification?.detected_doc_type || "").trim().toLowerCase();
  const matchedItemsRaw = Array.isArray(checklistMatch?.matched_items) ? checklistMatch.matched_items : [];

  if (matchStatus !== "matched_safe") {
    return {
      item: null,
      items: [],
      match_status: matchStatus || "no_match",
      source: "none"
    };
  }
  if (!matchedItemsRaw.length || detectedDocType === "nao_identificado") {
    return {
      item: null,
      items: [],
      match_status: matchStatus,
      source: "none"
    };
  }

  const matchedPendingItems = [];
  const seen = new Set();
  for (const matched of matchedItemsRaw) {
    const key = getEnvioDocsChecklistItemKey(matched);
    if (!isEnvioDocsChecklistItemKeyValid(key) || seen.has(key)) continue;
    seen.add(key);
    const pending = pendingItems.find((item) =>
      item?.tipo === matched?.tipo &&
      item?.participante === matched?.participante
    );
    if (pending) matchedPendingItems.push(pending);
  }

  return {
    item: matchedPendingItems[0] || null,
    items: matchedPendingItems,
    match_status: matchStatus,
    source: matchedPendingItems.length ? "document_engine" : "none"
  };
}

function resolveEnvioDocsRecommendedCtpsTarget(itens = [], checklistMatch = {}, documentClassification = {}) {
  const detectedDocType = String(documentClassification?.detected_doc_type || "").trim().toLowerCase();
  if (detectedDocType !== "ctps_completa") {
    return {
      item: null,
      items: [],
      source: "none"
    };
  }

  const matchStatus = String(checklistMatch?.match_status || "").trim().toLowerCase();
  const matchReason = String(checklistMatch?.match_reason || "").trim().toLowerCase();
  const noPendingReason =
    matchReason === "no_pending_item_for_doc_type" ||
    matchReason === "no_pending_item_for_doc_type_and_participant";
  if (matchStatus !== "no_match" || !noPendingReason) {
    return {
      item: null,
      items: [],
      source: "none"
    };
  }

  const recommendedCtpsItems = itens.filter((item) =>
    String(item?.tipo || "").trim().toLowerCase() === "ctps_completa" &&
    (
      String(item?.bucket || "").trim().toLowerCase() === "recomendado" ||
      Boolean(item?.recomendacao)
    )
  );
  if (!recommendedCtpsItems.length) {
    return {
      item: null,
      items: [],
      source: "none"
    };
  }

  const detectedParticipant = normalizeEnvioDocsDetectedParticipant(
    checklistMatch?.match_signals_json?.detected_participant
  );
  const participantConfidence = Number(
    checklistMatch?.match_signals_json?.participant_confidence || 0
  );
  const participantStrong =
    detectedParticipant !== "desconhecido" && participantConfidence >= 0.75;

  if (participantStrong) {
    const scoped = recommendedCtpsItems.filter(
      (item) => normalizeEnvioDocsDetectedParticipant(item?.participante) === detectedParticipant
    );
    if (scoped.length >= 1) {
      return {
        item: scoped[0],
        items: scoped,
        source: "recommended_ctps"
      };
    }
  }

  const itemsByParticipant = new Map();
  for (const item of recommendedCtpsItems) {
    const participant = normalizeEnvioDocsDetectedParticipant(item?.participante);
    if (!itemsByParticipant.has(participant)) {
      itemsByParticipant.set(participant, []);
    }
    itemsByParticipant.get(participant).push(item);
  }

  if (detectedParticipant !== "desconhecido") {
    const detectedScoped = itemsByParticipant.get(detectedParticipant) || [];
    if (detectedScoped.length >= 1) {
      return {
        item: detectedScoped[0],
        items: detectedScoped,
        source: "recommended_ctps"
      };
    }
  }

  const titularItems = itemsByParticipant.get("p1") || [];
  if (titularItems.length >= 1) {
    return {
      item: titularItems[0],
      items: titularItems,
      source: "recommended_ctps"
    };
  }

  if (itemsByParticipant.size === 1) {
    const onlyGroup = Array.from(itemsByParticipant.values())[0] || [];
    if (onlyGroup.length >= 1) {
      return {
        item: onlyGroup[0],
        items: onlyGroup,
        source: "recommended_ctps"
      };
    }
  }

  if (recommendedCtpsItems.length === 1) {
    return {
      item: recommendedCtpsItems[0],
      items: recommendedCtpsItems,
      source: "recommended_ctps"
    };
  }

  return {
    item: null,
    items: [],
    source: "none"
  };
}

function resolveEnvioDocsPendingCtpsTarget(itens = [], checklistMatch = {}, documentClassification = {}) {
  const detectedDocType = String(documentClassification?.detected_doc_type || "").trim().toLowerCase();
  if (detectedDocType !== "ctps_completa") {
    return {
      item: null,
      items: [],
      source: "none"
    };
  }

  const pendingCtpsItems = (Array.isArray(itens) ? itens : []).filter((item) => {
    if (!isEnvioDocsConversationalPendingItem(item)) return false;
    const tipo = String(item?.tipo || "").trim().toLowerCase();
    return CTPS_NON_BLOCKING_DOC_TYPES.has(tipo);
  });
  if (!pendingCtpsItems.length) {
    return {
      item: null,
      items: [],
      source: "none"
    };
  }

  const detectedParticipant = normalizeEnvioDocsDetectedParticipant(
    checklistMatch?.match_signals_json?.detected_participant
  );
  const participantConfidence = Number(
    checklistMatch?.match_signals_json?.participant_confidence || 0
  );
  const participantStrong =
    detectedParticipant !== "desconhecido" && participantConfidence >= 0.75;
  if (participantStrong) {
    const scoped = pendingCtpsItems.filter(
      (item) => normalizeEnvioDocsDetectedParticipant(item?.participante) === detectedParticipant
    );
    if (scoped.length >= 1) {
      return {
        item: scoped[0],
        items: scoped,
        source: "pending_ctps"
      };
    }
  }

  const activeParticipant = normalizeEnvioDocsDetectedParticipant(
    resolveEnvioDocsCurrentParticipant(itens)
  );
  const activeScoped = pendingCtpsItems.filter(
    (item) => normalizeEnvioDocsDetectedParticipant(item?.participante) === activeParticipant
  );
  if (activeScoped.length === 1) {
    return {
      item: activeScoped[0],
      items: activeScoped,
      source: "pending_ctps"
    };
  }

  if (pendingCtpsItems.length === 1) {
    return {
      item: pendingCtpsItems[0],
      items: pendingCtpsItems,
      source: "pending_ctps"
    };
  }

  return {
    item: null,
    items: [],
    source: "none"
  };
}

function chooseEnvioDocsFinalTarget(input = {}) {
  const itens = Array.isArray(input?.itens) ? input.itens : [];
  const checklistMatch = input?.checklistMatch || {};
  const documentClassification = input?.documentClassification || {};
  const legacySelection = input?.legacySelection || {};
  const engineResolution = input?.engineResolution || resolveEnvioDocsTargetFromDocumentEngine(itens, checklistMatch, documentClassification);
  const pendingCtpsResolution = resolveEnvioDocsPendingCtpsTarget(itens, checklistMatch, documentClassification);
  const recommendedCtpsResolution = resolveEnvioDocsRecommendedCtpsTarget(itens, checklistMatch, documentClassification);
  const matchStatus = String(checklistMatch?.match_status || "").trim().toLowerCase();
  const fallbackAllowed = matchStatus !== "matched_safe" || !engineResolution.item;
  const fallbackItem = fallbackAllowed ? (legacySelection?.item || null) : null;
  const fallbackItems = fallbackAllowed && Array.isArray(legacySelection?.items) ? legacySelection.items : [];
  const pendingItems = itens.filter((item) => isEnvioDocsBlockingItem(item) && !isEnvioDocsItemReceived(item));
  const detectedDocType = String(documentClassification?.detected_doc_type || "").trim().toLowerCase();
  const detectedRendaResidencia = ENVIO_DOCS_TIPOS_ALVO_RENDA_RESIDENCIA.includes(detectedDocType);
  const dossierCoverageCandidates = detectedRendaResidencia
    ? pendingItems.filter((item) => envioDocsHintTipoMatchesItemTipo(detectedDocType, item?.tipo))
    : [];
  const dossierCoverageResolution =
    dossierCoverageCandidates.length === 1
      ? {
          item: dossierCoverageCandidates[0],
          items: dossierCoverageCandidates,
          source: "dossier_coverage"
        }
      : {
          item: null,
          items: [],
          source: "none"
        };
  const fallbackTargetsRendaResidencia =
    fallbackItem &&
    ["comprovante_residencia", "comprovante_renda"].includes(String(fallbackItem?.tipo || "").trim().toLowerCase());
  const fallbackTipoNormalizado = String(fallbackItem?.tipo || "").trim().toLowerCase();
  const detectedCoveredTypes = getEnvioDocsCoveredChecklistTypes(detectedDocType);
  const isFallbackCoverageCoherent =
    !fallbackTargetsRendaResidencia ||
    (detectedRendaResidencia && detectedCoveredTypes.includes(fallbackTipoNormalizado));
  const fallbackSameTypePending = fallbackTargetsRendaResidencia
    ? pendingItems.filter((item) => String(item?.tipo || "").trim().toLowerCase() === fallbackTipoNormalizado)
    : [];
  const canUseFallbackSafelyWithDossier =
    !fallbackTargetsRendaResidencia ||
    (isFallbackCoverageCoherent &&
      fallbackSameTypePending.length === 1 &&
      fallbackSameTypePending[0]?.tipo === fallbackItem?.tipo &&
      fallbackSameTypePending[0]?.participante === fallbackItem?.participante);

  if (engineResolution.item) {
    return {
      target: engineResolution.item,
      matchedItems: engineResolution.items,
      fallbackUsed: false,
      finalTargetSource: "document_engine",
      engineResolution,
      recommendedCtpsResolution,
      recommendedCtpsRuleEvaluated: true
    };
  }

  if (pendingCtpsResolution.item) {
    return {
      target: pendingCtpsResolution.item,
      matchedItems: pendingCtpsResolution.items,
      fallbackUsed: false,
      finalTargetSource: "pending_ctps",
      engineResolution,
      pendingCtpsResolution,
      recommendedCtpsResolution,
      recommendedCtpsRuleEvaluated: true
    };
  }

  if (recommendedCtpsResolution.item) {
    return {
      target: recommendedCtpsResolution.item,
      matchedItems: recommendedCtpsResolution.items,
      fallbackUsed: false,
      finalTargetSource: "recommended_ctps",
      engineResolution,
      pendingCtpsResolution,
      recommendedCtpsResolution,
      recommendedCtpsRuleEvaluated: true
      };
  }

  if (dossierCoverageResolution.item) {
    return {
      target: dossierCoverageResolution.item,
      matchedItems: dossierCoverageResolution.items,
      fallbackUsed: false,
      finalTargetSource: "dossier_coverage",
      engineResolution,
      pendingCtpsResolution,
      recommendedCtpsResolution,
      recommendedCtpsRuleEvaluated: true
    };
  }

  if (fallbackItem && !canUseFallbackSafelyWithDossier) {
    return {
      target: null,
      matchedItems: [],
      fallbackUsed: false,
      finalTargetSource: "none",
      engineResolution,
      pendingCtpsResolution,
      recommendedCtpsResolution,
      recommendedCtpsRuleEvaluated: true
    };
  }

  if (fallbackItem) {
    return {
      target: fallbackItem,
      matchedItems: fallbackItems.length ? fallbackItems : [fallbackItem],
      fallbackUsed: true,
      finalTargetSource: "legacy_fallback",
      engineResolution,
      pendingCtpsResolution,
      recommendedCtpsResolution,
      recommendedCtpsRuleEvaluated: true
    };
  }

  return {
    target: null,
    matchedItems: [],
    fallbackUsed: false,
    finalTargetSource: "none",
    engineResolution,
    pendingCtpsResolution,
    recommendedCtpsResolution,
    recommendedCtpsRuleEvaluated: true
  };
}

function getEnvioDocsChecklistItemKey(item = {}) {
  return `${item?.tipo || ""}:${item?.participante || ""}`;
}

function isEnvioDocsChecklistItemKeyValid(key) {
  return !!key && key !== ":";
}

function normalizeEnvioDocsMatchedItems(items = []) {
  const out = [];
  const seen = new Set();
  for (const item of Array.isArray(items) ? items : []) {
    const key = getEnvioDocsChecklistItemKey(item);
    if (!isEnvioDocsChecklistItemKeyValid(key) || seen.has(key)) continue;
    seen.add(key);
    out.push(item);
  }
  return out;
}

function mapEnvioDocsItemRefs(items = []) {
  return (Array.isArray(items) ? items : []).map((item) => ({
    tipo: item?.tipo || null,
    participante: item?.participante || null
  }));
}

function isEnvioDocsTextualUploadSignal(texto) {
  const t = normalizeText(texto || "");
  if (!t) return false;
  if (!/\b(enviei|envio|segue|mandei|acabei de mandar|anexei|subi)\b/.test(t)) return false;
  return /\b(doc|documento|arquivo|anexo|foto|comprovante|rg|cpf|holerite|ir|extrato)\b/.test(t);
}

function clearEnvioDocsPendingTypeConfirmationPatch(extra = {}) {
  return {
    fase_docs: "envio_documentos",
    docs_status_texto: null,
    ...extra
  };
}

function isEnvioDocsAwaitingTypeConfirmation(st = {}) {
  const legacyPending = decodeEnvioDocsLegacyPendingConfirmation(st);
  return (
    String(st?.envio_docs_confirmacao_tipo_doc_status || st?.fase_docs || "").trim().toLowerCase() === "aguardando_confirmacao_tipo_doc" &&
    (!!st?.envio_docs_ultimo_upload_pendente_confirmacao_json || !!legacyPending)
  );
}

function normalizeEnvioDocsUploadSemanticStatus(value) {
  const raw = String(value || "").trim().toLowerCase();
  if (raw === "confirmado") return "confirmado";
  if (raw === "plausivel_incerto") return "plausivel_incerto";
  return "incompativel";
}

function resolveEnvioDocsPendingConfirmationCandidateItems(input = {}) {
  const itens = Array.isArray(input?.itens) ? input.itens : [];
  const checklistMatchedItems = Array.isArray(input?.checklistMatch?.matched_items) ? input.checklistMatch.matched_items : [];
  const legacyItems = Array.isArray(input?.selection?.items) ? input.selection.items : [];
  const detectedDocType = String(input?.documentClassification?.detected_doc_type || "").trim().toLowerCase();
  const candidates = [];
  const seen = new Set();
  const pushCandidate = (item) => {
    const key = `${item?.tipo || ""}:${item?.participante || ""}`;
    if (!item || !isEnvioDocsChecklistItemKeyValid(key) || seen.has(key)) return;
    seen.add(key);
    candidates.push({
      tipo: item?.tipo || null,
      participante: item?.participante || null
    });
  };

  for (const item of checklistMatchedItems) pushCandidate(item);
  for (const item of legacyItems) pushCandidate(item);

  if (detectedDocType && detectedDocType !== "nao_identificado") {
    for (const item of itens.filter((entry) => isEnvioDocsConversationalPendingItem(entry))) {
      if (envioDocsHintTipoMatchesItemTipo(detectedDocType, item?.tipo)) {
        pushCandidate(item);
      }
    }
  }

  return candidates;
}

function resolveEnvioDocsUploadSemanticStatus(input = {}) {
  const validationStatus = String(input?.validation?.status || "").trim().toLowerCase();
  const detectedDocType = String(input?.documentClassification?.detected_doc_type || "").trim().toLowerCase();
  const candidateItems = Array.isArray(input?.candidateItems) ? input.candidateItems : [];
  const hasRecognitionEvidence =
    (detectedDocType && detectedDocType !== "nao_identificado") ||
    String(input?.selectionDebug?.hinted_tipo_raw || "").trim().length > 0 ||
    candidateItems.length > 0;

  if (Array.isArray(input?.matchedItems) && input.matchedItems.length > 0) {
    return "confirmado";
  }

  if (validationStatus === "invalido" || validationStatus === "invûÀlido" || validationStatus === "reenvio_solicitado" || validationStatus === "reenvio solicitado") {
    return "incompativel";
  }

  if (hasRecognitionEvidence && candidateItems.length > 0) {
    return "plausivel_incerto";
  }

  if (detectedDocType && detectedDocType !== "nao_identificado") {
    return "confirmado";
  }

  return "incompativel";
}

function buildEnvioDocsPendingConfirmationQuestion(pendingUpload = {}) {
  const candidateItems = Array.isArray(pendingUpload?.candidate_items) ? pendingUpload.candidate_items : [];
  if (candidateItems.length === 1) {
    const candidate = candidateItems[0];
    const docLabel = prettyDocLabel(candidate?.tipo || "documento").toLowerCase();
    const ownerLabel =
      candidate?.participante === "p1"
        ? `seu ${docLabel}`
        : candidate?.participante === "p2"
          ? `${docLabel} do parceiro(a)`
          : `${docLabel} da composiûÏûÈo`;
    return `Recebi seu arquivo, mas nûÈo consegui confirmar sozinho. Esse arquivo ûˋ mesmo ${ownerLabel}?`;
  }

  const suggestedDocLabel = prettyDocLabel(pendingUpload?.detected_doc_type || "documento").toLowerCase();
  return `Recebi seu arquivo, mas nûÈo consegui confirmar sozinho. Que documento ûˋ esse arquivo? Ex.: ${suggestedDocLabel}.`;
}

function buildEnvioDocsPendingConfirmationRecord(input = {}) {
  const normalizedMsg = input?.normalizedMsg || {};
  const mediaObject = input?.mediaObject || null;
  const pendingUploadId =
    String(
      normalizedMsg?.message_id ||
      mediaObject?.id ||
      input?.st?.last_message_id ||
      `upload_pendente_${Date.now()}`
    ).trim();
  const candidateItems = resolveEnvioDocsPendingConfirmationCandidateItems(input);
  const mediaRef = {
    media_id: mediaObject?.id || null,
    mime_type: mediaObject?.mime_type || null,
    file_name: mediaObject?.filename || mediaObject?.file_name || null,
    url: String(
      mediaObject?.url ||
      mediaObject?.link ||
      mediaObject?.document_url ||
      mediaObject?.download_url ||
      mediaObject?.media_url ||
      ""
    ).trim() || null
  };
  return {
    upload_id: pendingUploadId,
    upload_message_id: String(normalizedMsg?.message_id || input?.st?.last_message_id || "").trim() || null,
    received_at: new Date().toISOString(),
    detected_doc_type: input?.documentClassification?.detected_doc_type || null,
    detected_doc_category: input?.documentClassification?.detected_doc_category || null,
    detected_participant: input?.participantInference?.detected_participant || null,
    classification_confidence: Number(input?.documentClassification?.classification_confidence || 0) || 0,
    recognition_source: input?.recognitionSource || "document_engine",
    candidate_items: candidateItems,
    media_ref: mediaRef,
    pergunta_confirmacao: buildEnvioDocsPendingConfirmationQuestion({
      detected_doc_type: input?.documentClassification?.detected_doc_type || null,
      candidate_items: candidateItems
    })
  };
}

function resolveEnvioDocsPendingConfirmationTargetFromText(st = {}, pendingUpload = {}, text = "") {
  const hintedTipoRaw = guessEnvioDocsTipoFromText(text);
  if (!hintedTipoRaw) {
    return {
      ok: false,
      reason: "confirmation_text_without_doc_type",
      target: null,
      hinted_tipo_raw: null
    };
  }

  const selection = selectEnvioDocsItemForUpload(st, { hintText: text });
  const candidateKeys = new Set(
    (Array.isArray(pendingUpload?.candidate_items) ? pendingUpload.candidate_items : [])
      .map((item) => `${item?.tipo || ""}:${item?.participante || ""}`)
      .filter((key) => isEnvioDocsChecklistItemKeyValid(key))
  );
  const selectedItem = selection?.item || null;
  const selectedKey = selectedItem ? `${selectedItem?.tipo || ""}:${selectedItem?.participante || ""}` : null;
  const selectedMatchesPending = !!selectedKey && candidateKeys.has(selectedKey);

  if (selectedItem && selectedMatchesPending) {
    return {
      ok: true,
      reason: "confirmation_text_matched_pending_candidate",
      target: selectedItem,
      hinted_tipo_raw: hintedTipoRaw
    };
  }

  const hintedParticipant = inferEnvioDocsParticipanteFromText(text);
  const candidateItems = (Array.isArray(pendingUpload?.candidate_items) ? pendingUpload.candidate_items : [])
    .filter((item) => envioDocsHintTipoMatchesItemTipo(hintedTipoRaw, item?.tipo))
    .filter((item) => !hintedParticipant || item?.participante === hintedParticipant);

  if (candidateItems.length === 1) {
    return {
      ok: true,
      reason: "confirmation_text_resolved_single_candidate",
      target: candidateItems[0],
      hinted_tipo_raw: hintedTipoRaw
    };
  }

  return {
    ok: false,
    reason: candidateItems.length > 1 ? "confirmation_text_still_ambiguous" : "confirmation_text_incompatible_with_pending_upload",
    target: null,
    hinted_tipo_raw: hintedTipoRaw
  };
}

function normalizeEnvioDocsIncomingMedia(msg, seen = new WeakSet()) {
  const rawMsg = msg;
  if (typeof msg === "string") {
    const trimmed = msg.trim();
    if (!trimmed) return msg;
    if (/^[\[{]/.test(trimmed)) {
      try {
        msg = JSON.parse(trimmed);
      } catch {
        return rawMsg;
      }
    } else {
      return rawMsg;
    }
  }

  if (!msg || typeof msg !== "object") return msg;
  if (seen.has(msg)) return msg;
  seen.add(msg);

  if (msg.image || msg.audio || msg.document || msg.video) return msg;

  const knownTypes = ["image", "audio", "document", "video"];

  const hasMediaPayload = (obj) =>
    obj &&
    typeof obj === "object" &&
    (
      obj.id ||
      obj.link ||
      obj.url ||
      obj.mime_type ||
      obj.mimetype ||
      obj.filename ||
      obj.file_name ||
      obj.sha256
    );

  const normalizeMediaNode = (node, fallbackCaption = null) => ({
    ...node,
    caption: node?.caption || fallbackCaption || null
  });

  const tryNormalizeFromNode = (node, fallbackCaption = null, fallbackType = "document") => {
    if (!hasMediaPayload(node)) return null;
    return {
      ...(typeof msg === "object" ? msg : {}),
      type: msg?.type || fallbackType,
      [fallbackType]: normalizeMediaNode(node, fallbackCaption || msg?.caption || null)
    };
  };

  const directType = String(msg.type || "").toLowerCase();
  if (knownTypes.includes(directType)) {
    const directNode = msg[directType];
    if (hasMediaPayload(directNode)) {
      return {
        ...msg,
        [directType]: normalizeMediaNode(directNode, msg.caption || null)
      };
    }
    if (hasMediaPayload(msg)) {
      return {
        ...msg,
        [directType]: normalizeMediaNode(msg, msg.caption || null)
      };
    }
  }

  for (const t of knownTypes) {
    if (hasMediaPayload(msg[t])) {
      return {
        ...msg,
        type: msg.type || t,
        [t]: normalizeMediaNode(msg[t], msg.caption || null)
      };
    }
  }

  const rootAsDocument = tryNormalizeFromNode(
    msg,
    msg.caption || null,
    "document"
  );
  if (rootAsDocument) return rootAsDocument;

  const nested = msg.media && typeof msg.media === "object" ? msg.media : null;
  const nestedType = String(nested?.type || "").toLowerCase();
  if (nested && knownTypes.includes(nestedType)) {
    const nestedNode = nested[nestedType] && typeof nested[nestedType] === "object"
      ? nested[nestedType]
      : nested;
    if (hasMediaPayload(nestedNode)) {
      return {
        ...msg,
        type: nestedType,
        [nestedType]: normalizeMediaNode(nestedNode, msg.caption || nested.caption || null)
      };
    }
  }

  for (const t of knownTypes) {
    const candidate =
      (nested && nested[t] && typeof nested[t] === "object" ? nested[t] : null) ||
      (msg.payload && typeof msg.payload === "object" && msg.payload[t] && typeof msg.payload[t] === "object" ? msg.payload[t] : null);

    if (hasMediaPayload(candidate)) {
      return {
        ...msg,
        type: t,
        [t]: normalizeMediaNode(candidate, msg.caption || nested?.caption || null)
      };
    }
  }

  const wrapperCandidatesRaw = [
    msg.media,
    msg.payload,
    msg.message,
    msg.msg,
    msg.data,
    msg.value,
    msg.value?.message,
    msg.value?.messages?.[0],
    msg.entry?.[0]?.changes?.[0]?.value,
    msg.entry?.[0]?.changes?.[0]?.value?.messages?.[0]
  ].filter((candidate) => candidate && typeof candidate === "object");

  const wrapperCandidates = [];
  const wrapperSeen = new Set();
  for (const candidate of wrapperCandidatesRaw) {
    if (wrapperSeen.has(candidate)) continue;
    wrapperSeen.add(candidate);
    wrapperCandidates.push(candidate);
  }

  for (const wrapper of wrapperCandidates) {
    const normalizedWrapper = normalizeEnvioDocsIncomingMedia(wrapper, seen);
    if (
      normalizedWrapper &&
      typeof normalizedWrapper === "object" &&
      (
        normalizedWrapper.image ||
        normalizedWrapper.audio ||
        normalizedWrapper.document ||
        normalizedWrapper.video
      )
    ) {
      return {
        ...msg,
        ...normalizedWrapper,
        caption:
          normalizedWrapper.caption ||
          msg.caption ||
          wrapper.caption ||
          null
      };
    }
  }

  return msg;
}

// ======================================================================
// ÞÏÝ BLOCO 19 ã ROTEADOR DE MûDIA PARA DOCUMENTOS (FINAL MASTER)
// ======================================================================

/**
 * handleDocumentUpload(env, st, msg)
 *
 * - Detecta envio de arquivo/mûÙdia no contexto de docs
 * - Associa ao item mais provûÀvel do checklist (sem validaûÏûÈo profunda)
 * - Marca como recebido_pendente_validacao
 * - Recalcula status geral da pasta (aguardando_envio/parcial/completo)
 * - Retorna mensagem humanizada mantendo etapa envio_docs
 */
async function handleDocumentUpload(env, st, msg, options = {}) {
  try {
    const silent = options?.silent === true;
    const normalizedMsg = normalizeEnvioDocsIncomingMedia(msg);
    const stage = st?.fase_conversa || "envio_docs";
    // ==========================================================
    // 1 ã DETECTAR TIPO DE ARQUIVO VINDO DO WHATSAPP
    // ==========================================================
    const mediaObject =
      normalizedMsg?.image || normalizedMsg?.audio || normalizedMsg?.document || normalizedMsg?.video || null;
    const isTextSignal = normalizedMsg?.text_signal === true;

    if (!mediaObject && !isTextSignal) {
      const safePreview = (() => {
        if (typeof msg === "string") return msg.slice(0, 400);
        try {
          return JSON.stringify(msg).slice(0, 400);
        } catch {
          return String(msg).slice(0, 400);
        }
      })();

      await telemetry(env, {
        wa_id: st.wa_id,
        event: "envio_docs_media_shape_unrecognized",
        stage: st.fase_conversa || "envio_docs",
        severity: "warning",
        force: true,
        message: "Shape de mûÙdia nûÈo reconhecido em envio_docs",
        details: {
          original_msg_type: msg?.type || typeof msg,
          normalized_type: normalizedMsg?.type || typeof normalizedMsg,
          keys_root: normalizedMsg && typeof normalizedMsg === "object" ? Object.keys(normalizedMsg).slice(0, 30) : [],
          keys_media: normalizedMsg?.media && typeof normalizedMsg.media === "object" ? Object.keys(normalizedMsg.media).slice(0, 30) : [],
          keys_payload: normalizedMsg?.payload && typeof normalizedMsg.payload === "object" ? Object.keys(normalizedMsg.payload).slice(0, 30) : [],
          has_document: !!normalizedMsg?.document,
          has_image: !!normalizedMsg?.image,
          has_audio: !!normalizedMsg?.audio,
          has_video: !!normalizedMsg?.video,
          preview_string_truncated: safePreview
        }
      });

      return {
        ok: false,
        message: [
          "NûÈo consegui identificar o arquivo Þ",
          "Pode tentar enviar novamente?"
        ],
        keepStage: "envio_docs"
      };
    }

    const mediaCaption =
      normalizedMsg?.document?.caption ||
      normalizedMsg?.image?.caption ||
      normalizedMsg?.caption ||
      "";
    const hintText = mediaCaption;
    const itensBase = Array.isArray(st.envio_docs_itens_json) && st.envio_docs_itens_json.length
      ? [...st.envio_docs_itens_json]
      : generateChecklistForDocs(st);
    const itens = reconcileEnvioDocsItensWithSavedDossier(st, itensBase);
    // Sync in-memory state so downstream functions (matchEnvioDocsClassificationToChecklist,
    // selectEnvioDocsItemForUpload) see the generated/reconciled checklist when reading
    // st.envio_docs_itens_json directly ã prevents empty-checklist false "no_pending_item" matches.
    st.envio_docs_itens_json = itens;
    const pendingUpload = (
      st?.envio_docs_ultimo_upload_pendente_confirmacao_json &&
      typeof st.envio_docs_ultimo_upload_pendente_confirmacao_json === "object"
    )
      ? st.envio_docs_ultimo_upload_pendente_confirmacao_json
      : decodeEnvioDocsLegacyPendingConfirmation(st);

    if (isTextSignal) {
      const progressAtual = recomputeEnvioDocsProgress(itens);
      const hasPendingConfirmation = isEnvioDocsAwaitingTypeConfirmation(st);
      if (!hasPendingConfirmation || !pendingUpload) {
        return {
          ok: true,
          message: [
            "Recebi sua mensagem, mas por texto sozinho eu nûÈo consigo classificar documento agora.",
            ...buildEnvioDocsUploadGuidanceLines(itens, progressAtual)
          ],
          keepStage: "envio_docs"
        };
      }

      const uploadId = String(pendingUpload?.upload_id || "").trim() || null;
      const alreadyConfirmed = false;
      const immediatelyAfterUpload =
        !!pendingUpload?.upload_message_id &&
        !!st?.last_message_id_prev &&
        String(st.last_message_id_prev) === String(pendingUpload.upload_message_id);

      if (alreadyConfirmed) {
        return {
          ok: true,
          message: [
            "Esse û¤ltimo arquivo jûÀ foi confirmado aqui ã",
            ...buildEnvioDocsUploadGuidanceLines(itens, progressAtual)
          ],
          keepStage: "envio_docs"
        };
      }

      if (!immediatelyAfterUpload) {
        return {
          ok: true,
          message: [
            "Pra eu confirmar o tipo por texto, essa resposta precisa vir logo depois do arquivo pendente.",
            "Se preferir, pode reenviar o arquivo com a legenda do documento."
          ],
          keepStage: "envio_docs"
        };
      }

      const confirmationResolution = resolveEnvioDocsPendingConfirmationTargetFromText(
        st,
        pendingUpload,
        hintText || normalizedMsg?.caption || ""
      );
      if (!confirmationResolution.ok || !confirmationResolution.target) {
        const alreadyAskedSameUpload = false;
        return {
          ok: true,
          message: alreadyAskedSameUpload
            ? [
                "Ainda preciso que vocûˆ me diga qual ûˋ o û¤ltimo arquivo enviado.",
                "Pode responder curto, por exemplo: *holerite*, *RG*, *CPF* ou *comprovante de residûˆncia*."
              ]
            : [pendingUpload?.pergunta_confirmacao || buildEnvioDocsPendingConfirmationQuestion(pendingUpload)],
          keepStage: "envio_docs"
        };
      }

      const targetConfirmedByText = confirmationResolution.target;
      const idxConfirmedByText = itens.findIndex((item) =>
        item.tipo === targetConfirmedByText?.tipo &&
        item.participante === targetConfirmedByText?.participante &&
        !isEnvioDocsItemReceived(item)
      );
      if (idxConfirmedByText >= 0) {
        itens[idxConfirmedByText] = {
          ...itens[idxConfirmedByText],
          status: "recebido_pendente_validacao",
          recebido_em: new Date().toISOString(),
          validacao_basica_em: new Date().toISOString(),
          validacao_basica_motivo: "confirmacao_textual_tipo_doc"
        };
      }

      // ãã Persist confirmed upload to enova_docs + update in-memory historico ãã
      if (idxConfirmedByText >= 0) {
        const _cMediaRef = pendingUpload?.media_ref && typeof pendingUpload.media_ref === "object" ? pendingUpload.media_ref : {};
        const _cMetaVer = String(env?.META_API_VERSION || "v20.0");
        const _cResolvedUrl = String(
          _cMediaRef?.url || _cMediaRef?.link ||
          _cMediaRef?.document_url || _cMediaRef?.download_url ||
          _cMediaRef?.media_url || ""
        ).trim() || (_cMediaRef?.media_id ? `https://graph.facebook.com/${_cMetaVer}/${_cMediaRef.media_id}` : null);
        const _cUploadMediaRef = {
          media_id: _cMediaRef?.media_id || null,
          mime_type: _cMediaRef?.mime_type || null,
          file_name: _cMediaRef?.file_name || null,
          url: _cResolvedUrl
        };
        const _cUpdatedHistorico = Array.isArray(st?.envio_docs_historico_json) ? [...st.envio_docs_historico_json] : [];
        _cUpdatedHistorico.push({
          origem: "confirmacao_textual",
          at: new Date().toISOString(),
          associado: { tipo: targetConfirmedByText?.tipo || null, participante: targetConfirmedByText?.participante || null },
          media_ref: _cUploadMediaRef
        });
        st.envio_docs_historico_json = _cUpdatedHistorico;
        if (_cResolvedUrl) {
          const _cTipo = String(targetConfirmedByText?.tipo || "").trim();
          const _cParticipante = String(targetConfirmedByText?.participante || "").trim();
          const _cSavePayload = {
            participante: targetConfirmedByText?.participante || null,
            tipo: targetConfirmedByText?.tipo || null,
            url: _cResolvedUrl,
            created_at: new Date().toISOString()
          };
          let _cAlreadySaved = false;
          let _cPrecheckFailed = false;
          if (_cTipo && _cParticipante && st?.wa_id) {
            const _cPrecheckQuery = {
              select: "id",
              wa_id: `eq.${st.wa_id}`,
              tipo: `eq.${encodeURIComponent(_cTipo)}`,
              participante: `eq.${encodeURIComponent(_cParticipante)}`,
              url: `eq.${encodeURIComponent(_cResolvedUrl)}`,
              limit: 1
            };
            try {
              const _cExistingRows = normalizeSupabaseRows(await sbFetch(env, "/rest/v1/enova_docs", {
                method: "GET",
                query: _cPrecheckQuery
              }));
              _cAlreadySaved = _cExistingRows.length > 0;
            } catch (_e) {
              _cPrecheckFailed = true;
              const _cErrorDebug = getSupabaseErrorDebugInfo(_e);
              console.error("handleDocumentUpload: enova_docs precheck failed", {
                wa_id: st?.wa_id,
                tipo: targetConfirmedByText?.tipo,
                participante: targetConfirmedByText?.participante,
                phase: "precheck",
                query: _cPrecheckQuery,
                ..._cErrorDebug
              });
            }
          }
          if (!_cPrecheckFailed && !_cAlreadySaved) {
            try {
              await saveDocumentToSupabase(env, st.wa_id, _cSavePayload);
            } catch (_e) {
              const _cErrorDebug = getSupabaseErrorDebugInfo(_e);
              console.error("handleDocumentUpload: enova_docs insert failed", {
                wa_id: st?.wa_id,
                tipo: targetConfirmedByText?.tipo,
                participante: targetConfirmedByText?.participante,
                phase: "insert",
                payload: _e?.enova_docs_payload || { ..._cSavePayload, wa_id: st?.wa_id || null },
                ..._cErrorDebug
              });
            }
          }
        }
      }

      const progress = recomputeEnvioDocsProgress(itens);
      const pendingClearedState = {
        ...st,
        ...clearEnvioDocsPendingTypeConfirmationPatch({
          fase_docs: "envio_documentos"
        })
      };
      const plausiveisPendentes = buildEnvioDocsPlausiveisPendentesConferenciaFromState(pendingClearedState);
      const patch = {
        ...progress,
        ...clearEnvioDocsPendingTypeConfirmationPatch({
          fase_docs: "envio_documentos",
          docs_status_texto: null
        })
      };
      let analisePayload = null;
      if (progress.envio_docs_status === "completo" || plausiveisPendentes.length > 0) {
        analisePayload = buildAnaliseDocsPayloadFromEnvio(itens, { plausiveisPendentes });
      }
      const pacotePayload = buildPacoteCorrespondentePayloadFromState({ ...st, ...patch }, itens, analisePayload);
      const legacyResumoPatch = buildEnvioDocsLegacySummaryPatch(itens, progress, {
        isPendingConfirmation: false
      });
      const analiseStatusLegacy = mapAnaliseDocsStatusToLegacyStatus(analisePayload?.analise_docs_status);
      if (analiseStatusLegacy) {
        legacyResumoPatch.docs_status_geral = analiseStatusLegacy;
      }
      Object.assign(patch, legacyResumoPatch, pickEnvioDocsPersistedPacotePatch(pacotePayload));
      patch.envio_docs_itens_json = itens;
      await upsertState(env, st.wa_id, patch);
      Object.assign(st, patch, {
        envio_docs_itens_json: itens,
        analise_docs_status: analisePayload?.analise_docs_status || null,
        pacote_status: pacotePayload?.pacote_status || st?.pacote_status || null
      });

      return {
        ok: true,
        message: [
          "Perfeito, confirmei o tipo do û¤ltimo arquivo e atualizei sua pasta ã",
          ...buildEnvioDocsUploadGuidanceLines(itens, progress)
        ],
        keepStage: "envio_docs"
      };
    }

    const aiSourceType = normalizedMsg?.image
      ? "image"
      : (
          String(mediaObject?.mime_type || "").toLowerCase() === "application/pdf" ||
          /\.pdf$/i.test(String(mediaObject?.filename || mediaObject?.file_name || ""))
        )
        ? "pdf"
        : "document";
    const sourceType = normalizedMsg?.image
      ? "image"
      : normalizedMsg?.document
        ? "document"
        : normalizedMsg?.audio
          ? "audio"
          : normalizedMsg?.video
            ? "video"
            : null;
    const shouldRunDocumentExtract = mediaObject && (normalizedMsg?.image || normalizedMsg?.document);
    const isPdf = shouldRunDocumentExtract && aiSourceType === "pdf";
    if (isPdf) {
      const buildStamp = String(typeof ENOVA_BUILD === "string" ? ENOVA_BUILD : "").trim() || null;
      await telemetry(env, {
        wa_id: st?.wa_id || null,
        event: "envio_docs_pdf_input_debug",
        stage,
        severity: "info",
        force: true,
        message: "PDF input debug",
        details: {
          wa_id: st?.wa_id || null,
          stage,
          msg_type: normalizedMsg?.type || msg?.type || null,
          mime_type: mediaObject?.mime_type || null,
          filename: mediaObject?.filename || mediaObject?.file_name || null,
          media_id: mediaObject?.id || null,
          source_type: aiSourceType || null,
          is_pdf: true,
          build_stamp: buildStamp
        }
      });
    }
    if (shouldRunDocumentExtract) {
      await telemetry(env, {
        wa_id: st?.wa_id || null,
        event: "envio_docs_doc_ai_callsite_before_extract",
        stage: "envio_docs",
        severity: "info",
        force: true,
        message: "DEBUG callsite antes da extraûÏûÈo documental",
        details: {
          wa_id: st?.wa_id || null,
          source_type: sourceType,
          mime_type: mediaObject?.mime_type || null,
          file_name: mediaObject?.filename || mediaObject?.file_name || null,
          has_media_object: !!mediaObject,
          document_upload_path_active: true
        }
      });
    }
    const documentAiSignals = shouldRunDocumentExtract
      ? await extractEnvioDocsSignals(env, mediaObject, {
          sourceType: aiSourceType,
          wa_id: st?.wa_id || null,
          mime_type: mediaObject?.mime_type || null,
          file_name: mediaObject?.filename || mediaObject?.file_name || null,
          fetchImpl: options?.fetchImpl
        })
      : null;
    if (isPdf) {
      const extractedTextRaw = String(
        documentAiSignals?.extracted_text_full ||
        documentAiSignals?.extracted_text_preview ||
        ""
      );
      const hintSupportText = normalizeText(
        `${hintText || ""} ${mediaObject?.filename || mediaObject?.file_name || ""} ${mediaCaption || ""}`
      );
      const signalsJsonObj = documentAiSignals?.signals_json && typeof documentAiSignals.signals_json === "object"
        ? documentAiSignals.signals_json
        : null;
      const signalsJsonSize = signalsJsonObj ? Object.keys(signalsJsonObj).length : 0;
      await telemetry(env, {
        wa_id: st?.wa_id || null,
        event: "envio_docs_pdf_ocr_result_debug",
        stage,
        severity: "info",
        force: true,
        message: "PDF OCR result debug",
        details: {
          wa_id: st?.wa_id || null,
          is_pdf: true,
          extraction_ok: documentAiSignals?.extraction_ok === true,
          error_code: documentAiSignals?.extraction_error_code || null,
          text_length: extractedTextRaw.length,
          text_preview: extractedTextRaw ? maskEnvioDocsExtractPreview(extractedTextRaw, 220) : null,
          hint_support_length: hintSupportText.length,
          has_signals_json: signalsJsonSize > 0,
          source_type: documentAiSignals?.source_type || aiSourceType || null
        }
      });
    }
    if (shouldRunDocumentExtract) {
      const extractedTextRaw =
        String(documentAiSignals?.extracted_text_full || documentAiSignals?.extracted_text_preview || "");
      const extractedTextNormalized = normalizeText(extractedTextRaw);
      await telemetry(env, {
        wa_id: st?.wa_id || null,
        event: "envio_docs_doc_ai_callsite_after_extract",
        stage: "envio_docs",
        severity: "info",
        force: true,
        message: "DEBUG callsite apû°s extraûÏûÈo documental",
        details: {
          wa_id: st?.wa_id || null,
          file_name: mediaObject?.filename || mediaObject?.file_name || null,
          mime_type: mediaObject?.mime_type || null,
          text_length: extractedTextRaw.length,
          text_preview_masked: maskEnvioDocsExtractPreview(extractedTextRaw, 300),
          has_text: extractedTextNormalized.length >= 20,
          doc_type_hints: Array.isArray(documentAiSignals?.signals_json?.doc_type_hints) ? documentAiSignals.signals_json.doc_type_hints : [],
          participant_hints: Array.isArray(documentAiSignals?.signals_json?.participant_hints) ? documentAiSignals.signals_json.participant_hints : [],
          keyword_density: Number(documentAiSignals?.signals_json?.keyword_density || 0) || 0,
          extraction_source: documentAiSignals?.extraction_source || null,
          extraction_ok: documentAiSignals?.extraction_ok === true
        }
      });
    }
    const documentClassification = classifyEnvioDocsDocument(documentAiSignals, st, {
      wa_id: st?.wa_id || null,
      hintText,
      caption: mediaCaption,
      fileName: mediaObject?.filename || mediaObject?.file_name || "",
      mimeType: mediaObject?.mime_type || ""
    });
    if (isPdf) {
      const detectedSignals = documentClassification?.detected_signals_json && typeof documentClassification.detected_signals_json === "object"
        ? documentClassification.detected_signals_json
        : {};
      const textScores = detectedSignals?.text_scores && typeof detectedSignals.text_scores === "object" ? detectedSignals.text_scores : {};
      const signalScores = detectedSignals?.signal_scores && typeof detectedSignals.signal_scores === "object" ? detectedSignals.signal_scores : {};
      const supportScores = detectedSignals?.support_scores && typeof detectedSignals.support_scores === "object" ? detectedSignals.support_scores : {};
      const scoring = scoreEnvioDocsDocumentClassification({ textScores, signalScores, supportScores });
      const textStrongTypes = Object.entries(textScores)
        .filter(([, score]) => Number(score) >= 0.95)
        .map(([tipo]) => tipo);
      const hasTextConflict =
        textStrongTypes.length > 1 &&
        !textStrongTypes.every((tipo) => ENVIO_DOCS_TIPOS_ALVO_RENDA_RESIDENCIA.includes(String(tipo || "").trim().toLowerCase()));
      const blockedByThreshold = Number(scoring?.topScore || 0) < 0.45;
      const blockedByConflict = hasTextConflict || scoring?.hasRelevantConflict === true;
      const topType = scoring?.topType || null;
      const topTextScore = Number(textScores?.[topType] || 0);
      const topSignalScore = Number(signalScores?.[topType] || 0);
      const topSupportScore = Number(supportScores?.[topType] || 0);
      const topReasonLabels = [
        topTextScore > 0 ? "text" : null,
        topSignalScore > 0 ? "signal" : null,
        topSupportScore > 0 ? "support" : null
      ].filter(Boolean);
      const ctpsScoreRaw = scoring?.totals && Number.isFinite(Number(scoring.totals.ctps_completa))
        ? Number(scoring.totals.ctps_completa)
        : null;
      const cnhOrIdentityCandidates = [
        scoring?.totals?.cnh,
        scoring?.totals?.rg_com_cpf,
        scoring?.totals?.rg
      ]
        .map((value) => Number(value))
        .filter((value) => Number.isFinite(value));
      const cnhOrIdentityScore = cnhOrIdentityCandidates.length ? Math.max(...cnhOrIdentityCandidates) : null;
      await telemetry(env, {
        wa_id: st?.wa_id || null,
        event: "envio_docs_pdf_classification_debug",
        stage,
        severity: "info",
        force: true,
        message: "PDF classification debug",
        details: {
          wa_id: st?.wa_id || null,
          detected_doc_type: topType || null,
          detected_doc_category: topType ? (envioDocsCategoriaFromTipo(topType) || null) : null,
          top_score: Number(scoring?.topScore || 0),
          second_score: Number(scoring?.secondScore || 0),
          blocked_by_threshold: blockedByThreshold,
          blocked_by_conflict: blockedByConflict,
          ctps_score: ctpsScoreRaw,
          cnh_or_identity_score: cnhOrIdentityScore,
          top_reason_labels: topReasonLabels
        }
      });
    }
    if (shouldRunDocumentExtract) {
      await telemetry(env, {
        wa_id: st?.wa_id || null,
        event: "envio_docs_doc_ai_callsite_after_classify",
        stage: "envio_docs",
        severity: "info",
        force: true,
        message: "DEBUG callsite apû°s classificaûÏûÈo documental",
        details: {
          wa_id: st?.wa_id || null,
          file_name: mediaObject?.filename || mediaObject?.file_name || null,
          mime_type: mediaObject?.mime_type || null,
          detected_doc_type: documentClassification?.detected_doc_type || null,
          confidence: Number(documentClassification?.classification_confidence || 0) || 0,
          reason: documentClassification?.classification_reason || null,
          error_code: documentClassification?.classification_error_code || null,
          error_message: documentClassification?.classification_error_message || null,
          participant: documentClassification?.detected_participant || null,
          covers_checklist_types: Array.isArray(documentClassification?.covers_checklist_types) ? documentClassification.covers_checklist_types : [],
          recognition_source: documentClassification?.recognition_source || "document_engine"
        }
      });
    }
    const participantInference = inferEnvioDocsParticipantFromSignals(documentClassification, documentAiSignals, st, {
      hintText,
      caption: normalizedMsg?.document?.caption || normalizedMsg?.image?.caption || normalizedMsg?.caption || "",
      fileName: mediaObject?.filename || mediaObject?.file_name || ""
    });
    const checklistMatch = matchEnvioDocsClassificationToChecklist(documentClassification, participantInference, st, {
      documentAiSignals,
      hintText,
      fileName: mediaObject?.filename || mediaObject?.file_name || ""
    });
    const engineResolution = resolveEnvioDocsTargetFromDocumentEngine(itens, checklistMatch, documentClassification);
    const fallbackAllowed = checklistMatch?.match_status !== "matched_safe" || !engineResolution.item;
    const selection = fallbackAllowed
      ? selectEnvioDocsItemForUpload(st, {
          hintText,
          fileName: mediaObject?.filename || mediaObject?.file_name || "",
          mimeType: mediaObject?.mime_type || ""
        })
      : { item: null, items: [], debug: {} };
    const selectionDebug = selection?.debug || {};
    const finalTargetDecision = chooseEnvioDocsFinalTarget({
      itens,
      checklistMatch,
      documentClassification,
      engineResolution,
      legacySelection: selection
    });
    const target = finalTargetDecision.target || null;
    const matchedItemsRaw = Array.isArray(finalTargetDecision.matchedItems)
      ? finalTargetDecision.matchedItems
      : (target ? [target] : []);
    const matchedItems = normalizeEnvioDocsMatchedItems(matchedItemsRaw);
    const finalTargetSource = finalTargetDecision.finalTargetSource || "none";
    const fallbackUsed = finalTargetDecision.fallbackUsed === true;
    const recognitionSource = finalTargetSource === "document_engine"
      ? "document_engine"
      : finalTargetSource === "recommended_ctps"
        ? "recommended_ctps"
      : (fallbackUsed ? "legacy_fallback" : "none");
    const expectedPendingItemsBefore = Array.isArray(selectionDebug.expected_pending_items_before) ? selectionDebug.expected_pending_items_before : [];
    const targetResolutionBuildStamp = String(typeof ENOVA_BUILD === "string" ? ENOVA_BUILD : "").trim() || null;
    const targetResolutionGitCommitHint = getRuntimeGitCommitHint(env);
    const targetResolutionLogicalBranchExecuted = finalTargetSource === "document_engine"
      ? "document_engine_matched_safe"
      : finalTargetSource === "recommended_ctps"
        ? "recommended_ctps_applied"
        : finalTargetSource === "legacy_fallback"
          ? "legacy_fallback_selected"
          : "none_selected";
    const recommendedCtpsRuleEvaluated = finalTargetDecision?.recommendedCtpsRuleEvaluated === true;
    const recommendedCtpsRuleHit = Boolean(finalTargetDecision?.recommendedCtpsResolution?.item);
    const recommendedCtpsRuleApplied = finalTargetSource === "recommended_ctps";
    if (isPdf) {
      const finalDetectedDocType = documentClassification?.detected_doc_type || null;
      const becameNaoIdentificado = finalDetectedDocType === "nao_identificado";
      const failureReason = becameNaoIdentificado
        ? (
            documentClassification?.classification_error_code ||
            documentClassification?.classification_reason ||
            "nao_identificado"
          )
        : (
            target
              ? null
              : (
                  checklistMatch?.match_reason ||
                  finalTargetDecision?.reason ||
                  "sem_target"
                )
          );
      await telemetry(env, {
        wa_id: st?.wa_id || null,
        event: "envio_docs_pdf_final_decision_debug",
        stage,
        severity: "info",
        force: true,
        message: "PDF final decision debug",
        details: {
          wa_id: st?.wa_id || null,
          final_detected_doc_type: finalDetectedDocType,
          final_target_source: finalTargetSource || null,
          final_target_participant: target?.participante || null,
          final_target_doc_key: target?.tipo || null,
          failure_reason: failureReason,
          became_nao_identificado: becameNaoIdentificado
        }
      });
    }

    await telemetry(env, {
      wa_id: st.wa_id,
      event: "envio_docs_media_debug_pre_validation",
      stage: st.fase_conversa || "envio_docs",
      severity: "info",
      force: true,
      message: "DEBUG prûˋ-validaûÏûÈo de mûÙdia recebida no envio_docs",
      details: {
        source_type: normalizedMsg?.image ? "image" : normalizedMsg?.document ? "document" : normalizedMsg?.audio ? "audio" : normalizedMsg?.video ? "video" : null,
        raw_type: normalizedMsg?.type || null,
        mime_type: mediaObject?.mime_type || null,
        filename: mediaObject?.filename || mediaObject?.file_name || null,
        file_size: mediaObject?.file_size ?? null,
        size: mediaObject?.size ?? null,
        bytes: mediaObject?.bytes ?? null,
        width: mediaObject?.width ?? null,
        height: mediaObject?.height ?? null,
        media_id: mediaObject?.id || null,
        caption: normalizedMsg?.document?.caption || normalizedMsg?.image?.caption || normalizedMsg?.caption || null,
        target_tipo: target?.tipo || null,
        target_participante: target?.participante || null,
        hinted_tipo_raw: selectionDebug.hinted_tipo_raw || null,
        hinted_tipo_normalized: selectionDebug.hinted_tipo_normalized || null,
        detected_doc_type: selectionDebug.detected_doc_type || null,
        covers_checklist_types: Array.isArray(selectionDebug.covers_checklist_types) ? selectionDebug.covers_checklist_types : [],
        detected_participant: selectionDebug.detected_participant || null,
        matched_item_tipo: selectionDebug.matched_item_tipo || null,
        matched_item_participante: selectionDebug.matched_item_participante || null,
        matched_checklist_items: Array.isArray(selectionDebug.matched_checklist_items) ? selectionDebug.matched_checklist_items : [],
        expected_pending_items_before: expectedPendingItemsBefore,
        document_ai_extraction_ok: documentAiSignals?.extraction_ok === true,
        document_ai_error_code: documentAiSignals?.extraction_error_code || null,
        document_ai_signal_density: Number(documentAiSignals?.signals_json?.keyword_density || 0) || 0,
        document_classification_type: documentClassification?.detected_doc_type || null,
        document_classification_category: documentClassification?.detected_doc_category || null,
        document_classification_confidence: Number(documentClassification?.classification_confidence || 0) || 0,
        document_classification_ok: documentClassification?.classification_ok === true,
        document_classification_error_code: documentClassification?.classification_error_code || null,
        participant_inference_detected: participantInference?.detected_participant || null,
        participant_inference_confidence: Number(participantInference?.participant_confidence || 0) || 0,
        participant_inference_ok: participantInference?.participant_inference_ok === true,
        participant_inference_error_code: participantInference?.participant_inference_error_code || null,
        checklist_match_status: checklistMatch?.match_status || null,
        checklist_match_confidence: Number(checklistMatch?.match_confidence || 0) || 0,
        checklist_match_reason: checklistMatch?.match_reason || null,
        checklist_match_item_ids: Array.isArray(checklistMatch?.matched_item_ids) ? checklistMatch.matched_item_ids : [],
        checklist_match_ok: checklistMatch?.checklist_match_ok === true,
        checklist_match_error_code: checklistMatch?.checklist_match_error_code || null,
        fallback_used: fallbackUsed,
        final_target_source: finalTargetSource,
        recognition_source: recognitionSource
      }
    });

    const validation = classifyEnvioDocsBasicValidation({
      mediaObject,
      normalizedMsg,
      target,
      hintText
    });
    const pendingConfirmationCandidates = resolveEnvioDocsPendingConfirmationCandidateItems({
      itens,
      checklistMatch,
      selection,
      documentClassification
    });
    const orchestrationStatus = normalizeEnvioDocsUploadSemanticStatus(resolveEnvioDocsUploadSemanticStatus({
      matchedItems,
      validation,
      documentClassification,
      checklistMatch,
      selectionDebug,
      candidateItems: pendingConfirmationCandidates
    }));
    const uploadPendingConfirmation = orchestrationStatus === "plausivel_incerto";
    const pendingConfirmationRecord = uploadPendingConfirmation
      ? buildEnvioDocsPendingConfirmationRecord({
          st,
          normalizedMsg,
          mediaObject,
          checklistMatch,
          selection,
          participantInference,
          documentClassification,
          recognitionSource,
          itens
        })
      : null;

    if (!uploadPendingConfirmation) {
      for (const matched of matchedItems) {
        const idx = itens.findIndex((item) =>
          item.tipo === matched?.tipo &&
          item.participante === matched?.participante &&
          !isEnvioDocsItemReceived(item)
        );
        if (idx >= 0) {
          itens[idx] = {
            ...itens[idx],
            status: validation.status,
            recebido_em: new Date().toISOString(),
            validacao_basica_em: new Date().toISOString(),
            validacao_basica_motivo: validation.reason
          };
        }
      }

      // ãã Persist upload to enova_docs + update in-memory historico ãã
      if (matchedItems.length > 0 && mediaObject) {
        const _metaVer = String(env?.META_API_VERSION || "v20.0");
        const _resolvedUrl = String(
          mediaObject?.url || mediaObject?.link ||
          mediaObject?.document_url || mediaObject?.download_url ||
          mediaObject?.media_url || ""
        ).trim() || (mediaObject?.id ? `https://graph.facebook.com/${_metaVer}/${mediaObject.id}` : null);
        const _uploadMediaRef = {
          media_id: mediaObject?.id || null,
          mime_type: mediaObject?.mime_type || null,
          file_name: mediaObject?.filename || mediaObject?.file_name || null,
          url: _resolvedUrl
        };
        const _updatedHistorico = Array.isArray(st?.envio_docs_historico_json) ? [...st.envio_docs_historico_json] : [];
        for (const matched of matchedItems) {
          _updatedHistorico.push({
            origem: "upload",
            at: new Date().toISOString(),
            associado: { tipo: matched?.tipo || null, participante: matched?.participante || null },
            media_ref: _uploadMediaRef
          });
          if (_resolvedUrl) {
            const _tipo = String(matched?.tipo || "").trim();
            const _participante = String(matched?.participante || "").trim();
            const _savePayload = {
              participante: matched?.participante || null,
              tipo: matched?.tipo || null,
              url: _resolvedUrl,
              created_at: new Date().toISOString()
            };
            let _alreadySaved = false;
            let _precheckFailed = false;
            if (_tipo && _participante && st?.wa_id) {
              const _precheckQuery = {
                select: "id",
                wa_id: `eq.${st.wa_id}`,
                tipo: `eq.${encodeURIComponent(_tipo)}`,
                participante: `eq.${encodeURIComponent(_participante)}`,
                url: `eq.${encodeURIComponent(_resolvedUrl)}`,
                limit: 1
              };
              try {
                const _existingRows = normalizeSupabaseRows(await sbFetch(env, "/rest/v1/enova_docs", {
                  method: "GET",
                  query: _precheckQuery
                }));
                _alreadySaved = _existingRows.length > 0;
              } catch (_e) {
                _precheckFailed = true;
                const _errorDebug = getSupabaseErrorDebugInfo(_e);
                console.error("handleDocumentUpload: enova_docs precheck failed", {
                  wa_id: st?.wa_id,
                  tipo: matched?.tipo,
                  participante: matched?.participante,
                  phase: "precheck",
                  query: _precheckQuery,
                  ..._errorDebug
                });
              }
            }
            if (!_precheckFailed && !_alreadySaved) {
              try {
                await saveDocumentToSupabase(env, st.wa_id, _savePayload);
              } catch (_e) {
                const _errorDebug = getSupabaseErrorDebugInfo(_e);
                console.error("handleDocumentUpload: enova_docs insert failed", {
                  wa_id: st?.wa_id,
                  tipo: matched?.tipo,
                  participante: matched?.participante,
                  phase: "insert",
                  payload: _e?.enova_docs_payload || { ..._savePayload, wa_id: st?.wa_id || null },
                  ..._errorDebug
                });
              }
            }
          }
        }
        st.envio_docs_historico_json = _updatedHistorico;
      }
    }

    const progress = recomputeEnvioDocsProgress(itens);
    const expectedPendingItemsAfter = itens
      .filter((item) => isEnvioDocsBlockingItem(item) && !isEnvioDocsItemReceived(item))
      .map((item) => `${item.tipo}:${item.participante}`);
    const patch = {
      ...progress,
      ...(uploadPendingConfirmation
        ? {
            fase_docs: "aguardando_confirmacao_tipo_doc",
            docs_status_texto: encodeEnvioDocsLegacyPendingConfirmation(pendingConfirmationRecord)
          }
        : clearEnvioDocsPendingTypeConfirmationPatch({
            fase_docs: "envio_documentos",
            docs_status_texto: null
          }))
    };
    const plausiveisPendentes = buildEnvioDocsPlausiveisPendentesConferenciaFromState({ ...st, ...patch });
    let analisePayload = null;
    if (progress.envio_docs_status === "completo" || plausiveisPendentes.length > 0) {
      analisePayload = buildAnaliseDocsPayloadFromEnvio(itens, { plausiveisPendentes });
    }
    const pacotePayload = buildPacoteCorrespondentePayloadFromState({ ...st, ...patch }, itens, analisePayload);
    const legacyResumoPatch = buildEnvioDocsLegacySummaryPatch(itens, progress, {
      isPendingConfirmation: uploadPendingConfirmation,
      pendingConfirmationRecord
    });
    const analiseStatusLegacy = mapAnaliseDocsStatusToLegacyStatus(analisePayload?.analise_docs_status);
    if (analiseStatusLegacy) {
      legacyResumoPatch.docs_status_geral = analiseStatusLegacy;
    }
    Object.assign(patch, legacyResumoPatch, pickEnvioDocsPersistedPacotePatch(pacotePayload));
    patch.envio_docs_itens_json = itens;
    await upsertState(env, st.wa_id, patch);
    Object.assign(st, patch, {
      envio_docs_itens_json: itens,
      analise_docs_status: analisePayload?.analise_docs_status || null,
      pacote_status: pacotePayload?.pacote_status || st?.pacote_status || null
    });

    await telemetry(env, {
      wa_id: st.wa_id,
      event: "envio_docs_ctps_target_resolution_debug",
      stage: st.fase_conversa || "envio_docs",
      severity: "info",
      force: true,
      message: "DEBUG resoluûÏûÈo final de target CTPS no pû°s-match",
      details: {
        build_stamp: targetResolutionBuildStamp,
        runtime_guard_version: CTPS_TARGET_RUNTIME_GUARD_VERSION,
        git_commit_hint: targetResolutionGitCommitHint,
        resolution_path_guard: CTPS_RESOLUTION_PATH_GUARD,
        detected_doc_type_classification: documentClassification?.detected_doc_type || null,
        checklist_match_status: checklistMatch?.match_status || null,
        checklist_match_reason: checklistMatch?.match_reason || null,
        final_target_source: finalTargetSource,
        recognition_source: recognitionSource,
        logical_branch_executed: targetResolutionLogicalBranchExecuted,
        recommended_ctps_rule_evaluated: recommendedCtpsRuleEvaluated,
        recommended_ctps_rule_hit: recommendedCtpsRuleHit,
        recommended_ctps_rule_applied: recommendedCtpsRuleApplied,
        expected_pending_items_before: expectedPendingItemsBefore,
        expected_pending_items_after: expectedPendingItemsAfter
      }
    });

    await telemetry(env, {
      wa_id: st.wa_id,
      event: "envio_docs_media_debug_post_match",
      stage: st.fase_conversa || "envio_docs",
      severity: "info",
      force: true,
      message: "DEBUG pû°s-vûÙnculo de mûÙdia no envio_docs",
      details: {
        hinted_tipo_raw: selectionDebug.hinted_tipo_raw || null,
        hinted_tipo_normalized: selectionDebug.hinted_tipo_normalized || null,
        detected_doc_type: selectionDebug.detected_doc_type || null,
        covers_checklist_types: Array.isArray(selectionDebug.covers_checklist_types) ? selectionDebug.covers_checklist_types : [],
        detected_participant: selectionDebug.detected_participant || null,
        inferred_participant_document: participantInference?.detected_participant || null,
        checklist_match_status: checklistMatch?.match_status || null,
        checklist_match_confidence: Number(checklistMatch?.match_confidence || 0) || 0,
        checklist_match_reason: checklistMatch?.match_reason || null,
        checklist_match_item_ids: Array.isArray(checklistMatch?.matched_item_ids) ? checklistMatch.matched_item_ids : [],
        matched_item_tipo: target?.tipo || null,
        matched_item_participante: target?.participante || null,
        matched_checklist_items: mapEnvioDocsItemRefs(matchedItems),
        expected_pending_items_before: expectedPendingItemsBefore,
        expected_pending_items_after: expectedPendingItemsAfter,
        fallback_used: fallbackUsed,
        final_target_source: finalTargetSource,
        recognition_source: recognitionSource
      }
    });

    if (silent) {
      return {
        ok: true,
        silent: true,
        keepStage: "envio_docs",
        itemResult: {
          matchedItems: mapEnvioDocsItemRefs(matchedItems),
          validation,
          progress,
          selectionDebug,
          orchestrationStatus,
          pendingConfirmationRecord,
          documentAiSignals,
          documentClassification,
          participantInference,
          checklistMatch,
          expectedPendingItemsAfter
        }
      };
    }

    const linhas = ["Recebi seu arquivo e jûÀ registrei na sua pasta ã"];

    if (matchedItems.length) {
      const statusMensagens = {
        recebido_pendente_validacao: "recebido pendente de validaûÏûÈo",
        validado_basico: "validado bûÀsico",
        ilegivel: "ilegûÙvel",
        invalido: "invûÀlido",
        reenvio_solicitado: "reenvio solicitado"
      };
      const vinculados = [...new Set(matchedItems
        .map((matched) => `**${prettyDocLabel(matched.tipo)}** (${envioDocsParticipanteLabel(matched.participante)})`))];
      const statusTexto = statusMensagens[validation.status] || validation.status;
      if (matchedItems.length === 1) {
        linhas.push(`Vinculei como ${vinculados.join(", ")}, com status *${statusTexto}*.`);
      } else {
        linhas.push(`Vinculei como ${vinculados.join(", ")}, todos com status *${statusTexto}*.`);
      }
      if (validation.status === "ilegivel" || validation.status === "invalido" || validation.status === "reenvio_solicitado") {
        linhas.push("Se quiser, jûÀ pode reenviar esse documento com melhor qualidade/arquivo correto que eu atualizo aqui.");
      }
    } else if (uploadPendingConfirmation && pendingConfirmationRecord) {
      linhas.push(pendingConfirmationRecord.pergunta_confirmacao || buildEnvioDocsPendingConfirmationQuestion(pendingConfirmationRecord));
    } else if (orchestrationStatus === "incompativel") {
      linhas.push("Recebi o arquivo, mas ele nûÈo ficou compatûÙvel para classificar sua pendûˆncia.");
      linhas.push("Pode reenviar o documento correto ou com melhor qualidade?");
    } else {
      linhas.push("Registrei o recebimento e sigo com sua pasta; a validaûÏûÈo detalhada acontece na prû°xima etapa interna.");
    }

    if (!uploadPendingConfirmation) {
      linhas.push(...buildEnvioDocsUploadGuidanceLines(itens, progress));
    }

    return {
      ok: true,
      message: linhas,
      keepStage: "envio_docs"
    };

  } catch (err) {
    console.error("Erro handleDocumentUpload:", err);

    return {
      ok: false,
      message: [
        "OpaãÎ deu algum errinho aqui Þ",
        "Tenta me enviar o documento de novo, por favor?"
      ],
      keepStage: "envio_docs"
    };
  }
}

