  // Guarda: comissûÈo, hora extra e adicional NûO sûÈo renda mista ã pertencem û  leitura de renda formal fixa x variûÀvel.
  // "extra" isolado continua como gatilho, mas "hora extra" / "horas extras" puro sem marcador de renda por fora ûˋ excluûÙdo.
  const isHoraExtraOnly = /\bhoras?\s+extras?\b/i.test(t) && !/\b(bico|uber|ifood|freela|renda\s+extra|por\s+fora|informal)\b/i.test(t);
  const isComissaoOnly = /\b(comiss[aûÈ]o|adicional\s+noturno|adicional)\b/i.test(t) && !/\b(bico|uber|ifood|freela|renda\s+extra|por\s+fora|informal)\b/i.test(t);
  const sim = !isHoraExtraOnly && !isComissaoOnly && /(sim|tenho|faûÏo|faco|uber|ifood|extra|bico)/i.test(t);
  const nao = /^(nao|nûÈo|n\s?tem|nenhuma|zero)$/i.test(String(t || "").trim());

  // ============================================================
  // SIM ã possui renda extra ã vai para renda_mista_detalhe
