  const familia  = composicaoSignal === "familiar" || /(pai|m[aûÈ]e|mae|irm[aûÈ]|av[oû°]|tia|tio|primo|prima|famil)/i.test(t);
  const sozinho  = /(s[oû°]\s*(a\s*)?minha(\s+renda)?|s[oû°]\s*eu|apenas eu|somente eu|solo|sozinh|nao tenho ninguem|nûÈo tenho ningu[eûˋ]m|ninguem para somar|ningu[eûˋ]m pra somar|sem ningu[eûˋ]m|sem composi[ûÏc]|n[aûÈ]o vou somar)/i.test(t);

