  // ãã Casca cognitiva: reprompt natural com opûÏûçes explûÙcitas ãã
  st.__cognitive_reply_prefix = "Com quem vocûˆ pretende somar renda: *Parceiro(a)*, *familiar* (pai/mûÈe/irmûÈo) ou *sozinho(a)*?";
