  // NormalizaûÏûÈo autûÇnomos
  const isAutTitular  = st.regime === "AUTONOMO" || st.regime === "autonomo";
  const isAutParceiro = regimeParceiro === "AUTONOMO" || regimeParceiro === "autonomo";

