  const jaFoiPlantaoConf = /\b(ja fui|jûÀ fui|ja passei|jûÀ passei|ja visitei|jûÀ visitei|ja estive|jûÀ estive)\b/.test(tNorm) && /\b(plant[aûÈ]o|l[aûÀ])\b/.test(tNorm);
